function renderGlossaryTip(key) {
  if (!GLOSSARY[key]) return '';
  return '<span class="glossary-tip" onclick="event.stopPropagation();showGlossaryModal(\'' + key + '\')">тД╣я╕П</span>';
}

function showGlossaryModal(key) {
  var g = GLOSSARY[key];
  if (!g) return;
  var existing = document.getElementById('glossaryModal');
  if (existing) existing.remove();
  var body = '<p style="font-size:13px;line-height:1.6;color:var(--text);margin:0 0 12px;">' + g.desc + '</p>';
  if (g.calc) body += '<div style="background:rgba(10,132,255,0.08);border-radius:10px;padding:10px 12px;margin-bottom:10px;"><div style="font-size:11px;font-weight:700;color:var(--blue);margin-bottom:4px;">ЁЯУР Comment c\'est calcul├й</div><div style="font-size:12px;color:var(--text);line-height:1.5;">' + g.calc + '</div></div>';
  if (g.example) body += '<div style="background:rgba(50,215,75,0.08);border-radius:10px;padding:10px 12px;"><div style="font-size:11px;font-weight:700;color:var(--green);margin-bottom:4px;">ЁЯТб Exemple concret</div><div style="font-size:12px;color:var(--text);line-height:1.5;">' + g.example + '</div></div>';
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.id = 'glossaryModal';
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = '<div class="modal-box" style="max-width:380px;padding:20px;text-align:left;">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;">' +
    '<div style="font-size:15px;font-weight:700;color:var(--text);">' + g.short + '</div>' +
    '<button onclick="document.getElementById(\'glossaryModal\').remove()" style="background:none;border:none;color:var(--sub);font-size:18px;cursor:pointer;padding:0;">тЬХ</button>' +
    '</div>' + body + '</div>';
  document.body.appendChild(overlay);
}

function renderGlossaryPage() {
  var el = document.getElementById('glossaryPageContent');
  if (!el) return;
  var html = '';
  for (var catKey in GLOSSARY_CATEGORIES) {
    var cat = GLOSSARY_CATEGORIES[catKey];
    html += '<div style="margin-bottom:16px;">' +
      '<div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:8px;">' + cat.icon + ' ' + cat.label + '</div>';
    cat.keys.forEach(function(key) {
      var g = GLOSSARY[key];
      if (!g) return;
      html += '<div class="glossary-item" onclick="showGlossaryModal(\'' + key + '\')">' +
        '<span style="font-size:12px;font-weight:600;color:var(--text);">' + g.short + '</span>' +
        '<span class="glossary-tip">тД╣я╕П</span>' +
        '</div>';
    });
    html += '</div>';
  }
  el.innerHTML = html;
}

// тФАтФА EXPORT / IMPORT JSON тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function exportData() {
  const json = JSON.stringify(db, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const date = new Date().toISOString().slice(0, 10);
  a.href = url;
  a.download = 'training-hub-backup-' + date + '.json';
  a.click();
  URL.revokeObjectURL(url);
  showToast('тЬУ Sauvegarde t├йl├йcharg├йe !');
}

// Export CSV тАФ format tableur simple
function exportDataCSV() {
  var rows = [['Date', 'Jour', 'Titre', 'Exercice', 'S├йrie', 'Poids (kg)', 'Reps', 'RPE', 'Type', 'Volume (kg)']];
  (db.logs || []).forEach(function(session) {
    var date = session.shortDate || session.date || '';
    var day = session.day || '';
    var title = (session.title || 'S├йance').replace(/"/g, '""');
    (session.exercises || []).forEach(function(exo) {
      var exoName = (exo.name || '').replace(/"/g, '""');
      var sets = exo.allSets || exo.series || [];
      sets.forEach(function(s, si) {
        var w = s.weight || 0;
        var r = s.reps || 0;
        var rpe = typeof getSetRPELabel === 'function' ? getSetRPELabel(s) : (s.rpe || '');
        var type = s.setType || 'normal';
        var vol = w * r;
        rows.push([date, day, '"' + title + '"', '"' + exoName + '"', si + 1, w, r, rpe, type, vol]);
      });
      if (sets.length === 0) {
        rows.push([date, day, '"' + title + '"', '"' + exoName + '"', '', '', '', '', '', '']);
      }
    });
  });

  var csv = rows.map(function(r) { return r.join(';'); }).join('\n');
  var blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url;
  a.download = 'training-hub-export-' + new Date().toISOString().slice(0, 10) + '.csv';
  a.click();
  URL.revokeObjectURL(url);
  showToast('тЬУ Export CSV t├йl├йcharg├й !');
}

let _restoreData = null;
function previewRestore(input) {
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = e => {
    try {
      const parsed = JSON.parse(e.target.result);
      // Validation minimale
      if (!parsed.logs || !parsed.user) throw new Error('Format invalide');
      _restoreData = parsed;
      const preview = document.getElementById('restorePreview');
      const btn = document.getElementById('restoreBtn');
      const sessions = parsed.logs ? parsed.logs.length : 0;
      const name = parsed.user ? (parsed.user.name || 'Inconnu') : 'тАФ';
      preview.style.display = '';
      preview.innerHTML = 'тЬЕ Fichier valide<br>' +
        '<strong>' + sessions + '</strong> s├йances ┬╖ Profil : <strong>' + name + '</strong>';
      btn.disabled = false;
    } catch(err) {
      _restoreData = null;
      const preview = document.getElementById('restorePreview');
      preview.style.display = '';
      preview.innerHTML = 'тЭМ Fichier invalide : ' + err.message;
      document.getElementById('restoreBtn').disabled = true;
    }
  };
  reader.readAsText(file);
}

function importData() {
  if (!_restoreData) return;
  showModal(
    'Restaurer les donn├йes ? Toutes les donn├йes actuelles seront remplac├йes.',
    'Restaurer',
    'var(--orange)',
    () => {
      db = sanitizeDB(_restoreData);
      saveDB();
      _restoreData = null;
      var _rfi = document.getElementById('restoreFileInput');
      var _rpv = document.getElementById('restorePreview');
      var _rbt = document.getElementById('restoreBtn');
      if (_rfi) _rfi.value = '';
      if (_rpv) _rpv.style.display = 'none';
      if (_rbt) _rbt.disabled = true;
      refreshUI();
      showToast('тЬУ Donn├йes restaur├йes !');
    }
  );
}
function showToast(msg, duration, onClick) {
  const t = document.createElement('div');
  t.className = 'toast';
  t.textContent = msg;
  if (typeof onClick === 'function') {
    t.style.cursor = 'pointer';
    t.addEventListener('click', function() { try { onClick(); } catch(e) {} t.remove(); });
  }
  document.body.appendChild(t);
  setTimeout(() => t.remove(), Math.max(1500, duration || 2500));
}
var _LABEL_MAP = {
  srs:   { 1:'Forme du jour',    2:'Forme du jour',   3:'SRS (Readiness)' },
  acwr:  { 1:'Charge semaine',   2:'Charge semaine',  3:'ACWR' },
  trimp: { 1:'Fatigue',          2:'Charge cumul.',   3:'TRIMP' }
};
function labelFor(key, fallback) {
  var lvl = Math.min(3, Math.max(1, parseInt((db && db.user && db.user.vocabLevel) || 2)));
  return (_LABEL_MAP[key] && _LABEL_MAP[key][lvl]) || fallback || key.toUpperCase();
}
function showInfoModal(title, contentHtml) { var o = document.createElement('div'); o.className = 'modal-overlay'; o.innerHTML = '<div class="modal-box"><p style="margin:0 0 10px;font-size:15px;font-weight:700;">'+title+'</p>'+contentHtml+'<div class="modal-actions"><button class="modal-confirm" onclick="this.closest(\'.modal-overlay\').remove()" style="background:var(--accent);color:white;width:100%;">Fermer</button></div></div>'; document.body.appendChild(o); }
function closeModal() { var el = document.querySelector('.modal-overlay'); if (el) el.remove(); }
function showModal(msg, cText, cColor, onConfirm, onCancelOrText) { var cancelLabel = typeof onCancelOrText === 'string' ? onCancelOrText : 'Annuler'; var onCancel = typeof onCancelOrText === 'function' ? onCancelOrText : null; const o = document.createElement('div'); o.className = 'modal-overlay'; o.innerHTML = '<div class="modal-box"><p style="margin:0 0 5px;font-size:14px;">'+msg+'</p><div class="modal-actions"><button class="modal-cancel" style="background:var(--sub);color:#000;">'+cancelLabel+'</button><button class="modal-confirm" style="background:'+cColor+';color:white;">'+cText+'</button></div></div>'; document.body.appendChild(o); o.querySelector('.modal-cancel').onclick = () => { o.remove(); if (onCancel) onCancel(); }; o.querySelector('.modal-confirm').onclick = () => { o.remove(); onConfirm(); }; }
