function obQ3SelectMat(matId, btn) {
  obMat = matId;
  document.querySelectorAll('#ob-q3-mat .ob-mat-btn').forEach(function(b) { b.classList.remove('selected'); });
  if (btn) btn.classList.add('selected');
  // Persistance imm├йdiate + side effects (Gemini v211)
  db.user.programParams = db.user.programParams || {};
  db.user.programParams.mat = matId;
  // Poids de corps uniquement тЖТ bascule en mode calisthenics (sauf si l'user a explicitement choisi calisthenics dans la grille)
  if (matId === 'maison') {
    db.user.trainingMode = 'calisthenics';
  } else if (db.user.trainingMode === 'calisthenics' && _obSelectedMode !== 'calisthenics') {
    // Revient sur salle/halt├иres sans avoir s├йlectionn├й explicitement calisthenics тЖТ repasser musculation
    db.user.trainingMode = 'musculation';
  }
  saveDB();
}

function obSaveQ3() {
  // Defaults for fields not asked in fast flow
  db.user.bw            = 0;
  db.user.height        = null;
  db.user.age           = null;
  db.user.gender        = 'unspecified';
  db.user.secondaryActivities = [];
  db.user.injuries      = [];
  db.user.prehabEnabled = true;
  db.user.cardio        = 'integre';
  obFreq                = 3;
  obDuration            = 60;
  obCardio              = 'integre';
  // Determine freq from profile
  var profile = ONBOARDING_PROFILES[_obQ1SelectedProfile || 'debutant'];
  if (profile && (profile.level === 'avance')) obFreq = 4;
  // Pick days automatically (Mon/Wed/Fri or Mon/Tue/Thu/Fri)
  var defaultDays3 = ['Lundi', 'Mercredi', 'Vendredi'];
  var defaultDays4 = ['Lundi', 'Mardi', 'Jeudi', 'Vendredi'];
  obSelectedDays = (obFreq === 4) ? defaultDays4 : defaultDays3;
  saveDB();
  // Si d├йbutant тЖТ skip morpho (pas pertinent sans base technique)
  var _level = (db.user && db.user.level) || 'intermediaire';
  if (_level === 'debutant') {
    db.user.morpho = null;
    obGenerateProgram();
  } else {
    _obMorphoAnswers = {}; // reset r├йponses
    gotoObStep('q4');
  }
}

// тФАтФА MORPHO ONBOARDING тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
var _obMorphoAnswers = {};

function obMorphoAnswer(morphType, value, btn) {
  _obMorphoAnswers[morphType] = value;
  var parent = btn.closest('.ob-morpho-question');
  if (parent) {
    parent.querySelectorAll('.ob-morpho-btn').forEach(function(b) {
      b.classList.remove('selected');
    });
  }
  btn.classList.add('selected');
}

function obSaveQ4() {
  db.user.morpho = {
    long_femurs:           !!_obMorphoAnswers.long_femurs,
    short_arms_long_torso: !!_obMorphoAnswers.short_arms_long_torso,
    long_arms:             !!_obMorphoAnswers.long_arms,
    short_torso:           !!_obMorphoAnswers.short_torso
  };
  saveDB();

  // Utilisateur d├йj├а onboard├й avec un programme existant тЖТ pr├йserver le programme,
  // r├йg├йn├йrer le weeklyPlan uniquement (applique les adaptations morpho sans tout ├йcraser)
  if (db.user.onboarded && db.routine && Object.keys(db.routine).length > 0) {
    if (typeof generateWeeklyPlan === 'function') {
      try { generateWeeklyPlan(); } catch(e) { console.warn('[morpho] generateWeeklyPlan:', e); }
    }
    showToast('ЁЯж┤ Morphologie enregistr├йe тАФ plan adapt├й.');
    var ov = document.getElementById('onboarding-overlay');
    if (ov) ov.style.display = 'none';
    return;
  }

  // Premier onboarding тЖТ g├йn├йrer le programme normalement
  obGenerateProgram();
}

function obSkipMorpho() {
  db.user.morpho = null;
  saveDB();

  // M├кme logique : utilisateur d├йj├а onboard├й тЖТ ne pas ├йcraser le programme
  if (db.user.onboarded && db.routine && Object.keys(db.routine).length > 0) {
    if (typeof generateWeeklyPlan === 'function') {
      try { generateWeeklyPlan(); } catch(e) {}
    }
    var ov = document.getElementById('onboarding-overlay');
    if (ov) ov.style.display = 'none';
    return;
  }

  obGenerateProgram();
}

function obOnGenderChange(val) {
  var block = document.getElementById('ob-cycle-block');
  if (block) block.style.display = val === 'female' ? 'block' : 'none';
}

function obToggleCycleTracking(enabled) {
  var fields = document.getElementById('ob-cycle-fields');
  if (fields) fields.style.display = enabled ? 'block' : 'none';
}

function obSaveStep1() {
  var name = (document.getElementById('ob-name') || {}).value || '';
  name = name.trim();
  if (!name) { showToast('Entre ton pr├йnom ЁЯШК'); return; }
  db.user.name   = name;
  db.user.bw     = parseFloat(document.getElementById('ob-bw').value) || 0;
  db.user.height = parseFloat(document.getElementById('ob-height').value) || null;
  db.user.age    = parseInt(document.getElementById('ob-age').value) || null;
  db.user.level  = document.getElementById('ob-level').value;
  db.user.gender = document.getElementById('ob-gender').value || 'unspecified';
  if (db.user.gender === 'female') {
    var cycleEnabled = document.getElementById('ob-cycle-enabled').checked;
    db.user.cycleTracking.enabled = cycleEnabled;
    if (cycleEnabled) {
      var dateVal = (document.getElementById('ob-cycle-date') || {}).value || '';
      if (dateVal) db.user.cycleTracking.lastPeriodDate = dateVal;
      var lengthVal = parseInt((document.getElementById('ob-cycle-length') || {}).value);
      if (lengthVal >= 21 && lengthVal <= 45) db.user.cycleTracking.cycleLength = lengthVal;
    }
  }
  saveDB();
  gotoObStep('2');
}

var _obSelectedGoal = 'masse';

function obSelectGoal(goal, btn) {
  _obSelectedGoal = goal;
  document.querySelectorAll('#ob-goal-grid .ob-goal-btn').forEach(function(b) { b.classList.remove('selected'); });
  if (btn) btn.classList.add('selected');
}

function obSaveStep2() {
  if (!db.user.trainingMode) { showToast('Choisis un mode d\'entra├оnement'); return; }
  db.user.goal = _obSelectedGoal;
  saveDB();
  gotoObStep('3');
}

function obRenderInjuriesList() {
  var container = document.getElementById('ob-inj-list');
  if (!container) return;
  var injuries = db.user.injuries || [];
  var byZone = {};
  injuries.forEach(function(inj) { if (inj && inj.zone) byZone[inj.zone] = inj; });
  container.innerHTML = INJURY_ZONES.map(function(z) {
    var inj = byZone[z.key];
    var level = (inj && inj.active) ? inj.level : 0;
    var btns = [
      '<button class="ob-inj-lvl-btn' + (level===0?' selected':'') + '" onclick="obSetInjuryLevel(\'' + z.key + '\',0,this.parentNode)"><span>Aucune</span></button>',
      '<button class="ob-inj-lvl-btn lvl1' + (level===1?' selected':'') + '" onclick="obSetInjuryLevel(\'' + z.key + '\',1,this.parentNode)"><span>G├кne</span></button>',
      '<button class="ob-inj-lvl-btn lvl2' + (level===2?' selected':'') + '" onclick="obSetInjuryLevel(\'' + z.key + '\',2,this.parentNode)"><span>Douleur</span></button>',
    ].join('');
    return '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;background:var(--surface);border:1px solid var(--border);border-radius:10px;">' +
      '<div style="font-size:13px;font-weight:600;flex:1;">' + z.label + '</div>' +
      '<div style="display:flex;gap:5px;">' + btns + '</div></div>';
  }).join('');
}

function obSetInjuryLevel(zone, level, container) {
  var btns = container.querySelectorAll('.ob-inj-lvl-btn');
  btns.forEach(function(b) { b.classList.remove('selected'); });
  if (btns[level]) btns[level].classList.add('selected');
  setInjuryLevel(zone, level);
}

function obSaveStep3() {
  saveDB();
  gotoObStep('4');
}

var _obSecondaryActivities = [];

function obToggleSecondary(act, btn) {
  var idx = _obSecondaryActivities.indexOf(act);
  if (idx >= 0) {
    _obSecondaryActivities.splice(idx, 1);
    if (btn) btn.classList.remove('selected');
  } else {
    _obSecondaryActivities.push(act);
    if (btn) btn.classList.add('selected');
  }
}

function obSaveStep4() {
  db.user.secondaryActivities = _obSecondaryActivities.slice();
  saveDB();
  gotoObStep('5');
}

function obSaveStep5() {
  if (obSelectedDays.length !== obFreq) {
    var hint = document.getElementById('ob-days-hint');
    if (hint) hint.textContent = obSelectedDays.length < obFreq
      ? 'S├йlectionne encore ' + (obFreq - obSelectedDays.length) + ' jour(s)'
      : 'Tu as s├йlectionn├й trop de jours тАФ retire-en ' + (obSelectedDays.length - obFreq);
    return;
  }
  var _obPrehabCb = document.getElementById('obPrehabToggle');
  if (_obPrehabCb) db.user.prehabEnabled = !!_obPrehabCb.checked;
  var showSBD = db.user.trainingMode && TRAINING_MODES[db.user.trainingMode] &&
    TRAINING_MODES[db.user.trainingMode].features &&
    TRAINING_MODES[db.user.trainingMode].features.showSBDCards;
  if (showSBD) {
    gotoObStep('6');
  } else {
    obGenerateProgram();
  }
}

function obSaveStep6() {
  var benchPR = parseFloat(document.getElementById('ob-bench-pr').value) || 0;
  var squatPR = parseFloat(document.getElementById('ob-squat-pr').value) || 0;
  var deadPR  = parseFloat(document.getElementById('ob-dead-pr').value)  || 0;
  if (benchPR > 0) db.bestPR.bench    = benchPR;
  if (squatPR > 0) db.bestPR.squat    = squatPR;
  if (deadPR  > 0) db.bestPR.deadlift = deadPR;
  db.user.onboardingPRs = { bench: benchPR, squat: squatPR, deadlift: deadPR };
  db.user.targets = {
    bench:    parseFloat(document.getElementById('ob-bench-tgt').value)  || db.user.targets.bench,
    squat:    parseFloat(document.getElementById('ob-squat-tgt').value)  || db.user.targets.squat,
    deadlift: parseFloat(document.getElementById('ob-dead-tgt').value)   || db.user.targets.deadlift,
  };
  saveDB();
  obGenerateProgram();
}

// Mapping zones тЖТ INJURY_EXCLUSIONS keys (used by generateProgram)
var _OB_ZONE_TO_EXCL = { genou:'genoux', epaule:'epaules', dos:'dos', hanche:'hanches', poignet:'poignets', coude:null, nuque:'nuque' };

// тФАтФА Consentement RGPD onboarding (v205) тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
// Cases D├ЙCOCH├ЙES par d├йfaut (RGPD France). Obligatoire avant g├йn├йration.
function renderConsentStep() {
  return '<div style="padding:20px;">'
    + '<div style="font-size:18px;font-weight:700;margin-bottom:16px;">ЁЯУЛ Avant de commencer</div>'
    + '<div style="font-size:13px;color:var(--sub);margin-bottom:20px;">'
    + 'TrainHub est un outil de programmation sportive, '
    + '<strong>pas un dispositif m├йdical</strong>. '
    + 'Consulte un professionnel de sant├й avant tout programme intensif.</div>'
    + '<label style="display:flex;gap:10px;align-items:flex-start;margin-bottom:14px;cursor:pointer;">'
    + '<input type="checkbox" id="consent-effort" style="margin-top:2px;width:18px;height:18px;">'
    + '<span style="font-size:13px;">Je confirme ├кtre apte ├а pratiquer une activit├й physique '
    + 'intense et assumer les risques li├йs ├а l\'entra├оnement.</span></label>'
    + '<label style="display:flex;gap:10px;align-items:flex-start;margin-bottom:20px;cursor:pointer;">'
    + '<input type="checkbox" id="consent-data" style="margin-top:2px;width:18px;height:18px;">'
    + '<span style="font-size:13px;">J\'accepte que mes donn├йes d\'entra├оnement soient trait├йes '
    + 'conform├йment ├а la <a href="#" style="color:var(--accent);">Politique de Confidentialit├й</a>.</span></label>'
    + '<button onclick="validateConsent()" '
    + 'style="width:100%;padding:14px;border-radius:12px;background:var(--accent);'
    + 'border:none;color:#fff;font-weight:700;font-size:15px;cursor:pointer;">'
    + 'Commencer тЖТ</button></div>';
}

function validateConsent() {
  var effortOk = !!(document.getElementById('consent-effort') && document.getElementById('consent-effort').checked);
  var dataOk   = !!(document.getElementById('consent-data')   && document.getElementById('consent-data').checked);
  if (!effortOk || !dataOk) {
    showToast('тЪая╕П Merci de cocher les deux cases pour continuer.', 3000);
    return;
  }
  db.user.consentHealth = true;
  db.user.consentHealthDate = new Date().toISOString();
  db.user.medicalConsent = true;
  db.user.medicalConsentDate = new Date().toISOString();
  saveDB();
  nextOnboardingStep();
}

// Ferme l'overlay consent et continue vers la g├йn├йration du programme
function nextOnboardingStep() {
  var overlay = document.getElementById('ob-consent-overlay');
  if (overlay) overlay.remove();
  _obConsentShown = true;
  _obGenerateProgramCore();
}

// v206 тАФ ├Йcran de compl├йtion apr├иs g├йn├йration programme (1├иre fois uniquement)
function showOnboardingComplete() {
  var _todaySession = db.weeklyPlan && db.weeklyPlan.days
    ? (db.weeklyPlan.days || []).find(function(d) {
        return d.exercises && d.exercises.length > 0 && !d.isRest;
      })
    : null;
  var _exoPreview = _todaySession
    ? ((_todaySession.exercises || []).slice(0, 3).map(function(e) { return e.name; }).join(' ┬╖ '))
    : '';

  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = '<div class="modal-box" style="max-width:360px;text-align:center;">'
    + '<div style="font-size:48px;margin-bottom:12px;">ЁЯОЙ</div>'
    + '<div style="font-size:18px;font-weight:800;margin-bottom:8px;">Ton programme est pr├кt !</div>'
    + (_exoPreview
      ? '<div style="font-size:12px;color:var(--sub);margin-bottom:4px;">'
        + 'Premi├иre s├йance : <strong>' + (_todaySession.title || '').split(' ┬╖ ')[0] + '</strong></div>'
        + '<div style="font-size:11px;color:var(--sub);margin-bottom:20px;">' + _exoPreview + '</div>'
      : '<div style="font-size:13px;color:var(--sub);margin-bottom:20px;">'
        + 'Va dans l\'onglet Plan pour voir ta semaine.</div>')
    + (!(db.bestPR && db.bestPR.squat)
      ? '<div style="font-size:12px;color:var(--orange);background:rgba(255,159,10,0.10);'
        + 'border-radius:8px;padding:10px;margin-bottom:14px;">'
        + 'ЁЯТб Renseigne tes PRs dans le Profil pour affiner les charges.</div>'
      : '')
    + '<button onclick="this.closest(\'.modal-overlay\').remove();showTab(\'tab-seances\')" '
    + 'style="width:100%;padding:14px;border-radius:12px;background:var(--accent);'
    + 'border:none;color:#fff;font-weight:700;font-size:15px;cursor:pointer;margin-bottom:8px;">'
    + 'Voir mon programme тЖТ</button>'
    + '<button onclick="this.closest(\'.modal-overlay\').remove();goStartWorkout(true)" '
    + 'style="width:100%;padding:12px;border-radius:12px;background:var(--surface);'
    + 'border:0.5px solid var(--accent);color:var(--accent);font-weight:600;cursor:pointer;">'
    + 'Lancer maintenant ЁЯТк</button>'
    + '</div>';
  document.body.appendChild(overlay);
}

// v206 тАФ Stub : ouvre la page Programme o├╣ l'user peut renseigner sa compDate
function openCompDateSettings() {
  if (typeof showTab === 'function') showTab('tab-seances');
}

// Flag interne тАФ ├йvite de re-afficher le consent si d├йj├а valid├й dans cette session
var _obConsentShown = false;

function obGenerateProgram() {
  // Afficher le consentement si l'user n'a pas encore valid├й les deux cases (RGPD France)
  if (!db.user.consentHealth || !db.user.medicalConsent) {
    if (!_obConsentShown) {
      var overlay = document.createElement('div');
      overlay.id = 'ob-consent-overlay';
      overlay.className = 'modal-overlay';
      overlay.innerHTML = '<div class="modal-box" style="max-width:380px;">'
        + renderConsentStep() + '</div>';
      document.body.appendChild(overlay);
      return;
    }
  }
  _obGenerateProgramCore();
}

function _obGenerateProgramCore() {
  gotoObStep('7');
  var logo   = document.getElementById('ob7-logo');
  var title  = document.getElementById('ob7-title');
  var sub    = document.getElementById('ob7-sub');
  var genAnim = document.getElementById('ob-gen-anim');
  var fill   = document.getElementById('ob-gen-bar-fill');
  var stepTxt = document.getElementById('ob-gen-step-text');
  var summary = document.getElementById('ob-summary');
  var finBtn  = document.getElementById('ob-finish-btn');
  if (logo)    logo.textContent  = 'тЪб';
  if (title)   title.textContent = 'G├йn├йration en coursтАж';
  if (sub)     sub.textContent   = 'On assemble ton programme sur mesure.';
  if (genAnim) genAnim.style.display = 'block';
  if (summary) summary.style.display = 'none';
  if (finBtn)  finBtn.style.display  = 'none';
  if (fill)    fill.style.width = '0%';

  var steps = ['Analyse du profilтАж', 'Calcul du volumeтАж', 'S├йlection des exercicesтАж', 'Adaptation aux blessuresтАж', 'FinalisationтАж'];
  var totalDur = 1600;
  var stepDur  = totalDur / steps.length;
  var i = 0;
  function animStep() {
    if (i < steps.length) {
      if (stepTxt) stepTxt.textContent = steps[i];
      if (fill)    fill.style.width = ((i + 1) / steps.length * 100) + '%';
      i++;
      setTimeout(animStep, stepDur);
    } else {
      // Compute injuries from db
      obInjuries = (db.user.injuries || [])
        .filter(function(inj) { return inj && inj.active && inj.level >= 1; })
        .map(function(inj) { return _OB_ZONE_TO_EXCL[inj.zone] || inj.zone; })
        .filter(Boolean);
      var goalObj = obGoals.find(function(g) { return g.id === (db.user.goal || 'masse'); }) || obGoals[1];
      var generated = generateProgram([goalObj], obFreq, obMat, obDuration, obInjuries, obCardio, null, null, db.user.level);
      db.generatedProgram = generated;
      db.user.programParams = { goals: [goalObj.id], freq: obFreq, mat: obMat, duration: obDuration, injuries: obInjuries, cardio: obCardio, level: db.user.level };
      db.routine = {};
      db.routineExos = db.routineExos || {};
      generated.forEach(function(d) {
        db.routine[d.day] = d.isRest ? 'ЁЯШ┤ Repos' : (d.isCardio ? 'ЁЯПГ ' + d.label : d.label);
        if (!d.isRest && d.exos && d.exos.length > 0) {
          db.routineExos[d.day] = d.exos.map(function(id) { return EXO_DB[id] ? EXO_DB[id].name : id; });
        }
      });
      saveDB();
      // Show result
      if (genAnim) genAnim.style.display = 'none';
      if (logo)  logo.textContent  = 'тЬи';
      if (title) title.textContent = 'Ton programme est pr├кt !';
      if (sub)   sub.textContent   = 'Voil├а ce qu\'on a pr├йpar├й pour toi.';
      renderObSummary(generated);
      if (summary) summary.style.display = 'block';
      if (finBtn)  finBtn.style.display  = 'block';
      var _medWrap = document.getElementById('ob-medical-consent-wrap');
      if (_medWrap) _medWrap.style.display = 'block';
    }
  }
  animStep();
}

function renderObSummary(generated) {
  var el = document.getElementById('ob-summary');
  if (!el) return;
  var trainingDays = generated.filter(function(d) { return !d.isRest; });
  var html = '<div style="background:var(--surface);border:1px solid var(--border);border-radius:14px;padding:14px;margin-top:12px;">';
  html += '<div style="font-size:13px;font-weight:700;margin-bottom:10px;">ЁЯУЛ ' + trainingDays.length + ' s├йances / semaine ┬╖ ' + obMat + ' ┬╖ ' + obDuration + 'min</div>';
  html += '<div style="display:flex;flex-direction:column;gap:6px;">';
  generated.forEach(function(d) {
    var icon = d.isRest ? 'ЁЯШ┤' : 'ЁЯТк';
    html += '<div style="display:flex;align-items:center;gap:8px;font-size:12px;">';
    html += '<span style="min-width:74px;font-weight:600;color:var(--sub);">' + d.day + '</span>';
    html += '<span>' + icon + ' ' + (d.isRest ? 'Repos' : d.label) + '</span>';
    html += '</div>';
  });
  html += '</div></div>';
  el.innerHTML = html;
}

function selectDur(min) {
  obDuration = min;
  document.querySelectorAll('.ob-dur-btn').forEach(b => b.classList.remove('selected'));
  event.currentTarget.classList.add('selected');
}

function toggleInjury(zone) {
  const btn = document.querySelector('.ob-inj-btn[data-inj="'+zone+'"]');
  if (obInjuries.includes(zone)) {
    obInjuries = obInjuries.filter(z => z !== zone);
    if (btn) btn.classList.remove('selected');
  } else {
    obInjuries.push(zone);
    if (btn) btn.classList.add('selected');
  }
}

function selectCardio(mode) {
  obCardio = mode;
  document.querySelectorAll('.ob-cardio-btn').forEach(b => b.classList.remove('selected'));
  event.currentTarget.classList.add('selected');
}

function doGenerateProgram() {
  const generated = generateProgram(obGoals, obFreq, obMat, obDuration, obInjuries, obCardio, obCompDate, obCompType, db.user.level);
  db.generatedProgram = generated;
  db.user.programParams = { goals: obGoals.map(g=>g.id), freq: obFreq, mat: obMat, duration: obDuration, injuries: obInjuries, cardio: obCardio, compDate: obCompDate, compType: obCompType, level: db.user.level };
  db.routine = {};
  db.routineExos = db.routineExos || {};
  generated.forEach(d => {
    db.routine[d.day] = d.isRest ? 'ЁЯШ┤ Repos' : (d.isCardio ? 'ЁЯПГ '+d.label : d.label);
    if (!d.isRest && d.exos && d.exos.length > 0) {
      db.routineExos[d.day] = d.exos.map(id => EXO_DB[id] ? EXO_DB[id].name : id);
    }
  });
  renderObGeneratedProgram(generated);
  gotoObStep('7');
}

// тФАтФА PARAM├ИTRES PAR NIVEAU тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
const LEVEL_PARAMS = {
  debutant: {
    setsWork: 2, setsMax: 3, repsLow: 10, repsHigh: 15,
    exosPerSession: { 30:3, 45:3, 60:4, 90:5, 120:5 },
    note: 'Progression lin├йaire тАФ ajoute 2.5kg ├а chaque s├йance',
    complexity: 'low' // pas d'exercices techniques complexes
  },
  intermediaire: {
    setsWork: 3, setsMax: 4, repsLow: 6, repsHigh: 12,
    exosPerSession: { 30:3, 45:4, 60:5, 90:6, 120:7 },
    note: 'Ondulation du volume тАФ varie les reps semaine ├а semaine',
    complexity: 'medium'
  },
  avance: {
    setsWork: 4, setsMax: 5, repsLow: 3, repsHigh: 10,
    exosPerSession: { 30:4, 45:5, 60:6, 90:7, 120:8 },
    note: 'Blocs force / volume / intensit├й avec deload toutes les 4тАУ6 semaines',
    complexity: 'high'
  },
  competiteur: {
    setsWork: 4, setsMax: 6, repsLow: 1, repsHigh: 8,
    exosPerSession: { 30:4, 45:5, 60:6, 90:8, 120:9 },
    note: 'Cycle de p├йriodisation avec semaine de peak et deload pr├й-comp├йtition',
    complexity: 'high'
  }
};

// тФАтФА EXERCICES EXCLUS PAR BLESSURE тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
const INJURY_EXCLUSIONS = {
  epaules:  ['ohp','ohp_halt','elev_lat','elev_front','incline_bench','dips_pec','dips_tri','face_pull','upright_row'],
  genoux:   ['squat','leg_press','leg_ext','fente','hack_squat','step_up','sissy'],
  dos:      ['deadlift','rdl','row_barre','row_halt','good_morning','shrug'],
  poignets: ['bench','bench_halt','curl_barre','skull','row_barre'],
  nuque:    ['lat_pull','traction','shrug','face_pull'],
  hanches:  ['deadlift','rdl','hip_thrust','fente','squat']
};

// тФАтФА SETS├ЧREPS PAR NIVEAU тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function getSetsReps(exoId, level, goalId) {
  const lp = LEVEL_PARAMS[level] || LEVEL_PARAMS.intermediaire;
  const isStrength = goalId === 'force' || goalId === 'recompo';
  const isHypertrophy = goalId === 'masse' || goalId === 'seche';
  const isCardioExo = exoId === 'cardio_hiit' || exoId === 'cardio_liss';

  if (isCardioExo) return EXO_DB[exoId]?.sets || '30min';

  const exo = EXO_DB[exoId];
  if (!exo) return lp.setsWork+'├Ч10';

  if (exo.exoType === 'time' || exo.sets?.includes('s') || exo.sets?.includes('min')) return exo.sets;
  if (exo.sets?.includes('max')) return lp.setsWork+'├Чmax';

  if (isStrength) {
    const reps = level === 'debutant' ? 6 : level === 'intermediaire' ? 5 : level === 'avance' ? 3 : 2;
    return lp.setsWork+'├Ч'+reps;
  }
  if (isHypertrophy) {
    return lp.setsWork+'├Ч'+lp.repsHigh;
  }
  return lp.setsWork+'├Ч'+(Math.round((lp.repsLow+lp.repsHigh)/2));
}

// тФАтФА G├ЙN├ЙRATION PROGRAMME ENRICHIE тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function generateProgram(goals, freq, mat, duration, injuries, cardio, compDate, compType, level) {
  const g1    = goals[0]?.id || 'force';
  const lp    = LEVEL_PARAMS[level] || LEVEL_PARAMS.intermediaire;
  const exosN = lp.exosPerSession[duration] || lp.exosPerSession[60];
  const excluded = new Set((injuries||[]).flatMap(z => INJURY_EXCLUSIONS[z]||[]));

  // тФАтФА 3-way split routing : powerlifting / powerbuilding / bodybuilding тФАтФА
  var trainingMode = (typeof db !== 'undefined' && db && db.user && db.user.trainingMode) || '';
  var isPL = (g1 === 'force');
  var isPB = (trainingMode === 'powerbuilding' || g1 === 'mixte');
  var isBB = (!isPL && !isPB);

  // Filtrage exercices par blessures + mat├йriel
  function filtSafe(ids, m) {
    return filtMat(ids.filter(id => !excluded.has(id)), m).slice(0, exosN);
  }

  // D├йbutants : remplacer les exercices complexes par des alternatives plus simples
  function filtLevel(ids) {
    if (lp.complexity === 'low') {
      const REPLACEMENTS = {
        'squat':    'leg_press',
        'deadlift': 'rdl',
        'rdl':      'leg_curl',
        'ohp':      'ohp_halt',
        'skull':    'tri_cable',
      };
      return ids.map(id => REPLACEMENTS[id] || id);
    }
    return ids;
  }

  const trainingDays = obSelectedDays.length === freq
    ? obSelectedDays
    : { 1:['Lundi'],2:['Lundi','Jeudi'],3:['Lundi','Mercredi','Vendredi'],4:['Lundi','Mardi','Jeudi','Vendredi'],5:['Lundi','Mardi','Mercredi','Jeudi','Vendredi'],6:['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'] }[Math.min(freq,6)] || ['Lundi','Mercredi','Vendredi'];

  // Blocs ajust├йs
  const B = {
    force: {
      push:    { label:'Push тАФ Force', exos: filtSafe(filtLevel(['bench','ohp','incline_bench','tri_cable','elev_lat']), mat) },
      pull:    { label:'Pull тАФ Force', exos: filtSafe(filtLevel(['deadlift','row_barre','lat_pull','traction','curl_barre','face_pull']), mat) },
      legs:    { label:'Jambes тАФ Force', exos: filtSafe(filtLevel(['squat','leg_press','rdl','mollet','leg_curl']), mat) },
      full_a:  { label:'Full Body A тАФ Force', exos: filtSafe(filtLevel(['squat','bench','row_barre','ohp','curl_barre']), mat) },
      full_b:  { label:'Full Body B тАФ Force', exos: filtSafe(filtLevel(['deadlift','incline_bench','lat_pull','elev_lat','tri_cable']), mat) },
      sbd:     { label:'SBD Technique', exos: filtSafe(['squat','bench','deadlift'], mat) },
      faibles: { label:'Points Faibles', exos: filtSafe(filtLevel(['elev_lat','face_pull','crunch','mollet','russian_twist']), mat) },
    },
    masse: {
      push:    { label:'Push тАФ Volume', exos: filtSafe(filtLevel(['bench_halt','incline_bench','ecarte','dips_pec','tri_cable','elev_lat']), mat) },
      pull:    { label:'Pull тАФ Volume', exos: filtSafe(filtLevel(['row_halt','lat_pull','traction','face_pull','curl_halt','shrug']), mat) },
      legs:    { label:'Jambes тАФ Volume', exos: filtSafe(filtLevel(['leg_press','leg_curl','fente','hip_thrust','mollet','leg_ext']), mat) },
      full_a:  { label:'Full Body A тАФ Volume', exos: filtSafe(filtLevel(['bench_halt','squat','row_halt','ohp_halt','curl_halt']), mat) },
      full_b:  { label:'Full Body B тАФ Volume', exos: filtSafe(filtLevel(['incline_bench','rdl','lat_pull','elev_lat','tri_cable']), mat) },
      upper:   { label:'Upper Body', exos: filtSafe(filtLevel(['bench_halt','row_halt','ohp_halt','lat_pull','elev_lat','curl_halt']), mat) },
      lower:   { label:'Lower Body', exos: filtSafe(filtLevel(['squat','leg_press','rdl','leg_curl','hip_thrust','mollet']), mat) },
    },
    seche: {
      push:    { label:'Push + Cardio', exos: filtSafe(filtLevel(['bench_halt','incline_bench','pompe','tri_cable','cardio_hiit']), mat) },
      pull:    { label:'Pull + Cardio', exos: filtSafe(filtLevel(['row_halt','traction','lat_pull','curl_halt','cardio_liss']), mat) },
      legs:    { label:'Jambes + Cardio', exos: filtSafe(filtLevel(['squat','rdl','leg_press','fente','cardio_hiit']), mat) },
      full_a:  { label:'Full Body + HIIT', exos: filtSafe(filtLevel(['squat','pompe','rowing_inv','crunch','cardio_hiit']), mat) },
      cardio:  { label:'Cardio actif', exos: filtSafe(['cardio_hiit','cardio_liss','planche','crunch'], mat) },
    },
    recompo: {
      push:    { label:'Push (Recompo)', exos: filtSafe(filtLevel(['bench_halt','ohp_halt','ecarte','dips_pec','tri_cable']), mat) },
      pull:    { label:'Pull (Recompo)', exos: filtSafe(filtLevel(['traction','row_halt','lat_pull','curl_halt','face_pull']), mat) },
      legs:    { label:'Jambes (Recompo)', exos: filtSafe(filtLevel(['squat','rdl','leg_press','hip_thrust','mollet']), mat) },
      full_a:  { label:'Full Body A', exos: filtSafe(filtLevel(['squat','bench_halt','row_halt','crunch','planche']), mat) },
      full_b:  { label:'Full Body B', exos: filtSafe(filtLevel(['rdl','ohp_halt','traction','planche','russian_twist']), mat) },
      cardio:  { label:'Cardio mod├йr├й', exos: filtSafe(['cardio_liss','planche','crunch'], mat) },
    },
    maintien: {
      full_a:  { label:'Full Body A', exos: filtSafe(filtLevel(['squat','bench_halt','row_halt','ohp_halt','crunch']), mat) },
      full_b:  { label:'Full Body B', exos: filtSafe(filtLevel(['rdl','pompe','traction','elev_lat','planche']), mat) },
      full_c:  { label:'Full Body C', exos: filtSafe(filtLevel(['fente','incline_bench','lat_pull','crunch','cardio_liss']), mat) },
      cardio:  { label:'Cardio + Mobilit├й', exos: filtSafe(['cardio_liss','planche','russian_twist'], mat) },
    },
    reprise: {
      full_a:  { label:'Full Body Doux A', exos: filtSafe(['pompe','rowing_inv','planche','mollet','crunch'], mat) },
      full_b:  { label:'Full Body Doux B', exos: filtSafe(['leg_press','ohp_halt','lat_pull','crunch','planche'], mat) },
      cardio:  { label:'Cardio l├йger', exos: filtSafe(['cardio_liss','planche'], mat) },
    },
    bien_etre: {
      full_a:  { label:'Full Body Doux', exos: filtSafe(filtLevel(['pompe','rowing_inv','planche','pilates_bridge','crunch']), mat) },
      full_b:  { label:'Full Body ├Йquilibr├й', exos: filtSafe(filtLevel(['leg_press','ohp_halt','lat_pull','pilates_rollup','planche']), mat) },
      mobility:{ label:'Mobilit├й & R├йcup├йration', exos: filtSafe(['yoga_downdog','mobility_hip_flexor','mobility_thoracic','pilates_cat_cow','mobility_hamstring','yoga_child_pose','mobility_world_greatest'], mat) },
      pilates: { label:'Pilates тАФ Core & Stabilit├й', exos: filtSafe(['pilates_hundred','pilates_rollup','pilates_bridge','pilates_swimming','pilates_teaser','pilates_mermaid','pilates_side_kick'], mat) },
      stretching:{ label:'├Йtirements Complets', exos: filtSafe(['mobility_hip_flexor','mobility_hamstring','mobility_pec_stretch','mobility_90_90','yoga_pigeon','yoga_downdog','mobility_shoulder_dislocate'], mat) },
      cardio:  { label:'Cardio Doux', exos: filtSafe(['cardio_liss','planche'], mat) },
    }
  };
  // Add shared mobility/pilates/stretching blocs to all goals
  var _sharedMobility = { label:'Mobilit├й & R├йcup├йration', exos: filtSafe(['yoga_downdog','mobility_hip_flexor','mobility_thoracic','pilates_cat_cow','mobility_hamstring','yoga_child_pose','mobility_world_greatest'], mat) };
  var _sharedPilates = { label:'Pilates тАФ Core & Stabilit├й', exos: filtSafe(['pilates_hundred','pilates_rollup','pilates_bridge','pilates_swimming','pilates_teaser','pilates_mermaid','pilates_side_kick'], mat) };
  var _sharedStretching = { label:'├Йtirements Complets', exos: filtSafe(['mobility_hip_flexor','mobility_hamstring','mobility_pec_stretch','mobility_90_90','yoga_pigeon','yoga_downdog','mobility_shoulder_dislocate'], mat) };
  for (var _bk in B) { if (!B[_bk].mobility) B[_bk].mobility = _sharedMobility; if (!B[_bk].pilates) B[_bk].pilates = _sharedPilates; if (!B[_bk].stretching) B[_bk].stretching = _sharedStretching; }

  const Bg = B[g1] || B.maintien;

  // тФАтФА Split intelligent bas├й sur fr├йquence, objectif et niveau тФАтФА
  // Chaque muscle entra├оn├й 2├Ч/sem minimum (pas de bro-split)
  // Sources : NSCA, Stronger by Science, meta-analyses 2024-2025
  function getSplitForFrequency(f, isPL, isPB, lvl) {
    if (f <= 2) return 'full_body';
    if (f === 3) return lvl === 'debutant' ? 'full_body' : 'upper_lower_alt';
    if (f === 4) {
      if (isPL) return 'powerlifting_4';
      if (isPB) return 'powerbuilding_4';
      return 'upper_lower';
    }
    if (f === 5) {
      if (isPL) return 'powerlifting_5';
      if (isPB) return 'powerbuilding_5';
      return 'ppl_ul';
    }
    if (f >= 6) {
      if (isPL) return 'powerlifting_6';
      if (isPB) return 'powerbuilding_6';
      return 'ppl_x2';
    }
    return 'upper_lower';
  }

  // Powerlifting-specific blocks (SBD chaque lift 2├Ч/sem)
  const plBlocks = {
    squat_acc:  { label:'Squat + Accessoires', exos: filtSafe(filtLevel(['squat','leg_press','rdl','leg_curl','mollet']), mat) },
    bench_acc:  { label:'Bench + Accessoires', exos: filtSafe(filtLevel(['bench','incline_bench','ecarte','tri_cable','elev_lat']), mat) },
    dead_acc:   { label:'Deadlift + Accessoires', exos: filtSafe(filtLevel(['deadlift','row_barre','lat_pull','face_pull','curl_barre']), mat) },
    bench2_sq:  { label:'Bench 2 + Squat l├йger', exos: filtSafe(filtLevel(['bench_halt','ohp','squat','elev_lat','tri_cable']), mat) },
    squat2:     { label:'Squat 2', exos: filtSafe(filtLevel(['squat','leg_press','hip_thrust','leg_curl','mollet']), mat) },
    bench2:     { label:'Bench 2', exos: filtSafe(filtLevel(['bench_halt','incline_bench','dips_pec','tri_cable','elev_lat']), mat) },
    dead2_acc:  { label:'Deadlift 2 + Accessoires', exos: filtSafe(filtLevel(['deadlift','row_halt','traction','face_pull','curl_halt']), mat) },
    accessoires:{ label:'Accessoires', exos: filtSafe(filtLevel(['elev_lat','face_pull','curl_barre','tri_cable','crunch','mollet']), mat) },
  };

  // Powerbuilding-specific blocks (Gemini v200 тАФ Ready for Prod)
  // Refonte compl├иte : compound prioritaire, gainage fonctionnel, ├йquilibre antago/protag
  var pbBlocks = {
    // BLOC 1 тАФ Squat Force/Hypertrophie : Presse pieds bas remplace Hack Squat post-Squat lourd
    sq_hyp:    { label:'Squat тАФ Force & Volume',     exos: filtSafe(filtLevel(['squat','leg_press','leg_ext','mollet_presse','planche']), mat) },
    // BLOC 2 тАФ Bench Force/Hypertrophie : sant├й ├йpaules (face_pull) crucial ├а 140kg+
    bench_hyp: { label:'Bench тАФ Force & Volume',     exos: filtSafe(filtLevel(['bench','rowing_poulie','dips','face_pull','tri_cable']), mat) },
    // BLOC 3 тАФ Deadlift Force/Hypertrophie : Squat Pause en position 2 (technical), leg_curl ajout├й
    dead_hyp:  { label:'Deadlift тАФ Force & Volume',  exos: filtSafe(filtLevel(['deadlift','squat_pause','lat_pull','leg_curl','relev├й_jambes']), mat) },
    // BLOC 4 тАФ Bench Volume/Variation : angle diff├йrent (incline + larsen) тЙа Bench barre J1
    bench2_hyp:{ label:'Bench 2 тАФ Volume',           exos: filtSafe(filtLevel(['incline_bench','larsen_press','row_halt','elev_lat','curl_barre']), mat) },
    // BLOC 5 spec тАФ SBD Technique/Vitesse (sp├йcialisation quad si ratio S/B < 1.20)
    sq2_spec:  { label:'SBD тАФ Technique & Vitesse',  exos: filtSafe(filtLevel(['squat','bench','speed_deadlift','leg_ext']), mat) },
    // BLOC 5 standard тАФ Squat 2 sans sp├йcialisation : Fentes ICI (pas dans sq_hyp)
    sq2_hyp:   { label:'Squat 2 тАФ Volume Jambes',    exos: filtSafe(filtLevel(['squat','leg_press','leg_ext','fentes','mollet']), mat) },
    // BLOC 6 тАФ R├йcup├йration active (6├иme jour optionnel, non-syst├йmique)
    recovery_day: { label:'R├йcup├йration Active',     exos: filtSafe(filtLevel(['face_pull','bird_dog','relev├й_jambes','planche']), mat) },
    // Pull тАФ gard├й pour compatibilit├й splits 6j (ne plus router par d├йfaut)
    pull_hyp:  { label:'Pull тАФ Volume',              exos: filtSafe(filtLevel(['row_halt','lat_pull','traction','face_pull','curl_halt']), mat) },
  };

  // v201 тАФ Phase-adaptive pbBlocks : exercices adapt├йs ├а la phase courante macrocycle
  // Force/Intensification тЖТ Squat Pause + Close Grip Bench (technique sp├йcifique SBD)
  // Peak тЖТ Volume r├йduit, exercices haute intensit├й neuro uniquement
  // v216 тАФ lire currentBlock.phase d'abord (canonical apr├иs generateWeeklyPlan),
  // fallback wpDetectPhase(), fallback 'hypertrophie' (jamais null)
  var _pbPhase = (typeof db !== 'undefined' && db && db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase)
    || (typeof wpDetectPhase === 'function' ? wpDetectPhase() : null)
    || 'hypertrophie';
  if (_pbPhase === 'force' || _pbPhase === 'intensification') {
    pbBlocks.sq_hyp = { label:'Squat тАФ Force',
      exos: filtSafe(filtLevel(['squat','squat_pause','leg_press','leg_ext','planche']), mat) };
    pbBlocks.bench_hyp = { label:'Bench тАФ Force',
      exos: filtSafe(filtLevel(['bench','close_grip_bench','rowing_poulie','dips','face_pull']), mat) };
  }
  if (_pbPhase === 'peak') {
    pbBlocks.sq_hyp = { label:'Squat тАФ Intensification',
      exos: filtSafe(filtLevel(['squat','squat_pause','leg_ext','planche']), mat) };
  }

  // тФАтФА FATIGUE-BASED EXERCISE SELECTION (Gemini Next Big Feature) тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
  // ACWR > 1.3 тЖТ remplacer Squat barre (axial lourd) par Leg Press (axial l├йger)
  var _acwrPB = typeof computeACWR === 'function' ? computeACWR() : null;
  if (isPB && _acwrPB && _acwrPB > 1.3) {
    pbBlocks.sq_hyp = { label: 'Lower Body тАФ R├йcup├йration (ACWR ' + _acwrPB.toFixed(2) + ')',
      exos: filtSafe(filtLevel(['leg_press','rdl','hip_thrust','leg_curl','mollet']), mat) };
    pbBlocks.sq2_spec = { label: 'Lower Volume тАФ R├йcup├йration',
      exos: filtSafe(filtLevel(['leg_press','leg_ext','hip_thrust','mollet']), mat) };
    pbBlocks.sq2_hyp = { label: 'Lower Volume тАФ R├йcup├йration',
      exos: filtSafe(filtLevel(['leg_press','leg_ext','hip_thrust','mollet']), mat) };
    if (typeof db !== 'undefined' && db) {
      db.weeklyPlan = db.weeklyPlan || {};
      db.weeklyPlan.coachNotes = db.weeklyPlan.coachNotes || [];
      db.weeklyPlan.coachNotes.push(
        'ACWR ' + _acwrPB.toFixed(2) + ' > 1.3 тАФ Squat remplac├й par Leg Press (charge axiale r├йduite)'
      );
    }
  }

  // тФАтФА ANALYSE BIOM├ЙCANIQUE тАФ ratio antagonistes тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
  var bestPR = (typeof db !== 'undefined' && db && db.bestPR) || {};
  var prSq   = parseFloat(bestPR.squat) || 0;
  var prBn   = parseFloat(bestPR.bench) || 0;
  var squatBenchRatio = prBn > 0 ? prSq / prBn : 1.20;
  var needsSquatSpec  = squatBenchRatio < 1.20 && level === 'avance' && isPB;
  var _ratioNote = needsSquatSpec
    ? 'Sp├йcialisation Squat activ├йe (ratio ' + squatBenchRatio.toFixed(2) + ' < 1.20)'
    : null;

  // Map split тЖТ s├йquence de blocs
  function getSplitSequence(splitType, f) {
    switch (splitType) {
      case 'full_body':
        if (f === 1) return [Bg.full_a];
        if (f === 2) return [Bg.full_a, Bg.full_b];
        return [Bg.full_a, Bg.full_b, Bg.full_a || Bg.full_c]; // 3j FB
      case 'upper_lower_alt':
        // 3j : U/L/U puis semaine suivante L/U/L (on fait U/L/U pour la g├йn├йration)
        return [Bg.upper || Bg.push, Bg.lower || Bg.legs, Bg.upper || Bg.pull];
      case 'upper_lower':
        // 4j : U/L/U/L
        return [Bg.upper || Bg.push, Bg.lower || Bg.legs, Bg.upper || Bg.pull, Bg.lower || Bg.legs];
      case 'ppl_ul':
        // 5j : PPL + U/L
        return [Bg.push, Bg.pull, Bg.legs, Bg.upper || Bg.push, Bg.lower || Bg.legs];
      case 'ppl_x2':
        // 6j : PPL ├Ч 2
        return [Bg.push, Bg.pull, Bg.legs, Bg.push, Bg.pull, Bg.legs];
      case 'powerlifting_4':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.bench2_sq];
      case 'powerlifting_5':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.squat2, plBlocks.bench2];
      case 'powerlifting_6':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.squat2, plBlocks.bench2, plBlocks.dead2_acc];
      case 'powerbuilding_4':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp];
      case 'powerbuilding_5':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp,
                needsSquatSpec ? pbBlocks.sq2_spec : pbBlocks.sq2_hyp];
      case 'powerbuilding_6':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp,
                needsSquatSpec ? pbBlocks.sq2_spec : pbBlocks.sq2_hyp, pbBlocks.pull_hyp];
      default:
        return [Bg.full_a];
    }
  }

  // Bien-├кtre et modes sp├йciaux gardent leur logique d├йdi├йe
  const specialSequences = {
    bien_etre:{ 1:[Bg.full_a],2:[Bg.full_a,Bg.mobility],3:[Bg.full_a,Bg.mobility,Bg.full_b],4:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.mobility],5:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.stretching,Bg.cardio],6:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.stretching,Bg.cardio,Bg.mobility] },
    seche:    { 1:[Bg.full_a],2:[Bg.full_a,Bg.cardio],3:[Bg.full_a,Bg.cardio,Bg.full_a],4:[Bg.push,Bg.pull,Bg.legs,Bg.cardio],5:[Bg.push,Bg.pull,Bg.legs,Bg.cardio,Bg.full_a],6:[Bg.push,Bg.pull,Bg.legs,Bg.cardio,Bg.full_a,Bg.cardio] },
    reprise:  { 1:[Bg.full_a],2:[Bg.full_a,Bg.full_b],3:[Bg.full_a,Bg.cardio,Bg.full_b],4:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility],5:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility,Bg.full_a],6:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility,Bg.full_a,Bg.cardio] },
    maintien: { 1:[Bg.full_a],2:[Bg.full_a,Bg.full_b],3:[Bg.full_a,Bg.full_b,Bg.full_c],4:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio],5:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio,Bg.mobility],6:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio,Bg.mobility,Bg.full_a] },
  };

  let seq;
  if (specialSequences[g1]) {
    seq = specialSequences[g1][Math.min(freq, 6)] || [Bg.full_a];
  } else {
    const splitType = getSplitForFrequency(Math.min(freq, 6), isPL, isPB, level);
    seq = getSplitSequence(splitType, Math.min(freq, 6));
  }

  // Audit trail : note de sp├йcialisation inject├йe par le ratio
  if (_ratioNote) {
    if (typeof db !== 'undefined' && db) {
      db.weeklyPlan = db.weeklyPlan || {};
      db.weeklyPlan.coachNotes = db.weeklyPlan.coachNotes || [];
      db.weeklyPlan.coachNotes.push(_ratioNote);
    }
  }

  const plan = [];
  const allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

  allDays.forEach(day => {
    const tIdx = trainingDays.indexOf(day);
    if (tIdx >= 0 && seq[tIdx]) {
      const bloc = seq[tIdx];
      const exosWithSets = (bloc.exos||[]).map(id => ({
        id,
        setsReps: getSetsReps(id, level, g1)
      }));
      // Cardio int├йgr├й : ajouter cardio_liss ├а la fin si option choisie et pas d├йj├а l├а
      if (cardio === 'integre' && !bloc.label.toLowerCase().includes('cardio') && !exosWithSets.some(e=>e.id==='cardio_liss'||e.id==='cardio_hiit')) {
        exosWithSets.push({ id:'cardio_liss', setsReps:'15min' });
      }
      plan.push({ day, label: bloc.label, exos: exosWithSets.map(e=>e.id), exosSets: exosWithSets, isRest: false, isCardio: bloc.label.toLowerCase().includes('cardio') });
    } else if (cardio === 'dedie' && !trainingDays.includes(day) && day !== 'Dimanche') {
      // Jours de repos тЖТ cardio l├йger d├йdi├й
      plan.push({ day, label:'Cardio l├йger', exos:['cardio_liss','planche'], exosSets:[{id:'cardio_liss',setsReps:'30тАУ40min'},{id:'planche',setsReps:'3├Ч60s'}], isRest: false, isCardio: true });
    } else {
      plan.push({ day, label:'Repos', exos:[], exosSets:[], isRest:true });
    }
  });

  // Comp├йtition : ajouter bloc info peak si date renseign├йe
  if (compDate) {
    const weeksOut = Math.round((new Date(compDate) - Date.now()) / 604800000);
    plan._compInfo = { date: compDate, weeksOut, type: compType };
  }
  plan._levelNote = lp.note;
  plan._level = level;
  if (_ratioNote) plan._ratioNote = _ratioNote;

  return plan;
}

function selectFreq(f) {
  obFreq = f;
  obSelectedDays = [];
  document.querySelectorAll('.ob-freq-btn').forEach(function(b, i) { b.classList.toggle('selected', i+1 === f); });
  if (document.getElementById('ob-days-grid')) renderDayPicker();
}

function renderDayPicker() {
  const grid = document.getElementById('ob-days-grid');
  const sub  = document.getElementById('ob-days-needed');
  if (sub) sub.textContent = obFreq;
  document.getElementById('ob-days-hint').textContent = '';

  const shorts = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];
  grid.innerHTML = DAYS_FULL.map((day, i) => {
    const sel = obSelectedDays.includes(day);
    return '<div class="ob-day-pick'+(sel?' selected':'')+'" data-day="'+day+'" onclick="toggleDayPick(\''+day+'\')">'+
      '<div class="dp-short">'+shorts[i]+'</div>'+
      '<div class="dp-full">'+day.substring(0,3)+'</div></div>';
  }).join('');
}

function toggleDayPick(day) {
  const hint = document.getElementById('ob-days-hint');
  if (obSelectedDays.includes(day)) {
    obSelectedDays = obSelectedDays.filter(d => d !== day);
  } else {
    if (obSelectedDays.length >= obFreq) {
      hint.textContent = 'Tu as d├йj├а s├йlectionn├й ' + obFreq + ' jour(s). Retire-en un d\'abord.';
      return;
    }
    // Maintain week order
    const order = DAYS_FULL;
    obSelectedDays.push(day);
    obSelectedDays.sort((a, b) => order.indexOf(a) - order.indexOf(b));
  }
  hint.textContent = obSelectedDays.length === obFreq ? 'тЬУ Parfait !' :
    'Encore ' + (obFreq - obSelectedDays.length) + ' jour(s) ├а s├йlectionner';
  renderDayPicker();
}

function selectMat(m) {
  obMat = m;
  document.querySelectorAll('.ob-mat-btn').forEach(b => b.classList.remove('selected'));
  event.currentTarget.classList.add('selected');
}

// Drag & drop priorit├йs
function renderObGoals() {
  const list = document.getElementById('ob-priority-list');
  if (!list) return;
  list.innerHTML = obGoals.map((g, i) =>
    '<div class="ob-priority-item" draggable="true" data-id="'+g.id+'" '+
    'ondragstart="obDragStart(event,'+i+')" ondragover="obDragOver(event)" ondrop="obDrop(event,'+i+')" ondragend="obDragEnd()">'+
    '<div class="ob-priority-rank">'+(i+1)+'</div>'+
    '<div class="ob-priority-icon">'+g.icon+'</div>'+
    '<div class="ob-priority-text"><strong>'+g.label+'</strong><span>'+g.desc+'</span></div>'+
    '<div class="ob-priority-handle">та┐</div></div>'
  ).join('');
}

function obDragStart(e, i) {
  obDragSrc = i;
  e.currentTarget.classList.add('dragging');
  e.dataTransfer.effectAllowed = 'move';
}
function obDragOver(e) {
  e.preventDefault();
  e.dataTransfer.dropEffect = 'move';
  document.querySelectorAll('.ob-priority-item').forEach(el => el.classList.remove('drag-over'));
  e.currentTarget.classList.add('drag-over');
}
function obDrop(e, i) {
  e.preventDefault();
  if (obDragSrc === null || obDragSrc === i) return;
  const moved = obGoals.splice(obDragSrc, 1)[0];
  obGoals.splice(i, 0, moved);
  renderObGoals();
}
function obDragEnd() {
  document.querySelectorAll('.ob-priority-item').forEach(el => { el.classList.remove('dragging'); el.classList.remove('drag-over'); });
  obDragSrc = null;
}

function parseManualProgram(text) {
  const result = {};
  const dayAliases = {
    'lun':'Lundi','lundi':'Lundi','mon':'Lundi','monday':'Lundi',
    'mar':'Mardi','mardi':'Mardi','tue':'Mardi','tuesday':'Mardi',
    'mer':'Mercredi','mercredi':'Mercredi','wed':'Mercredi','wednesday':'Mercredi',
    'jeu':'Jeudi','jeudi':'Jeudi','thu':'Jeudi','thursday':'Jeudi',
    'ven':'Vendredi','vendredi':'Vendredi','fri':'Vendredi','friday':'Vendredi',
    'sam':'Samedi','samedi':'Samedi','sat':'Samedi','saturday':'Samedi',
    'dim':'Dimanche','dimanche':'Dimanche','sun':'Dimanche','sunday':'Dimanche'
  };
  const lines = text.split('\n');
  lines.forEach(line => {
    const m = line.match(/^([^:я╝Ъ]+)[я╝Ъ:]\s*(.+)$/);
    if (!m) return;
    const dayRaw = m[1].trim().toLowerCase().replace(/[^a-z├б├а├в├д├й├и├к├л├о├п├┤├╢├╣├╗├╝├┐]/g,'');
    const content = m[2].trim();
    const day = dayAliases[dayRaw];
    if (day) result[day] = content;
  });
  return result;
}

// Render programme g├йn├йr├й (step 7)
function renderObGeneratedProgram(plan) {
  const container = document.getElementById('ob-generated-program');
  const summaryEl = document.getElementById('ob-prog-summary');
  if (!container) return;

  // Tags r├йsum├й
  const levelLabels = { debutant:'D├йbutant', intermediaire:'Interm├йdiaire', avance:'Avanc├й', competiteur:'Comp├йtiteur' };
  const matLabels   = { salle:'Salle compl├иte', halteres:'Halt├иres', maison:'Maison' };
  const durLabels   = { 30:'30min', 45:'45min', 60:'1h', 90:'1h30', 120:'2h+' };
  const cardioLabels = { integre:'Cardio int├йgr├й', dedie:'Cardio d├йdi├й', aucun:'Sans cardio' };

  const tags = [
    { text: obGoals[0]?.icon+' '+obGoals[0]?.label, cls:'' },
    obGoals[1] ? { text: obGoals[1]?.icon+' '+obGoals[1]?.label, cls:'purple' } : null,
    { text: 'ЁЯУЖ '+obFreq+'j/sem', cls:'green' },
    { text: matLabels[obMat]||obMat, cls:'orange' },
    { text: durLabels[obDuration]||obDuration+'min', cls:'orange' },
    { text: levelLabels[db.user.level]||db.user.level, cls:'' },
    { text: cardioLabels[obCardio], cls: obCardio==='aucun'?'':'green' },
    obInjuries.length ? { text:'ЁЯй╣ '+obInjuries.length+' zone(s) m├йnag├йe(s)', cls:'orange' } : null
  ].filter(Boolean);

  if (summaryEl) summaryEl.innerHTML = '<div class="ob-prog-tags">'+tags.map(t=>'<span class="ob-prog-tag'+(t.cls?' '+t.cls:'')+'" >'+t.text+'</span>').join('')+'</div>';

  // Bloc comp├йtition
  let compHtml = '';
  if (plan._compInfo) {
    const ci = plan._compInfo;
    const w = ci.weeksOut;
    let advice = '';
    if (w > 12) advice = 'Phase de construction тАФ '+Math.round(w-4)+' semaines de volume, puis 4 semaines de peak.';
    else if (w > 6) advice = 'Phase de force тАФ r├йduis progressivement le volume, augmente l\'intensit├й.';
    else if (w > 2) advice = 'Peak тАФ s├йances courtes, charges lourdes, r├йcup├йration prioritaire.';
    else advice = (typeof getVocab === 'function' ? getVocab('deload') : 'Deload') + ' тАФ s├йances l├йg├иres, aucun nouveau max. Pr├йserve ton ├йnergie.';
    compHtml = '<div class="ob-comp-bloc"><div class="ob-comp-bloc-title">ЁЯПЖ Comp├йtition dans '+w+' semaine'+(w>1?'s':'')+' тАФ '+new Date(ci.date).toLocaleDateString('fr-FR')+'</div><div class="ob-comp-bloc-body">'+advice+'</div></div>';
  }

  // Note niveau
  const levelNote = plan._levelNote ? '<div style="background:rgba(50,215,75,0.08);border:1px solid rgba(50,215,75,0.2);border-radius:10px;padding:10px 14px;font-size:12px;color:var(--green);margin-bottom:14px;">ЁЯТб '+plan._levelNote+'</div>' : '';

  container.innerHTML = compHtml + levelNote +
    '<div class="ob-program-card">'+
    plan.filter(d => !d._compInfo).map(d => {
      if (d.isRest) return '<div class="ob-day-card" style="opacity:0.4;"><div class="ob-day-header"><span class="ob-day-name">'+d.day+'</span><span class="ob-day-type">ЁЯШ┤ Repos</span></div></div>';
      const exoRows = (d.exosSets||d.exos.map(id=>({id,setsReps:''}))).map(e => {
        const exo = EXO_DB[e.id] || { name: e.id, icon:'ЁЯТк' };
        return '<span class="ob-exo-tag">'+exo.icon+' '+exo.name+(e.setsReps?' ┬╖ '+e.setsReps:'')+'</span>';
      }).join('');
      const restColor = d.isCardio ? 'var(--green)' : 'var(--blue)';
      return '<div class="ob-day-card">'+
        '<div class="ob-day-header"><span class="ob-day-name" style="color:'+restColor+'">'+d.day+'</span>'+
        '<span class="ob-day-type">'+(d.isCardio?'ЁЯПГ ':'ЁЯПЛя╕П ')+'Entra├оnement</span></div>'+
        '<div class="ob-day-label">'+d.label+'</div>'+
        '<div class="ob-day-exos">'+exoRows+'</div></div>';
    }).join('')+
    '</div>';
}

function autoPopulateKeyLifts() {
  if (db.keyLifts && db.keyLifts.length > 0) return; // d├йj├а configur├йs

  const lifts = [];

  // Priorit├й 1 : exercices par d├йfaut du mode actif
  const modeDefaults = modeFeature('defaultKeyLifts') || [];
  if (modeDefaults.length > 0) {
    modeDefaults.forEach(name => {
      lifts.push({ name, target: 0 });
    });
  }

  // Priorit├й 1b : exercices SBD si mode SBD et renseign├йs pendant l'onboarding
  if (modeFeature('showSBDCards') && lifts.length === 0) {
    const SBD_DEFAULTS = [
      { key: 'bench',    name: 'Bench Press (Barre)', targetKey: 'bench' },
      { key: 'squat',    name: 'Squat (Barre)',        targetKey: 'squat' },
      { key: 'deadlift', name: 'Soulev├й de Terre',     targetKey: 'deadlift' }
    ];
    SBD_DEFAULTS.forEach(({ key, name, targetKey }) => {
      if ((db.bestPR[key] || 0) > 0 || (db.user.targets[targetKey] || 0) > 0) {
        lifts.push({ name, target: db.user.targets[targetKey] || 0 });
      }
    });
  }

  // Priorit├й 2 : exercices du programme g├йn├йr├й (si pas de SBD)
  if (lifts.length === 0 && db.generatedProgram) {
    const seen = new Set();
    for (const day of db.generatedProgram) {
      if (day.isRest || day.isCardio || day._compInfo) continue;
      const exos = day.exosSets || (day.exos || []).map(id => ({ id }));
      for (const e of exos) {
        const exo = EXO_DB[e.id];
        if (exo && !seen.has(exo.name) && seen.size < 4) {
          seen.add(exo.name);
          lifts.push({ name: exo.name, target: 0 });
        }
      }
      if (seen.size >= 4) break;
    }
  }

  // Priorit├й 3 : exercices du programme import├й manuellement
  if (lifts.length === 0 && db.routineExos) {
    const seen = new Set();
    for (const day of DAYS_FULL) {
      const exos = getProgExosForDay(day);
      for (const name of exos) {
        if (!seen.has(name) && seen.size < 4 && name) {
          seen.add(name);
          lifts.push({ name, target: 0 });
        }
      }
      if (seen.size >= 4) break;
    }
  }

  if (lifts.length > 0) {
    db.keyLifts = lifts.slice(0, 6);
  }
}

function obFinish() {
  var _medEl = document.getElementById('ob-medical-consent');
  if (_medEl && !_medEl.checked) {
    showToast('тЪая╕П Veuillez confirmer votre aptitude m├йdicale pour continuer');
    return;
  }
  if (_medEl) {
    db.user.medicalConsent = true;
    db.user.medicalConsentDate = new Date().toISOString();
  }
  db.user.onboarded = true;
  db.user.onboardingVersion = ONBOARDING_VERSION;
  if (!db.user.onboardingDate) db.user.onboardingDate = new Date().toISOString().split('T')[0];
  // Persist selectedDays into programParams тАФ engine reads from here, not from the closure.
  if (Array.isArray(obSelectedDays) && obSelectedDays.length) {
    if (!db.user.programParams) db.user.programParams = {};
    db.user.programParams.selectedDays = obSelectedDays.slice();
  }
  if (typeof validateUserLevel === 'function') validateUserLevel();
  autoPopulateKeyLifts();
  saveDB();
  hideOnboarding();
  refreshUI();
  renderProgramViewer();
  showToast('Bienvenue ' + (db.user.name||'') + ' ! ЁЯЪА');
  if (!db._magicStartDone) {
    setTimeout(showMagicStart, 400);
  }
  // Encha├оner l'onboarding social si user connect├й et pas encore de pseudo
  setTimeout(async function() {
    var isLoggedIn = false;
    try {
      if (typeof supaClient !== 'undefined' && supaClient) {
        var session = await supaClient.auth.getSession();
        isLoggedIn = !!(session && session.data && session.data.session);
      }
    } catch(e) {}
    if (isLoggedIn && (!db.social || !db.social.onboardingCompleted)) {
      if (typeof showSocialOnboarding === 'function') showSocialOnboarding();
    }
  }, 500);
}

