  b.push({id:'col30',   r:'rare',      icon:'ЁЯП║', name:'Chasseur de Troph├йes',    desc:'30 badges тАФ les vitrines ne suffisent plus ├а tout exposer', condition:'30 badges', ck:()=>_colCount(30)});
  b.push({id:'col50',   r:'epic',      icon:'ЁЯУВ', name:'Archiviste de l\'Ar├иne',  desc:'50 badges тАФ les grands archivistes t\'envient profond├йment', condition:'50 badges', ck:()=>_colCount(50)});
  b.push({id:'col75',   r:'legendary', icon:'ЁЯЫбя╕П', name:'Gardien de Panoplie',     desc:'75 badges тАФ ta panoplie l├йgendaire fait p├вlir tous les marchands', condition:'75 badges', ck:()=>_colCount(75)});
  b.push({id:'col100',  r:'mythic',    icon:'ЁЯМА', name:'Arsenal Absolu',          desc:'100 badges тАФ chaque badge est une arme suppl├йmentaire dans ton arsenal', condition:'100 badges', ck:()=>_colCount(100)});
