function isBadgeActive(badgeId) {
  var e = db.earnedBadges && db.earnedBadges[badgeId];
  if (!e) return false;
  // Achiever badges are always active once earned
  // Status badges have an explicit active flag
  return e.active !== false;
}

function checkAndAwardBadges() {
  if (!db.earnedBadges) db.earnedBadges = {};
  var allBadges = typeof getAllBadges === 'function' ? getAllBadges() : [];
  var newBadges = [];
  allBadges.forEach(function(badge) {
    if (!badge.id || badge.impossible) return;
    var type = badge.badgeType || 'achiever';
    if (type === 'status') {
      // Status badges: re-evaluate each time, store earned state and active state
      try {
        var isActive = typeof badge.ck === 'function' && badge.ck();
        if (!db.earnedBadges[badge.id] && isActive) {
          db.earnedBadges[badge.id] = { earnedAt: Date.now(), xp: badge.xp || 0, active: true };
          newBadges.push(badge);
        } else if (db.earnedBadges[badge.id]) {
          // Update active flag but keep earnedAt and xp
          db.earnedBadges[badge.id].active = !!isActive;
        }
      } catch(e) {}
      return;
    }
    // Achiever badges: once earned, never revoked
    if (db.earnedBadges[badge.id]) return;
    try {
      if (typeof badge.ck === 'function' && badge.ck()) {
        db.earnedBadges[badge.id] = { earnedAt: Date.now(), xp: badge.xp || 0, active: true };
        newBadges.push(badge);
      }
    } catch(e) {}
  });
  if (newBadges.length > 0) {
    saveDB();
    newBadges.forEach(function(b, i) {
      setTimeout(function() {
        showToast('ЁЯПЕ Badge d├йbloqu├й тАФ ' + b.name, 3500);
        if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
      }, i * 2000);
    });
    // Show red dot on game tab and social cross-link
    var _gameTabBadge = document.getElementById('gameTabBadge');
    if (_gameTabBadge) {
      _gameTabBadge.textContent = newBadges.length;
      _gameTabBadge.style.display = 'inline-flex';
    }
    var _socialJeuxDot = document.getElementById('socialJeuxBadgeDot');
    if (_socialJeuxDot) _socialJeuxDot.style.display = 'block';
  }
  return newBadges;
}

function isBadgeEarned(badgeId) {
  return !!(db.earnedBadges && db.earnedBadges[badgeId]);
}

function getBadgeTheme() {
  var mode = db.user.trainingMode || 'powerbuilding';
  if (mode === 'bien_etre') return 'wellness';
  return 'warrior';
}

function calcTotalXP() {
  let xp = 0;
  const sorted = getSortedLogs().slice().reverse();
  const runningBest = {};
  sorted.forEach(log => {
    xp += 100;
    xp += Math.min(10, (log.exercises||[]).length) * 8;
    xp += Math.floor((log.volume || 0) / 500);
    (log.exercises||[]).forEach(exo => {
      if (exo.maxRM > 0) {
        const prev = runningBest[exo.name] || 0;
        if (prev > 0 && exo.maxRM > prev) xp += 50;
        else if (prev === 0) xp += 20;
        if (exo.maxRM > (runningBest[exo.name] || 0)) runningBest[exo.name] = exo.maxRM;
      }
    });
  });
  xp += calcStreak() * 25;
  // Weekly challenges XP
  var weeklyXP = 0;
  if (db.weeklyChallenges && db.weeklyChallenges.challenges) {
    db.weeklyChallenges.challenges.forEach(function(c) { if (c.completed) weeklyXP += (c.xpReward || 0); });
  }
  // Perfect quest bonus (25%)
  if (db.weeklyChallenges && db.weeklyChallenges.challenges) {
    var allDone = db.weeklyChallenges.challenges.every(function(c) { return c.completed; });
    if (allDone && db.weeklyChallenges.challenges.length > 0) weeklyXP = Math.round(weeklyXP * 1.25);
  }
  // Flame bonus
  var qs = db.questStreak || 0;
  if (qs >= 4) weeklyXP = Math.round(weeklyXP * 1.20);
  else if (qs >= 3) weeklyXP = Math.round(weeklyXP * 1.15);
  else if (qs >= 2) weeklyXP = Math.round(weeklyXP * 1.10);
  xp += weeklyXP;
  // Monthly challenges XP
  if (db.monthlyChallenges && db.monthlyChallenges.challenges) {
    db.monthlyChallenges.challenges.forEach(function(c) { if (c.completed) xp += (c.xpReward || 0); });
  }
  // Secret quests XP
  (db.secretQuestsCompleted || []).forEach(function(sqId) {
    var sq = SECRET_QUESTS.find(function(s) { return s.id === sqId; });
    if (sq) xp += sq.xp;
  });
  // Muscle XP
  var muscleXP = (db.gamification && db.gamification.muscleXP) || 0;
  xp += muscleXP;

  // Wisdom XP (badges sagesse тАФ Gemini v207)
  var wisdomXP = (db.gamification && db.gamification.wisdomXP) || 0;
  xp += wisdomXP;

  // High-water mark: XP can only increase, never drop
  var hwm = (db.gamification && db.gamification.xpHighWaterMark) || 0;
  if (xp > hwm) {
    db.gamification = db.gamification || {};
    db.gamification.xpHighWaterMark = xp;
    // Persist without full saveDB() in hot path тАФ will be committed on next saveDB
    try { localStorage.setItem('SBD_HUB', JSON.stringify(db)); } catch(e) {}
  }
  return Math.max(xp, hwm);
}

// тФАтФА LEADERBOARD METRICS тАФ used by syncLeaderboard() in supabase.js тФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function calcLeaderboardMetrics() {
  if (typeof db === 'undefined' || !db) return {};
  var now = Date.now();
  var WEEK = 7 * 86400000;
  var MONTH = 30 * 86400000;

  var allLogs = db.logs || [];
  var weekLogs = allLogs.filter(function(l) {
    return (now - (l.timestamp || 0)) <= WEEK;
  });
  var monthLogs = allLogs.filter(function(l) {
    return (now - (l.timestamp || 0)) <= MONTH;
  });

  var volumeWeek = weekLogs.reduce(function(s, l) {
    return s + (parseFloat(l.volume) || 0);
  }, 0);

  var totalXP = (db.gamification && db.gamification.xp)
    || (db.gamification && db.gamification.xpHighWaterMark)
    || 0;

  var xpWeek = 0;
  if (db.weeklyChallenges && Array.isArray(db.weeklyChallenges.challenges)) {
    db.weeklyChallenges.challenges.forEach(function(c) {
      if (c.completed) xpWeek += (c.xpReward || 0);
    });
  }

  var dots = 0;
  try {
    var bw = (db.user && db.user.bw) || 80;
    var gender = (db.user && db.user.gender) === 'female' ? 'F' : 'M';
    var sq = (db.bestPR && db.bestPR.squat) || 0;
    var bn = (db.bestPR && db.bestPR.bench) || 0;
    var dl = (db.bestPR && db.bestPR.deadlift) || 0;
    var total = sq + bn + dl;
    if (total > 0 && bw > 0 && typeof computeDOTS === 'function') {
      dots = Math.round(computeDOTS(total, bw, gender));
    }
  } catch(e) {}

  var streak = typeof calcStreak === 'function' ? calcStreak() : 0;

  return {
    xp:             totalXP,
    xp_week:        xpWeek,
    volume_week:    Math.round(volumeWeek),
    sessions_week:  weekLogs.length,
    sessions_month: monthLogs.length,
    dots:           dots,
    streak:         streak
  };
}

function getLeaderboardPeriodKey(type) {
  var now = new Date();
  if (type === 'weekly') {
    var d = new Date(now);
    d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
    var year = d.getUTCFullYear();
    var jan1 = new Date(Date.UTC(year, 0, 1));
    var week = Math.ceil((((d - jan1) / 86400000) + 1) / 7);
    return year + '-W' + String(week).padStart(2, '0');
  }
  if (type === 'monthly') {
    return now.getUTCFullYear() + '-' + String(now.getUTCMonth() + 1).padStart(2, '0');
  }
  return 'alltime';
}

// тФАтФА ISO 8601 week helpers (UTC-only, no DST/TZ drift) тФАтФА
function getISOWeekKey(ts) {
  var d = new Date(ts);
  if (isNaN(d.getTime())) return null;
  // Shift to Thursday of the same ISO week (pure UTC), per ISO 8601.
  // getUTCDay() returns 0=Sun..6=Sat; treat Sun as 7 to align Mon=1.
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  var year = d.getUTCFullYear();
  var jan1 = new Date(Date.UTC(year, 0, 1));
  var week = Math.ceil((((d - jan1) / 86400000) + 1) / 7);
  return year + '-W' + String(week).padStart(2, '0');
}

function _mondayFromISOWeekKey(key) {
  var m = /^(\d{4})-W(\d+)$/.exec(key || '');
  if (!m) return null;
  var year = parseInt(m[1], 10);
  var week = parseInt(m[2], 10);
  // Jan 4 is always in ISO week 1. Find that week's Monday (UTC).
  var jan4 = new Date(Date.UTC(year, 0, 4));
  var jan4Day = jan4.getUTCDay() || 7; // 1..7
  var mondayW1 = new Date(jan4.getTime() - (jan4Day - 1) * 86400000);
  return new Date(mondayW1.getTime() + (week - 1) * 7 * 86400000);
}

function _prevISOWeekKey(key) {
  var monday = _mondayFromISOWeekKey(key);
  if (!monday) return null;
  return getISOWeekKey(new Date(monday.getTime() - 7 * 86400000));
}

function calcStreak() {
  // Weekly calendar streak: ISO 8601 weeks (Mon-Sun, UTC) with тЙе1 session
  if (!db.logs.length) return 0;

  db.gamification = db.gamification || {};

  var now = Date.now();
  var currentWeek = getISOWeekKey(now);

  // Collect all weeks that have at least 1 session (ISO week keys, UTC-based)
  var weeksWithSession = new Set();
  var droppedLogs = 0;
  db.logs.forEach(function(log) {
    var ts = log.timestamp || new Date(log.date).getTime();
    if (!ts || isNaN(ts)) { droppedLogs++; return; }
    var wk = getISOWeekKey(ts);
    if (wk) weeksWithSession.add(wk);
    else droppedLogs++;
  });

  // Weeks already protected by a freeze consumed in previous calls.
  var protectedSet = new Set(db.gamification.freezeProtectedWeeks || []);
  var freezeConsumedThisCall = false;

  // DEBUG тАФ enable via window.DEBUG_STREAK = true in console
  var DEBUG = (typeof window !== 'undefined' && window.DEBUG_STREAK === true);
  if (DEBUG) {
    console.log('[calcStreak] logs=' + db.logs.length + ' dropped=' + droppedLogs +
      ' weeksInSet=' + weeksWithSession.size + ' currentWeek=' + currentWeek +
      ' freezes=' + (db.gamification.streakFreezes || 0) +
      ' protectedWeeks=' + protectedSet.size +
      ' freezeActiveThisWeek=' + (db.gamification.freezeActiveThisWeek === true));
    var sortedWeeks = Array.from(weeksWithSession).sort().reverse();
    console.log('[calcStreak] first 5 weeks:', sortedWeeks.slice(0, 5));
    console.log('[calcStreak] last 5 weeks:', sortedWeeks.slice(-5));
  }

  // Count consecutive weeks backward from startWeek.
  function countFromWeek(startWeek) {
    var streak = 0;
    var checkWeek = startWeek;
    while (checkWeek) {
      var hasSession = weeksWithSession.has(checkWeek);
      var alreadyProtected = protectedSet.has(checkWeek);
      if (hasSession || alreadyProtected) {
        streak++;
      } else if (checkWeek < '2026-W01') {
        if (DEBUG) console.log('[calcStreak] BREAK (pre-2026) at week=' + checkWeek + ' streak=' + streak);
        break;
      } else if (!freezeConsumedThisCall
                 && (db.gamification.streakFreezes || 0) > 0
                 && streak >= 4) {
        streak++;
        freezeConsumedThisCall = true;
        db.gamification.streakFreezes = Math.max(0, (db.gamification.streakFreezes || 0) - 1);
        db.gamification.freezeProtectedWeeks = db.gamification.freezeProtectedWeeks || [];
        if (db.gamification.freezeProtectedWeeks.indexOf(checkWeek) < 0) {
          db.gamification.freezeProtectedWeeks.push(checkWeek);
        }
        protectedSet.add(checkWeek);
        db.gamification.freezesUsedAt = db.gamification.freezesUsedAt || [];
        db.gamification.freezesUsedAt.push(Date.now());
        if (typeof syncToCloud === 'function') syncToCloud();
        if (typeof showToast === 'function') showToast('тЭДя╕П Freeze utilis├й тАФ streak prot├йg├й');
        if (DEBUG) console.log('[calcStreak] freeze consumed at week=' + checkWeek + ' streak=' + streak);
      } else {
        if (DEBUG) console.log('[calcStreak] BREAK at week=' + checkWeek + ' streak=' + streak +
          ' reason=' + (freezeConsumedThisCall ? 'freeze-already-consumed-this-call' :
                        (db.gamification.streakFreezes || 0) === 0 ? 'no-freezes-left' :
                        streak < 4 ? 'streak<4' : 'unknown'));
        break;
      }
      checkWeek = _prevISOWeekKey(checkWeek);
    }
    return streak;
  }

  // Start from the LAST COMPLETED week (ignore the unfinished current week).
  var lastWeekKey = _prevISOWeekKey(currentWeek);
  var streak = countFromWeek(lastWeekKey);

  // Add +1 if the current (unfinished) week already has a session,
  // or if it's manually protected by a freeze.
  if (weeksWithSession.has(currentWeek) || db.gamification.freezeActiveThisWeek === true) {
    streak += 1;
  }

  // Store in db for cloud sync (never overwrite a higher record)
  db.weeklyStreak = streak;
  if (streak > (db.weeklyStreakRecord || 0)) db.weeklyStreakRecord = streak;

  if (DEBUG) console.log('[calcStreak] FINAL streak=' + streak);

  return streak;
}

// тФАтФА SMART STREAK тАФ T├ВCHE 13 тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
// Ne se casse que sur les jours de s├йance pr├йvus rat├йs.
// Les jours de repos planifi├йs ne brisent pas le streak.

function calcSmartStreak() {
  var routine = typeof getRoutine === 'function' ? getRoutine() : {};
  var logs = db.logs || [];
  // Build set of days that had a session (YYYY-MM-DD)
  var trainedDays = new Set();
  logs.forEach(function(log) {
    var ts = log.timestamp || (log.date ? new Date(log.date).getTime() : 0);
    if (!ts) return;
    trainedDays.add(new Date(ts).toISOString().split('T')[0]);
  });

  var streak = 0;
  var today = new Date();
  // Check up to 365 days back
  for (var i = 0; i < 365; i++) {
    var d = new Date(today);
    d.setDate(d.getDate() - i);
    var dateStr = d.toISOString().split('T')[0];
    var dayName = DAYS_FULL[d.getDay()]; // getDay() returns 0=Sun
    var routineLabel = routine[dayName] || '';
    var isRestDay = !routineLabel || /repos/i.test(routineLabel);

    if (isRestDay) {
      // Rest day тАФ streak continues, no training required
      continue;
    } else {
      // Training day тАФ check if trained
      if (i === 0) {
        // Today тАФ don't break yet (they might still train)
        if (trainedDays.has(dateStr)) streak++;
        continue;
      }
      if (trainedDays.has(dateStr)) {
        streak++;
      } else {
        // Missed a planned session тАФ streak breaks
        break;
      }
    }
  }

  db.smartStreak = streak;
  if (streak > (db.smartStreakRecord || 0)) db.smartStreakRecord = streak;
  return streak;
}

// тФАтФА STREAK FREEZES тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function grantMonthlyFreeze() {
  db.gamification = db.gamification || {};
  db.gamification.streakFreezes = db.gamification.streakFreezes ?? 1;
  db.gamification.lastFreezeGrantedMonth = db.gamification.lastFreezeGrantedMonth ?? -1;
  var currentMonth = new Date().getMonth();
  if (currentMonth !== db.gamification.lastFreezeGrantedMonth
      && db.gamification.streakFreezes < 2) {
    db.gamification.streakFreezes += 1;
    db.gamification.lastFreezeGrantedMonth = currentMonth;
    if (typeof syncToCloud === 'function') syncToCloud();
  }
}

function activateFreezeManual() {
  db.gamification = db.gamification || {};
  if ((db.gamification.streakFreezes || 0) > 0 && db.gamification.freezeActiveThisWeek === false) {
    db.gamification.freezeActiveThisWeek = true;
    db.gamification.streakFreezes -= 1;
    db.gamification.freezesUsedAt = db.gamification.freezesUsedAt || [];
    db.gamification.freezesUsedAt.push(Date.now());
    // Remember that the current week is now protected (idempotent across renders)
    db.gamification.freezeProtectedWeeks = db.gamification.freezeProtectedWeeks || [];
    (function() {
      var wk = (typeof getISOWeekKey === 'function') ? getISOWeekKey(Date.now()) : null;
      if (wk && db.gamification.freezeProtectedWeeks.indexOf(wk) < 0) {
        db.gamification.freezeProtectedWeeks.push(wk);
      }
    })();
    if (typeof syncToCloud === 'function') syncToCloud();
    if (typeof showToast === 'function') showToast('тЭДя╕П Semaine prot├йg├йe');
    if (typeof renderGamificationTab === 'function') renderGamificationTab();
  } else {
    if (typeof showToast === 'function') showToast('Aucun freeze disponible');
  }
}

function getXPLevel(xp) {
  let lvl = XP_LEVELS[0];
  for (const l of XP_LEVELS) {
    if (xp >= l.xp) lvl = l;
  }
  return lvl;
}

function getNextXPLevel(xp) {
  for (const l of XP_LEVELS) {
    if (l.xp > xp) return l;
  }
  return null;
}

// Exercices o├╣ le poids de corps contribue ├а la charge totale (e1RM doit
// inclure bw + lest). Sinon les tractions/dips/pompes ├а poids de corps seul
// donnent e1RM=0 (calcE1RM(0, reps) = 0) et n'apparaissent jamais en Niveaux.
function isBodyweightExo(name) {
  var n = (name || '').toLowerCase().normalize('NFD').replace(/[╠А-═п]/g,'');
  return /traction|pull.?up|chin.?up|dips|pompe|push.?up/.test(n);
}

// v205 тАФ Affichage e1RM : fiable тЙд 8 reps, indicatif > 8 reps (Gemini-valid├й).
// Utilise calcBrzycki() d├йfini dans le bloc "auto PR detection" plus bas.
function getE1RMDisplay(weight, reps) {
  if (typeof calcBrzycki === 'function') {
    var e1rm = calcBrzycki(weight, reps);
    if (e1rm) return { value: Math.round(e1rm), label: 'e1RM estim├й', reliable: true };
  }
  // reps > 8 тЖТ indicatif via cap ├а 8 reps (Brzycki devient peu fiable)
  var indicativeReps = Math.min(reps, 8);
  var indicative = weight / (1.0278 - 0.0278 * indicativeReps);
  return { value: Math.round(indicative), label: 'Estimation indicative', reliable: false };
}

function getAllBestE1RMs() {
  // Returns { exoName: { e1rm, date } } for all exercises across all logs
  const best = {};
  const bw = getUserBW();
  db.logs.forEach(log => {
    (log.exercises||[]).forEach(exo => {
      var e1rm = exo.maxRM || 0;
      if (isBodyweightExo(exo.name)) {
        var sets = exo.allSets || exo.series || [];
        sets.forEach(function(s) {
          var r = s.reps || 0;
          if (r <= 0) return;
          var effW = (s.weight || 0) + bw;
          var rm = calcE1RM(effW, r);
          if (rm > e1rm) e1rm = rm;
        });
      }
      if (e1rm <= 0) return;
      if (!best[exo.name] || e1rm > best[exo.name].e1rm) {
        best[exo.name] = { e1rm: e1rm, date: log.shortDate || log.date || '' };
      }
    });
  });
  return best;
}

function toggleBdgSection(head) {
  const body = head.nextElementSibling;
  const chev = head.querySelector('.bdg-sec-chev');
  body.classList.toggle('open');
  if (chev) chev.classList.toggle('open');
}

// тФАтФА Gamification helpers тФАтФА

function _getWeekKey() {
  var d = new Date(); var day = d.getDay(); var diff = d.getDate() - day + (day === 0 ? -6 : 1);
  var mon = new Date(d.setDate(diff)); mon.setHours(0,0,0,0);
  return mon.toISOString().slice(0,10);
}

function _getWeekStart(date) {
  var d = new Date(date); var day = d.getDay(); var diff = d.getDate() - day + (day === 0 ? -6 : 1);
  d.setDate(diff); d.setHours(0,0,0,0); return d;
}

function _getLogsThisWeek() {
  var wk = _getWeekKey();
  var start = new Date(wk).getTime();
  var end = start + 7 * 86400000;
  return db.logs.filter(function(l) { return l.timestamp >= start && l.timestamp < end; });
}

