function findExoInDatabase(exoName) {
  if (!exoName) return null;
  if (typeof EXO_DATABASE === 'undefined' || !EXO_DATABASE) return null;

  function normalize(s) {
    if (!s || typeof s !== 'string') return '';
    return s
      .toLowerCase()
      .trim()
      .replace(/[()]/g, ' ')
      .replace(/[''┬┤`]/g, '')
      .replace(/\s+/g, ' ')
      .trim()
      .replace(/s\b/g, '')
      .replace(/\s+/g, ' ')
      .trim();
  }

  var n = normalize(exoName);
  var keys = Object.keys(EXO_DATABASE);

  for (var i = 0; i < keys.length; i++) {
    var e = EXO_DATABASE[keys[i]];
    if (e && e.name && normalize(e.name) === n) return e;
  }

  for (var i = 0; i < keys.length; i++) {
    var e = EXO_DATABASE[keys[i]];
    if (e && e.nameAlt && normalize(e.nameAlt) === n) return e;
  }

  for (var i = 0; i < keys.length; i++) {
    var e = EXO_DATABASE[keys[i]];
    if (!e || !e.name) continue;
    var d = normalize(e.name);
    if (n.indexOf(d) >= 0 || d.indexOf(n) >= 0) return e;
  }

  var nWords = n.split(' ').filter(function(w){ return w.length >= 3; });
  var bestMatch = null, bestScore = 0;
  for (var i = 0; i < keys.length; i++) {
    var e = EXO_DATABASE[keys[i]];
    if (!e || !e.name) continue;
    var dWords = normalize(e.name).split(' ').filter(function(w){ return w.length >= 3; });
    var common = nWords.filter(function(w){ return dWords.indexOf(w) >= 0; });
    if (common.length >= 2 && common.length > bestScore) {
      bestScore = common.length;
      bestMatch = e;
    }
  }
  if (bestMatch) return bestMatch;

  // Synonymes d'exercices : variantes FR/EN тЖТ cl├йs EXO_DATABASE.
  // IMPORTANT : les cl├йs ci-dessous doivent ├кtre normalis├йes selon `normalize()` :
  //   - minuscules, accents retir├йs, espaces collaps├йs
  //   - 's' final de chaque mot retir├й (via /s\b/g) тЖТ ex. "dips" devient "dip"
  // Utilis├йs en fallback quand aucun match direct name/nameAlt n'est trouv├й.
  const EXO_NAME_SYNONYMS = {
    // Tirage poulie / lat pulldown
    'tirage poitrine poulie':        'lat_pulldown_wide',
    'tirage poitrine bra tendu':     'lat_pulldown_wide',
    'tirage poitrine un bra':        'edb_one_arm_lat_pulldown',
    'tirage vertical':               'lat_pulldown_wide',
    'lat pulldown':                  'lat_pulldown_wide',
    // Rowing / rows
    'tirage machine convergente':    'cable_row',
    'rowing assi machine':           'cable_row',
    'rowing poulie assi':            'cable_row',
    'rowing poulie assi prise large':'lat_pulldown_wide',
    'rowing haltere':                'dumbbell_row',
    'rowing inverse':                'barbell_row',
    'seated row':                    'cable_row',
    'bent over row':                 'barbell_row',
    // D├йvelopp├й couch├й / bench press
    'chest press machine':           'bench_press_barbell',
    'chest press convergent machine':'bench_press_barbell',
    'bench press':                   'bench_press_barbell',
    // D├йvelopp├й ├йpaules / overhead press
    'presse epaule assi machine':    'ohp_barbell',
    'overhead press':                'ohp_barbell',
    'military press':                'ohp_barbell',
    'shoulder press':                'ohp_dumbbell',
    // Dos lombaires
    'extension do machine':          'hyperextension',
    'back extension':                'hyperextension',
    // Leg curl / hamstrings
    'leg curl assi':                 'leg_curl_seated',
    'leg curl':                      'leg_curl_seated',
    'leg curl couche':               'leg_curl_lying',
    // Hip thrust
    'hip thrust machine':            'hip_thrust_barbell',
    'hip thrust':                    'hip_thrust_barbell',
    'poussee de hanche machine':     'hip_thrust_barbell',
    // Squats
    'hack squat machine':            'hack_squat',
    'belt squat machine':            'hack_squat',
    // Dips
    'machine dip assi':              'dips_triceps',
    'dip':                           'dips_triceps',
    // Biceps curl
    'curl pupitre machine':          'curl_barbell',
    'curl pupitre haltere':          'curl_barbell',
    'barbell curl':                  'curl_barbell',
    'dumbbell curl':                 'curl_dumbbell',
    // Trap├иzes
    'shrug haltere':                 'shrugs_dumbbell',
    'shrug poulie':                  'edb_cable_shrugs',
    'shrug':                         'shrugs_dumbbell',
    // Adducteurs
    'adduction hanche':              'hip_adduction',
    'hip adduction':                 'hip_adduction',
    'hip abduction':                 'hip_abduction',
    // Deadlift
    'deadlift':                      'deadlift_conventional',
    'souleve de terre':              'deadlift_conventional',
    // Squat pause / variations techniques
    'squat pause':                   'squat_pause',
    'squat pause barre':             'squat_pause',
    'squat avec pause barre':        'squat_pause',
    'paused squat':                  'squat_pause',
    'pause squat':                   'squat_pause',
  };

  var nClean = n.replace(/[()]/g,' ')
                .replace(/[├й├и├к├л]/g,'e')
                .replace(/[├а├в├д]/g,'a')
                .replace(/[├╣├╗├╝]/g,'u')
                .replace(/[├о├п]/g,'i')
                .replace(/[├┤├╢]/g,'o')
                .replace(/\s+/g,' ').trim();
  if (EXO_NAME_SYNONYMS[nClean]) {
    var target = EXO_DATABASE[EXO_NAME_SYNONYMS[nClean]];
    if (target) return target;
  }

  return null;
}

