// тФАтФА PLANNING JOURS MODIFIABLE тФАтФА
function renderProgDaysList() {
  // Source : weeklyPlan (donn├йes enrichies) prioritaire sur generatedProgram
  var wpDays = (db.weeklyPlan && db.weeklyPlan.days) ? db.weeklyPlan.days : [];
  var routine = typeof getRoutine === 'function' ? getRoutine() : {};
  var today = typeof DAYS_FULL !== 'undefined' ? DAYS_FULL[new Date().getDay()] : '';
  var allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

  var rowsHtml = allDays.map(function(day) {
    var label = routine[day] || '';
    var isRest = !label || /repos/i.test(label);
    var isToday = day === today;
    var dayShort = day.substring(0,3);

    // Chercher dans weeklyPlan.days
    var wpDay = wpDays.find(function(d) { return d.day === day; });
    var exos = [];
    if (wpDay && wpDay.exercises && wpDay.exercises.length) {
      exos = wpDay.exercises.map(function(e) {
        return typeof e === 'string' ? e : (e && e.name) || 'Exercice';
      });
    }

    if (isRest) {
      return '<div class="prog-day-row rest">' +
        '<span class="prog-drag-handle" style="opacity:.1;">та┐</span>' +
        '<div class="prog-day-label' + (isToday ? ' today' : '') + '">' + dayShort + '</div>' +
        '<div class="prog-day-content"><div class="prog-day-name" style="color:var(--sub);">Repos</div></div>' +
        '<div class="prog-day-actions"><div class="prog-action-btn" style="color:var(--green);font-size:10px;" onclick="pbEditExisting()">+</div></div>' +
      '</div>';
    }

    // Prefer the current routine label as source of truth тАФ wpDay.title may be
    // stale if weeklyPlan was generated before the routine was last updated.
    var title = label || (wpDay && wpDay.title) || '';
    var exoStr = exos.slice(0,3).join(' ┬╖ ') + (exos.length > 3 ? ' +' + (exos.length - 3) : '');
    var setsCount = (wpDay && wpDay.exercises) ? wpDay.exercises.reduce(function(s, e) {
      if (typeof e.sets === 'number') return s + e.sets;
      var _arr = Array.isArray(e.sets) ? e.sets
        : Array.isArray(e.allSets) ? e.allSets
        : Array.isArray(e.series) ? e.series : null;
      if (!_arr) return s;
      return s + (_arr.filter(function(ss) { return !ss.isWarmup; }).length || 0);
    }, 0) : 0;
    var metaStr = exos.length + ' exo' + (exos.length > 1 ? 's' : '') + (setsCount > 0 ? ' ┬╖ ' + setsCount + ' s├йries' : '');

    // Prehab compact (rendu uniquement, jamais persist├й)
    var _prehabExosLine = (wpDay && wpDay.prehabKey && db.user.prehabEnabled !== false && typeof generatePrehabRoutine === 'function')
      ? generatePrehabRoutine(wpDay.prehabKey) : [];
    var prehabStr = _prehabExosLine.length
      ? 'ЁЯФе Prehab ┬╖ ' + _prehabExosLine.slice(0, 4).map(function(e) { return e.name; }).join(' ┬╖ ') + (_prehabExosLine.length > 4 ? ' +' + (_prehabExosLine.length - 4) : '')
      : '';

    // Note motivante contextuelle (diff├йrente par jour)
    var phase = typeof wpDetectPhase === 'function' ? wpDetectPhase() : 'accumulation';
    var dayDataForNote = wpDay || { title: title, label: label };
    var motivNote = typeof wpDayMotivation === 'function' ? wpDayMotivation(dayDataForNote, phase) : '';
    var noteHtml = motivNote
      ? '<div style="font-size:11px;color:var(--sub);font-style:italic;margin-top:4px;' +
        'border-left:2px solid var(--accent);padding-left:8px;">"' + motivNote + '"</div>'
      : '';

    return '<div class="prog-day-row' + (isToday ? ' today' : '') + '" draggable="true" data-day="' + day + '">' +
      '<span class="prog-drag-handle">та┐</span>' +
      '<div class="prog-day-label' + (isToday ? ' today' : '') + '">' + dayShort + '</div>' +
      '<div class="prog-day-content" onclick="progShowDayDetail(\'' + day + '\')" style="cursor:pointer;">' +
        '<div class="prog-day-name">' + title + '</div>' +
        (prehabStr ? '<div class="prog-day-exos" style="color:var(--orange);font-size:11px;">' + prehabStr + '</div>' : '') +
        (exoStr ? '<div class="prog-day-exos">' + exoStr + '</div>' : '') +
        noteHtml +
      '</div>' +
      '<div class="prog-day-actions">' +
        '<div class="prog-action-btn" onclick="event.stopPropagation();progEditDay(\'' + day + '\')">тЬПя╕П</div>' +
        '<div class="prog-action-btn danger" onclick="event.stopPropagation();progConfirmRemoveDay(\'' + day + '\')">├Ч</div>' +
      '</div>' +
    '</div>';
  }).join('');

  var _progMode = (db.user && db.user.programMode) || 'auto';
  var _tmpl = db.customProgramTemplate;
  var _progName = _progMode === 'custom' && _tmpl ? (_tmpl.name || 'Programme Custom') : 'Programme Auto';
  var _updatedAt = db.updatedAt || 0;
  var _cloudUpdatedAt = db._cloudUpdatedAt || 0;
  var _isSynced = _updatedAt && _cloudUpdatedAt && Math.abs(_updatedAt - _cloudUpdatedAt) < 5000;
  var _syncBadge = _isSynced
    ? '<span style="color:var(--green);font-size:10px;">тШБя╕П Synchronis├й</span>'
    : '<span style="color:var(--orange);font-size:10px;">ЁЯУ▒ Local</span>';

  return '<div class="prog-planning">' +
    '<div class="prog-planning-head" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">' +
      '<div>' +
        '<div style="font-size:15px;font-weight:700;">' + escapeHtml(_progName) + '</div>' +
        '<div style="font-size:10px;color:var(--sub);margin-top:2px;">' + _syncBadge + '</div>' +
      '</div>' +
      '<span class="prog-planning-add" onclick="pbEditExisting()">+ Modifier</span>' +
    '</div>' +
    rowsHtml +
  '</div>';
}

// тФАтФА PLANNING BIEN-├КTRE тФАтФА
function renderProgBienEtreDays() {
  var today = DAYS_FULL[new Date().getDay()];
  var routine = getRoutine();
  var allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

  var ACTIVITIES = [
    {key:'cardio',ico:'ЁЯПГ',label:'Cardio',color:'var(--green)',borderColor:'rgba(50,215,75,.2)'},
    {key:'yoga',ico:'ЁЯзШ',label:'Yoga',color:'var(--teal)',borderColor:'rgba(100,210,255,.2)'},
    {key:'renfo',ico:'ЁЯТк',label:'Renfo',color:'var(--purple)',borderColor:'rgba(191,90,242,.2)'},
    {key:'velo',ico:'ЁЯЪ┤',label:'Cardio',color:'var(--green)',borderColor:'rgba(50,215,75,.2)'}
  ];

  var rowsHtml = allDays.map(function(day) {
    var label = routine[day] || '';
    var isRest = !label || /repos/i.test(label);
    var isToday = day === today;
    var dayShort = day.substring(0,3);
    var lowLabel = label.toLowerCase();
    var act = ACTIVITIES.find(function(a){ return lowLabel.indexOf(a.key)>=0 || lowLabel.indexOf(a.label.toLowerCase())>=0; }) || null;

    if (isRest) {
      return '<div class="be-prog-act-row rest">'+
        '<span class="prog-drag-handle" style="opacity:.1;">та┐</span>'+
        '<div class="prog-day-label">'+dayShort+'</div>'+
        '<div class="be-prog-act-ico" style="background:rgba(255,255,255,.03);">ЁЯШ┤</div>'+
        '<div class="be-prog-act-info"><div class="be-prog-act-name" style="color:var(--sub);">Repos</div></div>'+
        '<div class="be-prog-act-edit" style="color:var(--green);">+</div>'+
      '</div>';
    }

    return '<div class="be-prog-act-row'+(isToday?' today':'')+'">'+
      '<span class="prog-drag-handle">та┐</span>'+
      '<div class="prog-day-label'+(isToday?' today':'')+'">'+dayShort+'</div>'+
      '<div class="be-prog-act-ico" style="background:rgba(100,210,255,.1);">'+(act?act.ico:'ЁЯМ┐')+'</div>'+
      '<div class="be-prog-act-info">'+
        '<div class="be-prog-act-name">'+label+'</div>'+
        '<div class="be-prog-act-meta">'+(isToday?'Aujourd\'hui ┬╖ ':'')+'45 min</div>'+
      '</div>'+
      (act?'<div class="be-prog-act-tag" style="color:'+act.color+';border-color:'+act.borderColor+';">'+act.label+'</div>':'')+
      '<div class="be-prog-act-check" style="color:'+(isToday?'var(--accent)':'var(--sub)')+';">'+(isToday?'тЖТ':'┬╖')+'</div>'+
      '<div class="be-prog-act-edit">тЬПя╕П</div>'+
    '</div>';
  }).join('');

  return '<div class="prog-planning"><div class="prog-planning-head">'+
    '<div class="prog-planning-title">Cette semaine</div>'+
    '<span class="prog-planning-add" onclick="pbEditExisting()">+ Modifier</span>'+
  '</div>'+rowsHtml+'</div>';
}

// тФАтФА HELPERS INTERACTIVIT├Й тФАтФА
function progSelectSplit(splitId, days) {
  document.querySelectorAll('.prog-split-chip').forEach(function(b){ b.classList.remove('active'); });
  if (typeof event !== 'undefined' && event && event.currentTarget) event.currentTarget.classList.add('active');
  if (!db.user) db.user = {};
  db.user.selectedSplit = splitId;
  if (typeof saveDB === 'function') saveDB();
  if (typeof showToast === 'function') showToast('Split mis ├а jour : '+splitId);
}

function progPLSelectWeek(w) {
  document.querySelectorAll('.prog-pl-cell').forEach(function(c,i){ c.classList.toggle('selected',i===w-1); });
  var lbl = document.getElementById('pl-sel-lbl');
  if (lbl) lbl.textContent = 'Semaine '+w;
}

function progToggleCompet(checked) {
  if (!db.user) db.user = {};
  if (!db.user.programParams) db.user.programParams = {};
  if (!checked) { db.user.programParams.competitionDate = null; }
  if (typeof saveDB === 'function') saveDB();
  if (typeof renderProgramBuilderView === 'function') {
    renderProgramBuilderView(document.getElementById('programBuilderContent'));
  }
}

function progSetCompetDate(date) {
  if (!db.user) db.user = {};
  if (!db.user.programParams) db.user.programParams = {};
  db.user.programParams.competitionDate = date;
  if (typeof saveDB === 'function') saveDB();
  if (typeof showToast === 'function') showToast('Date de comp├йtition enregistr├йe');
}

function progEditDay(day) { if (typeof pbEditExisting==='function') pbEditExisting(); }
function progShowDayDetail(day) {
  var wpDays = (db.weeklyPlan && db.weeklyPlan.days) ? db.weeklyPlan.days : [];
  var wpDay = wpDays.find(function(d) { return d.day === day; });
  if (!wpDay || !wpDay.exercises || !wpDay.exercises.length) {
    showToast('Aucun d├йtail disponible pour ' + day);
    return;
  }

  var exosHtml = wpDay.exercises.map(function(e) {
    if (!e || !e.name) return '';
    // v219 тАФ guard : e.sets peut ├кtre un entier sur les anciens plans pr├й-v218
    var _setsArr = Array.isArray(e.sets) ? e.sets : [];
    var workSets = _setsArr.filter(function(s) { return !s.isWarmup; });
    var warmSets = _setsArr.filter(function(s) { return s.isWarmup; });
    var firstWork = workSets[0];
    var loadStr = '';
    if (firstWork) {
      if (e.type === 'cardio') {
        loadStr = (firstWork.durationMin || '?') + 'min';
      } else if (e.type === 'time') {
        loadStr = Math.round((firstWork.durationSec || 0) / 60) + 'min';
      } else if (firstWork.weight) {
        loadStr = workSets.length + '├Ч' + firstWork.reps + ' @ ' + firstWork.weight + 'kg';
      } else {
        loadStr = workSets.length + '├Ч' + firstWork.reps;
      }
    }
    var warmStr = warmSets.length > 0 ? ' ┬╖ ' + warmSets.length + ' ├йchauff.' : '';

    return '<div style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid rgba(255,255,255,.04);">' +
      '<div style="flex:1;">' +
        '<div style="font-size:13px;font-weight:700;">' + e.name + '</div>' +
        '<div style="font-size:10px;color:var(--sub);">' + loadStr + warmStr +
          (e.restSeconds ? ' ┬╖ repos ' + Math.round(e.restSeconds/60) + 'min' : '') +
        '</div>' +
      '</div>' +
    '</div>';
  }).join('');

  var html = '<div style="padding:4px 0;">' +
    '<div style="font-size:16px;font-weight:800;margin-bottom:4px;">' + (wpDay.title || day) + '</div>' +
    (wpDay.coachNote ? '<div style="font-size:11px;color:var(--orange);margin-bottom:12px;">ЁЯТб ' + wpDay.coachNote + '</div>' : '') +
    exosHtml +
  '</div>';

  showModal(html, 'GO ЁЯТк', 'var(--accent)', function() {
    if (typeof startTodayWorkout === 'function') startTodayWorkout();
  });
}

function progConfirmRemoveDay(day) {
  showModal('Supprimer ' + day + ' du programme ?', 'Supprimer', 'var(--red)', function() {
    if (db.weeklyPlan && db.weeklyPlan.days) {
      db.weeklyPlan.days = db.weeklyPlan.days.map(function(d) {
        if (d.day === day) return { day: day, rest: true, title: 'ЁЯШ┤ Repos Complet', exercises: [] };
        return d;
      });
      if (typeof saveDB === 'function') saveDB();
      if (typeof syncToCloud === 'function') syncToCloud(true);
      renderProgramBuilderView(document.getElementById('programBuilderContent'));
      showToast('Jour supprim├й');
    }
  });
}
function beEditIntention() {
  var val = prompt('Intention de la semaine :', (db.user && db.user.weekIntention) || '');
  if (val !== null) {
    if (!db.user) db.user = {};
    db.user.weekIntention = val;
    if (typeof saveDB==='function') saveDB();
    renderProgramBuilderView(document.getElementById('programBuilderContent'));
  }
}

// тФАтФА AJUSTER MA S├ЙANCE (v203 тАФ Gemini UX valid├й) тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
var EXERCISE_ALTERNATIVES = {
  'Presse ├а Cuisses':    ['Hack Squat', 'Belt Squat', 'Sissy Squat Machine'],
  'Hack Squat':          ['Presse ├а Cuisses', 'Belt Squat', 'Goblet Squat'],
  'Leg Extension':       ['Sissy Squat Machine', 'Presse Bulgare', 'Leg Press Unilat.'],
  'Rowing Poulie':       ['Rowing Halt├иre', 'Rowing Barre', 'Tirage Horizontal C├вble'],
  'D├йvelopp├й Inclin├й':   ['D├йvelopp├й Halt├иres Plat', 'Machine Inclin├йe', 'C├вble Crossover'],
  'Dips':                ['Extension Triceps Corde', 'Pushdown Barre', 'Dips Machine'],
  'Leg Curl':            ['Nordic Curl', 'Leg Curl Debout', 'Romanian DL Halt├иres'],
  'Tirage Vertical':     ['Tractions', 'Pullover Machine', 'Tirage Poulie Haute'],
  '├Йl├йvations Lat├йrales':['├Йl├йvations Machine', 'C├вble Lat├йral', 'Arnold Press'],
  'Face Pull':           ['Oiseau Poulie', '├Йl├йvation Arri├иre Machine', 'Band Pull-Apart'],
  'Extension Triceps':   ['Dips Machine', 'Pushdown Corde', 'Overhead Triceps'],
  'Curl Biceps':         ['Curl Marteau', 'Curl Machine', 'Curl C├вble'],
  'Mollets Machine':     ['Mollets Presse', 'Mollets Debout', 'Mollets Assis']
};

function openAdjustSession() {
  var days = (db.weeklyPlan && db.weeklyPlan.days || [])
    .filter(function(d) { return d.exercises && d.exercises.length > 0; });
  if (!days.length) { showToast('Aucun programme ├а ajuster.'); return; }
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.id = 'adjustSessionOverlay';
  overlay.innerHTML = _renderAdjustSessionHTML(days, 0);
  document.body.appendChild(overlay);
}

function _renderAdjustSessionHTML(days, activeIdx) {
  var h = '<div class="modal-box" style="max-width:420px;max-height:85vh;'
    + 'overflow-y:auto;text-align:left;padding:16px;">';
  h += '<div style="font-size:16px;font-weight:700;margin-bottom:12px;">'
    + 'тЬПя╕П Ajuster ma s├йance</div>';
  // Tabs jours
  h += '<div style="display:flex;gap:6px;overflow-x:auto;margin-bottom:14px;padding-bottom:4px;">';
  days.forEach(function(d, i) {
    var active = i === activeIdx;
    var shortDay = (d.day || '').substring(0, 3).toUpperCase();
    h += '<button onclick="_adjustSwitchDay(' + i + ')" '
      + 'style="flex-shrink:0;padding:6px 12px;border-radius:8px;font-size:11px;'
      + 'font-weight:700;border:1.5px solid ' + (active ? 'var(--accent)' : 'var(--border)') + ';'
      + 'background:' + (active ? 'rgba(10,132,255,0.12)' : 'var(--surface)') + ';'
      + 'color:' + (active ? 'var(--accent)' : 'var(--sub)') + ';cursor:pointer;">'
      + escapeHtml(shortDay) + '</button>';
  });
  h += '</div>';
  // Exercices du jour actif
  var day = days[activeIdx];
  h += '<div style="font-size:12px;color:var(--sub);margin-bottom:8px;">'
    + escapeHtml((day.day || '') + ' тАФ ' + (day.title || '')) + '</div>';
  (day.exercises || []).forEach(function(exo) {
    var locked = exo.isPrimary || exo.isCorrectivePriority;
    var lockReason = exo.isPrimary ? 'Principal' : exo.isCorrectivePriority ? 'Correctif' : '';
    var firstWork = (exo.sets || []).find(function(s) { return !s.isWarmup; });
    var setCount = (exo.sets || []).filter(function(s) { return !s.isWarmup; }).length;
    var setLine = firstWork ? (setCount + '├Ч' + (firstWork.reps || '') + ' @ ' + (firstWork.weight || '') + 'kg') : '';
    h += '<div style="display:flex;align-items:center;justify-content:space-between;'
      + 'padding:10px 0;border-bottom:0.5px solid var(--border);">';
    h += '<div><div style="font-size:13px;font-weight:600;">' + escapeHtml(exo.name || '') + '</div>'
      + '<div style="font-size:11px;color:var(--sub);">' + escapeHtml(setLine) + '</div></div>';
    var safeName = (exo.name || '').replace(/'/g, "\\'");
    var safeDay = (day.day || '').replace(/'/g, "\\'");
    if (locked) {
      h += '<button onclick="_adjustPrimaryWarning(\'' + safeName + '\',\'' + safeDay + '\')" '
        + 'style="font-size:10px;color:var(--sub);background:var(--surface);'
        + 'padding:4px 8px;border-radius:6px;border:0.5px solid var(--border);cursor:pointer;">'
        + 'ЁЯФТ ' + escapeHtml(lockReason) + '</button>';
    } else {
      h += '<button onclick="_adjustShowAlternatives(\'' + safeName + '\',\'' + safeDay + '\')" '
        + 'style="padding:6px 12px;border-radius:8px;background:var(--surface);'
        + 'border:0.5px solid var(--accent);color:var(--accent);font-size:11px;'
        + 'font-weight:600;cursor:pointer;">тЬПя╕П Changer</button>';
    }
    h += '</div>';
  });
  h += '<button onclick="document.getElementById(\'adjustSessionOverlay\').remove()" '
    + 'style="width:100%;margin-top:14px;padding:12px;border-radius:10px;'
    + 'background:none;border:0.5px solid var(--border);color:var(--sub);cursor:pointer;">'
    + 'Fermer</button></div>';
  return h;
}

function _adjustSwitchDay(idx) {
  var days = (db.weeklyPlan && db.weeklyPlan.days || [])
    .filter(function(d) { return d.exercises && d.exercises.length > 0; });
  var overlay = document.getElementById('adjustSessionOverlay');
  if (overlay) overlay.innerHTML = _renderAdjustSessionHTML(days, idx);
}

function _adjustShowAlternatives(exoName, dayName) {
  var alts = EXERCISE_ALTERNATIVES[exoName] || [];
  if (!alts.length) { showToast('Pas d\'alternative disponible pour ' + exoName); return; }
  var safeOld = exoName.replace(/'/g, "\\'");
  var safeDay = dayName.replace(/'/g, "\\'");
  var h = '<div class="modal-box" style="max-width:360px;">'
    + '<div style="font-size:14px;font-weight:700;margin-bottom:4px;">Remplacer</div>'
    + '<div style="font-size:13px;color:var(--sub);margin-bottom:14px;">' + escapeHtml(exoName) + '</div>';
  alts.forEach(function(alt) {
    var safeAlt = alt.replace(/'/g, "\\'");
    h += '<button onclick="_adjustApplyChange(\'' + safeOld + '\',\'' + safeAlt + '\',\'' + safeDay + '\')" '
      + 'style="width:100%;padding:12px;margin-bottom:8px;border-radius:10px;'
      + 'background:var(--surface);border:0.5px solid var(--border);'
      + 'text-align:left;font-size:13px;font-weight:600;cursor:pointer;">'
      + escapeHtml(alt) + '</button>';
  });
  h += '<button onclick="this.closest(\'.modal-overlay\').remove()" '
    + 'style="width:100%;padding:10px;border-radius:10px;background:none;'
    + 'border:0.5px solid var(--border);color:var(--sub);cursor:pointer;margin-top:4px;">'
    + 'Annuler</button></div>';
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = h;
  document.body.appendChild(overlay);
}

function _adjustApplyChange(oldExo, newExo, dayName) {
  document.querySelectorAll('.modal-overlay').forEach(function(o) { o.remove(); });
  var safeOld = oldExo.replace(/'/g, "\\'");
  var safeNew = newExo.replace(/'/g, "\\'");
  var safeDay = dayName.replace(/'/g, "\\'");
  var h = '<div class="modal-box" style="max-width:320px;">'
    + '<div style="font-size:14px;font-weight:700;margin-bottom:8px;">' + escapeHtml(newExo) + '</div>'
    + '<div style="font-size:12px;color:var(--sub);margin-bottom:14px;">Appliquer ce changement pour...</div>'
    + '<button onclick="_adjustConfirm(\'' + safeOld + '\',\'' + safeNew + '\',\'' + safeDay + '\',false)" '
    + 'style="width:100%;padding:12px;margin-bottom:8px;border-radius:10px;'
    + 'background:var(--surface);border:0.5px solid var(--border);text-align:left;cursor:pointer;">'
    + '<div style="font-weight:600;font-size:13px;">Cette s├йance uniquement</div>'
    + '<div style="font-size:11px;color:var(--sub);">D├йpannage ponctuel</div></button>'
    + '<button onclick="_adjustConfirm(\'' + safeOld + '\',\'' + safeNew + '\',\'' + safeDay + '\',true)" '
    + 'style="width:100%;padding:12px;margin-bottom:8px;border-radius:10px;'
    + 'background:var(--surface);border:1.5px solid var(--accent);text-align:left;cursor:pointer;">'
    + '<div style="font-weight:600;font-size:13px;color:var(--accent);">Tout le cycle actuel</div>'
    + '<div style="font-size:11px;color:var(--sub);">M├йmoriser ma pr├йf├йrence</div></button>'
    + '<button onclick="this.closest(\'.modal-overlay\').remove()" '
    + 'style="width:100%;padding:10px;border-radius:10px;background:none;'
    + 'border:0.5px solid var(--border);color:var(--sub);cursor:pointer;">Annuler</button></div>';
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = h;
  document.body.appendChild(overlay);
}

function _adjustConfirm(oldExo, newExo, dayName, permanent) {
  document.querySelectorAll('.modal-overlay').forEach(function(o) { o.remove(); });
  var days = db.weeklyPlan && db.weeklyPlan.days;
  if (!days) return;
  var targetDays = permanent ? days : days.filter(function(d) { return d.day === dayName; });
  targetDays.forEach(function(day) {
    (day.exercises || []).forEach(function(exo, i) {
      if (exo.name === oldExo) {
        day.exercises[i] = Object.assign({}, exo, { name: newExo });
      }
    });
  });
  if (permanent) {
    if (!db.exercisePreferences) db.exercisePreferences = {};
    db.exercisePreferences[oldExo] = {
      replacement: newExo,
      changedAt: Date.now(),
      count: ((db.exercisePreferences[oldExo] || {}).count || 0) + 1
    };
  }
  saveDB();
  showToast('тЬЕ ' + newExo + ' appliqu├й' + (permanent ? ' pour tout le cycle' : ' aujourd\'hui'));
  if (typeof renderProgramTab === 'function') renderProgramTab();
}

function _adjustPrimaryWarning(exoName, dayName) {
  var weekNum = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.week) || 1;
  var maxWeeks = 4;
  try {
    if (typeof BLOCK_DURATION !== 'undefined' && db.weeklyPlan && db.weeklyPlan.currentBlock) {
      var mode = (db.user && db.user.trainingMode) || 'powerbuilding';
      var level = (db.user && db.user.level) || 'intermediaire';
      var phase = db.weeklyPlan.currentBlock.phase;
      maxWeeks = (BLOCK_DURATION[mode] && BLOCK_DURATION[mode][level] && BLOCK_DURATION[mode][level][phase]) || 4;
    }
  } catch(e) {}
  var safeName = exoName.replace(/'/g, "\\'");
  var safeDay = dayName.replace(/'/g, "\\'");
  var h = '<div class="modal-box" style="max-width:340px;">'
    + '<div style="font-size:14px;font-weight:700;margin-bottom:8px;">тЪая╕П ' + escapeHtml(exoName) + '</div>'
    + '<div style="font-size:12px;color:var(--sub);margin-bottom:14px;">'
    + 'Cet exercice est la fondation de ta progression Force. '
    + 'Le remplacer modifie tes objectifs de PR et ta p├йriodisation.</div>'
    + '<div style="font-size:12px;font-weight:600;margin-bottom:8px;">Raison ?</div>'
    + '<button onclick="_adjustPrimaryEquipment(\'' + safeName + '\',\'' + safeDay + '\')" '
    + 'style="width:100%;padding:11px;margin-bottom:6px;border-radius:10px;'
    + 'background:var(--surface);border:0.5px solid var(--border);text-align:left;cursor:pointer;">'
    + 'ЁЯПЛя╕П ├Йquipement indisponible<br>'
    + '<span style="font-size:11px;color:var(--sub);">Variante proche, aujourd\'hui seulement</span></button>'
    + '<button onclick="_adjustPrimaryInjury(\'' + safeName + '\')" '
    + 'style="width:100%;padding:11px;margin-bottom:6px;border-radius:10px;'
    + 'background:var(--surface);border:0.5px solid var(--red);text-align:left;cursor:pointer;">'
    + 'ЁЯй╣ Blessure / Douleur<br>'
    + '<span style="font-size:11px;color:var(--sub);">Le Coach adapte ta structure</span></button>'
    + '<button onclick="_adjustPrimaryWant(' + weekNum + ',' + maxWeeks + ')" '
    + 'style="width:100%;padding:11px;margin-bottom:6px;border-radius:10px;'
    + 'background:var(--surface);border:0.5px solid var(--border);text-align:left;cursor:pointer;">'
    + 'ЁЯФД Envie de changement<br>'
    + '<span style="font-size:11px;color:var(--sub);">Semaine ' + weekNum + '/' + maxWeeks + ' тАФ le Coach r├йpond</span></button>'
    + '<button onclick="this.closest(\'.modal-overlay\').remove()" '
    + 'style="width:100%;padding:10px;border-radius:10px;background:none;'
    + 'border:0.5px solid var(--border);color:var(--sub);cursor:pointer;margin-top:4px;">'
    + 'Annuler</button></div>';
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = h;
  document.body.appendChild(overlay);
}

function _adjustPrimaryWant(weekNum, maxWeeks) {
  document.querySelectorAll('.modal-overlay').forEach(function(o) { o.remove(); });
  showToast('ЁЯТк Semaine ' + weekNum + '/' + maxWeeks + '. Termine ce bloc pour valider tes gains avant de changer de pilier.', 5000);
}
function _adjustPrimaryEquipment(exoName, dayName) {
  document.querySelectorAll('.modal-overlay').forEach(function(o) { o.remove(); });
  _adjustShowAlternatives(exoName, dayName);
}
function _adjustPrimaryInjury(exoName) {
  document.querySelectorAll('.modal-overlay').forEach(function(o) { o.remove(); });
  showToast('ЁЯй╣ Blessure not├йe. Le Coach adapte ta prochaine s├йance.', 4000);
  if (!db.user.injuries) db.user.injuries = [];
  if (db.user.injuries.indexOf(exoName) === -1) db.user.injuries.push(exoName);
  saveDB();
}

function pbEditExisting() {
  if (db.user.programMode === 'custom') { pbStartCustomBuilder(true); return; }
  var routine = getRoutine();
  var allDays = ['Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi', 'Dimanche'];
  var dayNames = [];
  var dayExercises = {};
  allDays.forEach(function(day) {
    var label = routine[day];
    if (label && !/repos|ЁЯШ┤/i.test(label)) {
      dayNames.push(label);
      // R├йcup├йrer les exercices existants
      var exos = (db.routineExos && db.routineExos[day]) ? db.routineExos[day] : [];
      if (!exos.length && db.generatedProgram) {
        var gp = db.generatedProgram.find(function(p) { return p.day === day && !p.isRest; });
        if (gp && gp.exercises) exos = gp.exercises.map(function(e) { return typeof e === 'string' ? e : (e && e.name) || 'Exercice'; });
      }
      dayExercises[label] = exos;
    }
  });
  _pbState = { mode: 'manual', step: 3, days: dayNames.length || 4, split: 'custom', dayNames: dayNames, dayExercises: dayExercises };
  renderProgramBuilder();
}

function pbResetProgram() {
  if (!confirm('R├йinitialiser le programme ? Tu pourras en cr├йer un nouveau.')) return;
  db.generatedProgram = null;
  db.routine = null;
  db.manualProgram = null;
  db.routineExos = null;
  db.weeklyPlan = null;
  db.customProgramTemplate = null;
  db.customProgramBackups = [];
  db.user.programMode = 'auto';
  db.user.programParams = {};
  saveDBNow();
  _pbState = null;
  renderProgramBuilder();
}

// PROGRAMME VIEWER + SWAP EXERCICE
// ============================================================
function renderProgramViewer() {
  const plan = db.generatedProgram;
  const card = document.getElementById('programViewerCard');
  const viewer = document.getElementById('programViewer');
  if (!plan || !plan.length) { if (card) card.style.display = 'none'; return; }
  if (card) card.style.display = 'block';
  if (!viewer) return;
  viewer.innerHTML = plan.map((d, di) => {
    if (d.isRest) {
      return '<div class="prog-day-card" style="opacity:0.45;">'+
        '<div class="prog-day-header">'+
        '<div><div class="prog-day-badge" style="background:var(--border);color:var(--sub);">'+d.day.substring(0,3)+'</div><div class="prog-day-title" style="margin-top:6px;">Repos</div></div>'+
        '</div></div>';
    }
    const exos = d.exos || [];
    return '<div class="prog-day-card">'+
      '<div class="prog-day-header" onclick="toggleProgDay('+di+')">'+
      '<div><div class="prog-day-badge">'+d.day.substring(0,3)+'</div><div class="prog-day-title" style="margin-top:6px;">'+d.label+'</div>'+
      '<div class="prog-day-sub">'+exos.length+' exercice'+(exos.length>1?'s':'')+'</div></div>'+
      '<span class="prog-day-chevron" id="prog-chev-'+di+'">тЦ╛</span></div>'+
      '<div class="prog-day-body" id="prog-body-'+di+'">'+
      exos.map((id, ei) => {
        const exoEntry = d.exosSets ? d.exosSets[ei] : null;
        const setsReps = exoEntry?.setsReps || EXO_DB[id]?.sets || '';
        const e = EXO_DB[id] || { name: id, sets:'', icon:'ЁЯТк', muscle:'', alts:[] };
        return '<div class="prog-exo-row">'+
          '<span class="prog-exo-icon">'+e.icon+'</span>'+
          '<div class="prog-exo-info">'+
          '<div class="prog-exo-name">'+e.name+'</div>'+
          '<div class="prog-exo-detail">'+(setsReps||e.sets)+(e.muscle?' ┬╖ '+e.muscle:'')+'</div></div>'+
          (e.alts && e.alts.length ? '<button class="prog-exo-swap" onclick="openSwap('+di+','+ei+',\''+id+'\')">тЖФ Remplacer</button>' : '')+
          '</div>';
      }).join('')+
      '</div></div>';
  }).join('');
}

function toggleProgDay(di) {
  const body = document.getElementById('prog-body-'+di);
  const chev = document.getElementById('prog-chev-'+di);
  if (!body) return;
  body.classList.toggle('open');
  if (chev) chev.classList.toggle('open');
}

function openSwap(dayIdx, exoIdx, currentId) {
  const exo = EXO_DB[currentId];
  if (!exo || !exo.alts || !exo.alts.length) return;
  const matIcons = { salle:'ЁЯПЛя╕П', halteres:'ЁЯТк', maison:'ЁЯПа' };
  const modal = document.createElement('div');
  modal.className = 'swap-modal';
  modal.id = 'swap-modal';
  modal.innerHTML = '<div class="swap-modal-box">'+
    '<div class="swap-modal-title">Remplacer : '+exo.name+'</div>'+
    '<div class="swap-modal-sub">M├кme groupe musculaire ┬╖ '+exo.muscle+'</div>'+
    exo.alts.map((alt, ai) => {
      const matLabel = alt.mat || 'salle';
      return '<button class="swap-alt-btn" onclick="confirmSwap('+dayIdx+','+exoIdx+',\''+currentId+'\','+ai+')">'+
        '<span class="swap-alt-icon">'+(matIcons[matLabel]||'ЁЯТк')+'</span>'+
        '<div><span class="swap-alt-name">'+alt.name+'</span>'+
        '<span class="swap-alt-mat">'+matLabel+'<span class="swap-mat-badge">'+matLabel+'</span></span></div>'+
        '</button>';
    }).join('')+
    '<button onclick="closeSwap()" style="width:100%;margin-top:8px;background:none;border:none;color:var(--sub);padding:12px;cursor:pointer;font-size:13px;">Annuler</button>'+
    '</div>';
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) closeSwap(); });
}

function closeSwap() {
  const m = document.getElementById('swap-modal');
  if (m) m.remove();
}

function confirmSwap(dayIdx, exoIdx, currentId, altIdx) {
  const exo = EXO_DB[currentId];
  if (!exo || !exo.alts[altIdx]) return;
  const alt = exo.alts[altIdx];
  // Cr├йer ou r├йutiliser une entr├йe pour cet alt
  const newId = '_swap_'+dayIdx+'_'+exoIdx;
  EXO_DB[newId] = {
    name: alt.name, sets: exo.sets, mat: [alt.mat||'salle'],
    muscle: exo.muscle, icon: exo.icon,
    alts: [{ name: exo.name, mat: exo.mat[0] }, ...exo.alts.filter((_,i) => i !== altIdx)]
  };
  if (db.generatedProgram && db.generatedProgram[dayIdx]) {
    db.generatedProgram[dayIdx].exos[exoIdx] = newId;
    saveDB();
  }
  closeSwap();
  renderProgramViewer();
  showToast('тЬУ Exercice remplac├й');
}

// DUP ├ЙTAPE B тАФ Migration one-shot des zones e1RM depuis l'historique
function migrateDUPRegisters() {
  if (!db.exercises || db._dupMigrated) return;
  var cutoff30j = Date.now() - 30 * 86400000;
  Object.keys(db.exercises).forEach(function(exoName) {
    var exo = db.exercises[exoName];
    if (!exo || exo.zones) return;
    var legacyE1RM = exo.e1rm || exo.shadowWeight || 0;
    var zoneE1RMs = { force: 0, hypertrophie: 0, vitesse: 0 };
    (db.logs || []).forEach(function(log) {
      if (log.timestamp < cutoff30j) return;
      (log.exercises || []).forEach(function(logExo) {
        if (!logExo.name || logExo.name !== exoName) return;
        (logExo.allSets || logExo.series || []).forEach(function(s) {
          if (s.isWarmup || s.isBackOff) return;
          var reps = parseInt(s.reps) || 0;
          var weight = parseFloat(s.weight) || 0;
          if (reps <= 0 || weight <= 0) return;
          var e1rmCalc = weight / (1.0278 - 0.0278 * reps);
          var zone = typeof getDUPZone === 'function' ? getDUPZone(reps) : 'force';
          if (e1rmCalc > zoneE1RMs[zone]) zoneE1RMs[zone] = e1rmCalc;
        });
      });
    });
    var baseE1RM = zoneE1RMs.force > 0 ? zoneE1RMs.force : legacyE1RM;
    if (baseE1RM <= 0) return;
    exo.zones = {
      force: {
        e1rm: Math.round((zoneE1RMs.force > 0 ? zoneE1RMs.force : baseE1RM) / 2.5) * 2.5,
        shadowWeight: exo.shadowWeight || 0, sessionsCount: 0
      },
      hypertrophie: {
        e1rm: Math.round((zoneE1RMs.hypertrophie > 0 ? zoneE1RMs.hypertrophie : baseE1RM * 0.94) / 2.5) * 2.5,
        shadowWeight: 0, sessionsCount: 0
      },
      vitesse: {
        e1rm: Math.round((zoneE1RMs.vitesse > 0 ? zoneE1RMs.vitesse : baseE1RM * 0.88) / 2.5) * 2.5,
        shadowWeight: 0, sessionsCount: 0
      }
    };
    if (typeof applyDUPTethering === 'function') applyDUPTethering(exoName);
  });
  db._dupMigrated = true;
  saveDB();
}

function migrateBadges() {
  if (db._badgesMigrated) return;
  if (!db.earnedBadges) db.earnedBadges = {};
  var allBadges = typeof getAllBadges === 'function' ? getAllBadges() : [];
  allBadges.forEach(function(badge) {
    if (!badge.id || badge.impossible) return;
    if (db.earnedBadges[badge.id]) return; // don't overwrite
    try {
      if (typeof badge.ck === 'function' && badge.ck()) {
        db.earnedBadges[badge.id] = { earnedAt: Date.now(), xp: badge.xp || 0 };
      }
    } catch(e) {}
  });
  db._badgesMigrated = true;
  saveDB();
}

function migrateActivityData() {
  if (db.user._activityMigrated) return;

  var legacy = db.user.secondaryActivities || [];
  var existing = db.user.activities || [];
  var template = [];

  // Merge legacy strings (onboarding) + existing objects (settings)
  legacy.forEach(function(act) {
    var sanitized = typeof sanitizeActivity === 'function'
      ? sanitizeActivity(act)
      : { type: act, intensity: 3, duration: 45, days: [], fixed: true };
    var exists = existing.some(function(e) {
      var normalizedType = (typeof ACTIVITY_KEY_MAP !== 'undefined'
        ? (ACTIVITY_KEY_MAP[e.type] || e.type) : e.type);
      return normalizedType === sanitized.type;
    });
    if (!exists) template.push(sanitized);
  });

  existing.forEach(function(act) {
    template.push(typeof sanitizeActivity === 'function' ? sanitizeActivity(act) : act);
  });

  db.user.activityTemplate = template;
  db.user._activityMigrated = true;
  saveDB();
}

// v219 тАФ Normalize legacy weeklyPlan.days[].exercises[].sets:number тЖТ Array.
// Pre-v218, selectExercisesForProfile injected corrective exercises with
// sets:N (an integer). renderWpExercise / progShowDayDetail / renderGoTab
// all called sets.filter(...) which crashed for any exo with sets:number.
// Heal once on load so old saved plans don't keep crashing the UI.
function migrateWeeklyPlanSets() {
  if (db._weeklyPlanSetsMigrated) return;
  var plan = db.weeklyPlan;
  if (plan && Array.isArray(plan.days)) {
    plan.days.forEach(function(d) {
      if (!d || !Array.isArray(d.exercises)) return;
      d.exercises.forEach(function(exo) {
        if (!exo || Array.isArray(exo.sets) || typeof exo.sets !== 'number') return;
        var _cnt = Math.max(1, Math.round(exo.sets));
        var _reps = exo.reps || '10';
        var _rpe = exo.rpe || 8;
        var _isWup = exo.isWarmup === true;
        var _arr = [];
        for (var _i = 0; _i < _cnt; _i++) {
          _arr.push({ reps: _reps, rpe: _rpe, weight: null, isWarmup: _isWup });
        }
        exo.sets = _arr;
      });
    });
  }
  db._weeklyPlanSetsMigrated = true;
  saveDB();
}

function migrateInjuryNames() {
  // Pre-v179 : injuries were stored as accented capitalised labels ("├Йpaules"),
  // but INJURY_EXCLUSIONS / WP_INJURY_EXCLUSIONS keys are lowercase ASCII
  // ("epaules") тАФ so exclusions silently never fired. Normalize once.
  if (db.user._injuryMigrated) return;
  if (!db.user.programParams || !Array.isArray(db.user.programParams.injuries)) {
    db.user._injuryMigrated = true;
    return;
  }
  var fn = (typeof _normalizeInjuryZone === 'function')
    ? _normalizeInjuryZone
    : function(z) { return String(z || '').toLowerCase().normalize('NFD').replace(/[╠А-═п]/g, ''); };
  var seen = {};
  db.user.programParams.injuries = db.user.programParams.injuries
    .map(fn)
    .filter(function(z) { if (!z || seen[z]) return false; seen[z] = true; return true; });
  db.user._injuryMigrated = true;
  saveDB();
}

// v212 тАФ Synchronise db.routine avec programParams.selectedDays.
// Bug observ├й (D'Jo/L├йa) : routine peut diverger des selectedDays apr├иs
// migrations multiples тАФ un jour s├йlectionn├й appara├оt en Repos ou un
// jour exclu garde un titre d'entra├оnement. Force la coh├йrence.
function syncRoutineWithSelectedDays() {
  var _selected = (db.user && db.user.programParams && db.user.programParams.selectedDays) || [];
  if (!_selected.length || !db.routine) return;
  var _allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  var _changed = false;
  _allDays.forEach(function(day) {
    var _isSelected = _selected.indexOf(day) >= 0;
    var _label = db.routine[day];
    var _isRest = typeof _label === 'string' && /repos|rest|ЁЯШ┤/i.test(_label);
    if (_isSelected && _label && _isRest) {
      delete db.routine[day];
      _changed = true;
    } else if (!_isSelected && _label && !_isRest) {
      db.routine[day] = 'ЁЯШ┤ Repos';
      _changed = true;
    }
  });
  if (_changed && typeof saveDB === 'function') saveDB();
}

// ============================================================
// INIT
// ============================================================
(function init() {
  if (checkWaitlistRoute()) return; // Waitlist landing page тАФ skip app init
  if(!db.reports)db.reports=[];
  if (typeof grantMonthlyFreeze === 'function') grantMonthlyFreeze();
  let ns=false;
  db.logs.forEach(l=>{if(!l.id){l.id=generateId();ns=true;}});

  // Recalculer maxRM de chaque exercice depuis series/repRecords (corrige les valeurs corrompues)
  db.logs.forEach(log=>{
    log.exercises.forEach(exo=>{
      if(exo.isCardio||exo.isTime)return;
      let recalc=0;
      if(exo.series&&exo.series.length){exo.series.forEach(s=>{if(s.weight>0&&s.reps>0){const rm=calcE1RM(s.weight,s.reps);if(rm>recalc)recalc=rm;}});}
      if(exo.repRecords){Object.entries(exo.repRecords).forEach(([rKey,w])=>{if(w>0){const rm=calcE1RM(w,parseInt(rKey));if(rm>recalc)recalc=rm;}});}
      // Toujours ├йcraser maxRM avec la valeur recalcul├йe (m├кme 0 si aucune donn├йe)
      if(exo.maxRM!==recalc){exo.maxRM=recalc;ns=true;}
    });
  });

  recalcBestPR();
  if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
  if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks();
  if(ns)saveDB();
  cleanupExistingLogs();
  purgeExpiredReports();
  // Compress logs older than 6 months to save storage
  if (typeof compressOldLogs === 'function') compressOldLogs();

  const today=DAYS_FULL[new Date().getDay()];
  selectedDay=today;
  document.querySelectorAll('.day-btn').forEach(b=>b.classList.toggle('active',b.dataset.day===today));

  // Pr├й-remplir settings
  if(db.user.name){const ni=document.getElementById('inputName');if(ni)ni.value=db.user.name;}
  document.getElementById('inputBW').value=db.user.bw||'';
  var _fpEl = document.getElementById('inputFatPct');
  if (_fpEl) _fpEl.value = (db.user.fatPct != null) ? db.user.fatPct : '';
  const tB=document.getElementById('tgtBench'),tS=document.getElementById('tgtSquat'),tD=document.getElementById('tgtDead');
  if(tB)tB.value=db.user.targets.bench;if(tS)tS.value=db.user.targets.squat;if(tD)tD.value=db.user.targets.deadlift;

  newPRs={bench:false,squat:false,deadlift:false};
  renderDash();
  updateCoachBadge();
  // Migration : generatedProgram
  if (!db.generatedProgram) db.generatedProgram = null;

  // Migration : re-estimer la dur├йe des s├йances sans source GO r├йelle
  var _durMigrated = false;
  (db.logs || []).forEach(function(log) {
    if (log.durationSource === 'go') return;
    var estimated = estimateSessionDuration(log.exercises || []) * 60; // en secondes
    if (estimated > 0) { log.duration = estimated; log.durationSource = 'estimated'; _durMigrated = true; }
  });
  if (_durMigrated) saveDB();
  renderProgramViewer();

  if (typeof migrateExerciseNames === 'function') migrateExerciseNames();
  migrateDUPRegisters();
  migrateActivityData();
  if (db.user.morpho === undefined) db.user.morpho = null;
  migrateInjuryNames();
  migrateBadges();
  migrateWeeklyPlanSets();
  if (typeof syncRoutineWithSelectedDays === 'function') syncRoutineWithSelectedDays();

  // Auto-generate weeklyPlan on J1 тАФ deferred so WP_SESSION_TEMPLATES (line 15269+) is initialised
  setTimeout(function() {
    if (db.user && db.user.onboarded && db.user.programParams && db.user.programParams.freq
        && (!db.weeklyPlan || !Array.isArray(db.weeklyPlan.days) || !db.weeklyPlan.days.length)) {
      try { if (typeof generateWeeklyPlan === 'function') generateWeeklyPlan(); } catch(e) {}
    }
  }, 0);

  // Auth gate: show login screen if not authenticated
  checkAuthGate().then(() => {
    // Helper: show onboarding then quiz тАФ only for authenticated email users
    function _showFirstRunUI(user) {
      if (!user || !user.email) return; // skip for anonymous / no-auth
      if (needsOnboarding()) showOnboarding();
      db.gamification = db.gamification || {};
      if (!db.user.quizDone) {
        setTimeout(function() { if (typeof showClassQuiz === 'function') showClassQuiz(); }, 400);
      }
    }
    cloudSignIn().then(async user => {
      if (!user) return;
      if (db.logs.length === 0) {
        await syncFromCloud();
        if (typeof grantMonthlyFreeze === 'function') grantMonthlyFreeze();
        if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
        if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
        setTimeout(_restoreLastTabFromCloud, 0);
        _showFirstRunUI(user);
        return;
      }
      if (!db.lastSync) {
        if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
        if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
        syncToCloud(true);
        return;
      }
      try {
        const {data:{user:u}} = await supaClient.auth.getUser();
        if (!u) {
          if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
          if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
          syncToCloud(true); return;
        }
        const {data, error} = await supaClient.from('sbd_profiles').select('updated_at').eq('user_id', u.id).maybeSingle();
        if (error) throw error;
        if (data && data.updated_at) {
          const cloudTs = new Date(data.updated_at).getTime();
          if (cloudTs > db.lastSync + 5000) {
            showToast('тШБя╕П Donn├йes plus r├йcentes sur le cloud тАФ synchronisationтАж');
            await syncFromCloud();
            if (typeof grantMonthlyFreeze === 'function') grantMonthlyFreeze();
            if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
            if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
            setTimeout(_restoreLastTabFromCloud, 0);
          } else {
            if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
            if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
            syncToCloud(true);
          }
        } else {
          if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
          if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
          syncToCloud(true);
        }
      } catch(e) {
        if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
        if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
        syncToCloud(true);
      }
      // Onboarding + quiz after all sync paths resolve
      _showFirstRunUI(user);
      // Check password migration for existing magic-link users
      checkPasswordMigration(user);
      // Keep-alive ping to prevent Supabase project pause
      if (typeof keepAlive === 'function') keepAlive();
    });
  });
  // Local notifications init
  try { initNotifications(); } catch(e) {}
  // iOS install prompt (Safari only, once)
  setTimeout(function() { try { checkIOSInstallPrompt(); } catch(e) {} }, 3000);
})();

// ============================================================
// NOTIFICATIONS LOCALES
// ============================================================
function initNotifications() {
  if (!('Notification' in window) || !('serviceWorker' in navigator)) return;
  if (Notification.permission === 'granted') {
    _checkTrainingReminder();
    return;
  }
  if (db.logs.length < 3) return;
  Notification.requestPermission().then(function(perm) {
    if (perm === 'granted') _checkTrainingReminder();
  });
}

function checkIOSInstallPrompt() {
  var ua = navigator.userAgent || '';
  var isIOS = /iPad|iPhone|iPod/.test(ua);
  var isSafari = isIOS && !/CriOS|FxiOS|EdgiOS|OPiOS/.test(ua);
  if (!isSafari) return;
  if (navigator.standalone) return; // already installed
  if (db.user && db.user._iosInstallPromptShown) return;
  var banner = document.createElement('div');
  banner.id = 'ios-install-banner';
  banner.style.cssText = 'position:fixed;bottom:0;left:0;right:0;z-index:9999;'
    + 'background:var(--bg-card,#1c1c1e);border-top:0.5px solid var(--border-card,#3a3a3c);'
    + 'padding:14px 16px;display:flex;align-items:center;gap:12px;'
    + 'box-shadow:0 -4px 20px rgba(0,0,0,0.4);';
  banner.innerHTML = '<div style="flex:1;">'
    + '<div style="font-size:13px;font-weight:600;color:var(--text,#fff);margin-bottom:2px;">Installer TrainHub</div>'
    + '<div style="font-size:11px;color:var(--sub,#8e8e93);">Appuie sur <strong>Partager тОЩ</strong> puis <strong>Sur l\'├йcran d\'accueil</strong></div>'
    + '</div>'
    + '<button onclick="document.getElementById(\'ios-install-banner\').remove()" '
    + 'style="background:none;border:none;color:var(--sub,#8e8e93);font-size:20px;padding:4px;cursor:pointer;">тЬХ</button>';
  document.body.appendChild(banner);
  if (db.user) { db.user._iosInstallPromptShown = true; saveDB(); }
  setTimeout(function() { var b = document.getElementById('ios-install-banner'); if (b) b.remove(); }, 10000);
}

function sendLocalNotification(title, body) {
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  try { new Notification(title, { body: body }); } catch(e) {}
}

function addToNotificationHistory(title, body, type) {
  if (!db.notificationHistory) db.notificationHistory = [];
  db.notificationHistory.unshift({ title: title, body: body, type: type || 'training', ts: Date.now(), read: false });
  if (db.notificationHistory.length > 20) db.notificationHistory.length = 20;
  db._unreadNotifications = (db._unreadNotifications || 0) + 1;
  saveDB();
  _refreshLocalNotifBadge();
}

function _refreshLocalNotifBadge() {
  var unread = (db.notificationHistory || []).filter(function(n) { return !n.read; }).length;
  if (unread === 0) return;
  var badge = document.getElementById('notif-bell-badge');
  if (!badge) return;
  badge.textContent = unread > 9 ? '9+' : String(unread);
  badge.style.display = 'flex';
}

function renderNotificationCenter() {
  var container = document.getElementById('notif-training-list');
  if (!container) return;
  var history = (db.notificationHistory || []);
  if (history.length === 0) { container.style.display = 'none'; return; }
  var hadUnread = history.some(function(n) { return !n.read; });
  history.forEach(function(n) { n.read = true; });
  if (hadUnread) { db._unreadNotifications = 0; saveDB(); }
  container.style.display = 'block';
  var icons = { acwr: 'тЪб', streak_danger: 'ЁЯТк', session_complete: 'тЬЕ', local: 'ЁЯФФ', training: 'ЁЯПЛя╕П' };
  container.innerHTML = history.map(function(n) {
    var icon = icons[n.type] || 'ЁЯФФ';
    var d = new Date(n.ts);
    var timeStr = d.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' })
      + ' ' + d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
    return '<div style="display:flex;gap:10px;padding:10px 14px;border-bottom:0.5px solid rgba(255,255,255,0.04);">'
      + '<span style="font-size:16px;flex-shrink:0;">' + icon + '</span>'
      + '<div style="flex:1;min-width:0;">'
      + '<div style="font-size:13px;font-weight:600;color:var(--text);">' + n.title + '</div>'
      + '<div style="font-size:12px;color:var(--sub);margin-top:2px;">' + n.body + '</div>'
      + '<div style="font-size:10px;color:var(--sub);margin-top:4px;opacity:0.6;">' + timeStr + '</div>'
      + '</div></div>';
  }).join('');
}

async function sendPushNotification(title, body, type) {
  var today = getTodayStr();
  if (db._lastPushSent === today) return;
  if (typeof supaClient === 'undefined' || !supaClient) return;
  try {
    var sessionData = await supaClient.auth.getSession();
    var session = sessionData.data && sessionData.data.session;
    if (!session) return;
    await fetch('https://swwygywahfdenyzotrce.supabase.co/functions/v1/send-push', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + session.access_token },
      body: JSON.stringify({ title: title, body: body, type: type || 'training' })
    });
    db._lastPushSent = today;
    saveDB();
  } catch(e) {
    console.error('sendPushNotification:', e);
  }
}

async function checkPushTriggers() {
  var now = new Date();
  if (now.getHours() < 20) return;

  var _srs = typeof computeSRS === 'function' ? computeSRS() : null;
  var _acwr = _srs ? (_srs.acwr || 1.0) : 1.0;
  if (_acwr >= 0.8 && _acwr <= 1.3) {
    if ((Date.now() - (db._lastPushAcwr || 0)) / 86400000 >= 7) {
      var t1 = 'тЪб Fen├кtre optimale';
      var b1 = 'Ton ratio charge/r├йcup├йration est parfait. C\'est le bon moment pour pousser.';
      addToNotificationHistory(t1, b1, 'acwr');
      await sendPushNotification(t1, b1, 'acwr');
      db._lastPushAcwr = Date.now();
      saveDB();
      return;
    }
  }

  var _lastLog = (db.logs || []).slice().sort(function(a, b) { return (b.timestamp || 0) - (a.timestamp || 0); })[0];
  if (_lastLog) {
    var _daysSince = (Date.now() - (_lastLog.timestamp || 0)) / 86400000;
    if (_daysSince >= 2 && (Date.now() - (db._lastPushStreak || 0)) / 86400000 >= 7) {
      var t2 = 'ЁЯТк Reprend l├а o├╣ tu t\'es arr├кt├й';
      var b2 = '├Зa fait ' + Math.floor(_daysSince) + ' jours sans s├йance. M├кme 30 min compte.';
      addToNotificationHistory(t2, b2, 'streak_danger');
      await sendPushNotification(t2, b2, 'streak_danger');
      db._lastPushStreak = Date.now();
      saveDB();
    }
  }
}

