function checkDisciplinePercentile() {
  var monthStart = new Date();
  monthStart.setDate(1); monthStart.setHours(0, 0, 0, 0);
  var count = (db.logs || []).filter(function(l) {
    return (l.timestamp || 0) > monthStart.getTime();
  }).length;
  if ((Date.now() - (db._lastPercentileNotif || 0)) / 86400000 < 7) return;
  var rank = REGULARITY_BENCHMARKS.find(function(b) { return count >= b.sessions; });
  if (!rank) return;
  sendLocalNotification(
    rank.emoji + ' R├йgularit├й ' + rank.label,
    'Avec ' + count + ' s├йances ce mois, tu es dans le ' + rank.label + '.'
  );
  db._lastPercentileNotif = Date.now();
  saveDB();
}

function checkPersonalRecord() {
  var now = new Date();
  var thisMonth = (db.logs || []).filter(function(l) {
    var d = new Date(l.timestamp || 0);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  }).length;
  var lastYear = (db.logs || []).filter(function(l) {
    var d = new Date(l.timestamp || 0);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear() - 1;
  }).length;
  if (lastYear < 3 || thisMonth <= lastYear) return;
  if ((Date.now() - (db._lastGhostNotif || 0)) / 86400000 < 7) return;
  showToast('ЁЯС╗ ' + thisMonth + ' s├йances ce mois тАФ record vs l\'an dernier (' + lastYear + ') !');
  db._lastGhostNotif = Date.now();
  saveDB();
}

async function checkScheduledNotifications() {
  if (!db.user || !db.user.onboardingDate) return;
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  var onboardingDate = new Date(db.user.onboardingDate);
  var daysSince = Math.floor((Date.now() - onboardingDate.getTime()) / 86400000) + 1;
  if (daysSince < 1 || daysSince > 30) return;
  var sent = db.notificationsSent || [];

  for (var i = 0; i < NOTIFICATION_SCHEDULE.length; i++) {
    var notif = NOTIFICATION_SCHEDULE[i];
    if (notif.day !== daysSince) continue;
    if (sent.indexOf('day_' + notif.day) >= 0) continue;
    if (notif.profileFilter && db.user.obProfile !== notif.profileFilter) continue;

    var shouldSend = false;
    if (notif.trigger === 'morning' || notif.trigger === 'evening'
        || notif.trigger === 'training_time' || notif.trigger === 'friend_activity') {
      shouldSend = true;
    }
    if (notif.trigger === 'high_srs') {
      var srs = typeof computeSRS === 'function' ? computeSRS() : { score: 75 };
      shouldSend = srs.score >= 80;
    }
    if (!shouldSend) continue;

    var body = notif.body;
    if (body.includes('{{tonnage}}')) {
      body = body.replace('{{tonnage}}', calcWeeklyTonnage());
    }

    sendLocalNotification(notif.title, body);

    if (!db.notificationsSent) db.notificationsSent = [];
    db.notificationsSent.push('day_' + notif.day);
    saveDB();
    break; // Une seule notification par jour
  }

  // тФАтФА Triggers comportementaux (ind├йpendants du calendrier J1тЖТJ30) тФАтФАтФАтФАтФАтФАтФАтФАтФА

  // Trigger ACWR optimal тАФ max 1x par semaine
  var _srsForAcwr = typeof computeSRS === 'function' ? computeSRS() : null;
  var _acwr = _srsForAcwr ? (_srsForAcwr.acwr || 1.0) : null;
  if (_acwr && _acwr >= 0.8 && _acwr <= 1.3) {
    var _lastAcwrNotif = db._lastAcwrNotif || 0;
    if ((Date.now() - _lastAcwrNotif) / 86400000 >= 7) {
      sendLocalNotification(
        'тЪб Fen├кtre optimale',
        'Ton ratio charge/r├йcup├йration est parfait cette semaine. C\'est le bon moment pour pousser un peu plus.'
      );
      db._lastAcwrNotif = Date.now();
      saveDB();
    }
  }

  // Trigger s├йances manqu├йes тАФ max 1x tous les 3 jours
  var _lastLog = (db.logs || []).slice().sort(function(a, b) { return (b.timestamp||0) - (a.timestamp||0); })[0];
  if (_lastLog) {
    var _daysSinceSession = (Date.now() - (_lastLog.timestamp || 0)) / 86400000;
    var _lastMissedNotif = db._lastMissedNotif || 0;
    if (_daysSinceSession >= 2 && (Date.now() - _lastMissedNotif) / 86400000 >= 3) {
      sendLocalNotification(
        'ЁЯТк On se retrouve ?',
        '├Зa fait ' + Math.floor(_daysSinceSession) + ' jours. M├кme 30 minutes compte pour maintenir ta progression.'
      );
      db._lastMissedNotif = Date.now();
      saveDB();
    }
  }

  // Trigger percentile r├йgularit├й + ghost record тАФ max 1x par semaine chacun
  checkDisciplinePercentile();
  checkPersonalRecord();

  // Push notifications (background) тАФ ACWR optimal + streak danger
  checkPushTriggers();
}

