function toggleCorpsAcc(id) {
  const body = document.getElementById(id);
  if (!body) return;
  body.classList.toggle('open');
  const chev = document.getElementById('chev-' + id);
  if (chev) chev.classList.toggle('open', body.classList.contains('open'));

  // Rendu lazy du profil social ├а l'ouverture de l'accord├йon
  if (id === 'ca-social-profile' && body.classList.contains('open')) {
    if (typeof renderSocialProfileCard === 'function') renderSocialProfileCard();
  }
}

function renderCorpsTab() {
  const bw=getUserBW();
  const bench=db.bestPR.bench,squat=db.bestPR.squat,dead=db.bestPR.deadlift;
  const logs7=getLogsInRange(7),tonnage7=logs7.reduce((s,l)=>s+l.volume,0);
  const ipf=calcIPFGLTotal(bench,squat,dead,bw);
  const ratio=bw>0&&ipf>0?Math.round((ipf/bw)*100)/100:0;
  const baseTdee=calcTDEE(bw,tonnage7);
  // Dynamic TDEE based on today's programme
  const todayDayName = DAYS_FULL[new Date().getDay()];
  const todayRoutine = getRoutine();
  const todayLabel = todayRoutine[todayDayName] || '';
  const todayIsRest = !todayLabel || /repos|ЁЯШ┤/i.test(todayLabel);
  const todayIsDeload = isDeloadWeek();
  let tdeeMultiplier = 0.95; // Repos par d├йfaut
  let tdeeLabel = 'ЁЯЫЛя╕П Jour de repos тАФ -5% kcal';
  if (todayIsDeload) {
    tdeeMultiplier = 0.95; tdeeLabel = 'ЁЯФД Jour de deload тАФ -5% kcal';
  } else if (!todayIsRest) {
    // Check if today has a big lift
    const todayExos = getProgExosForDay(todayDayName);
    const hasBig = todayExos.some(n => {
      const nl = n.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
      return /squat|deadlift|souleve|bench\s*(press|barre|couche)?|developpe\s*couche/.test(nl);
    });
    if (hasBig) { tdeeMultiplier = 1.10; tdeeLabel = 'ЁЯПЛя╕П Jour lourd тАФ +10% kcal'; }
    else { tdeeMultiplier = 1.05; tdeeLabel = 'ЁЯТк Jour mod├йr├й тАФ +5% kcal'; }
  }
  const tdee = baseTdee > 0 ? Math.round(baseTdee * tdeeMultiplier) : 0;
  const cible=calcCalorieCible(bw);
  const adjustedCible = baseTdee > 0 ? Math.round(cible * tdeeMultiplier / (cible > 0 && baseTdee > 0 ? baseTdee / baseTdee : 1)) : cible;
  const macros=calcMacrosCibles(adjustedCible > 0 ? adjustedCible : cible, bw);
  const today=new Date().toDateString();
  const todayEntry=(db.body||[]).find(e=>new Date(e.ts).toDateString()===today);
  const kcalMange=todayEntry?todayEntry.kcal:0,protMange=todayEntry?todayEntry.prot:0,carbMange=todayEntry?todayEntry.carb:0,fatMange=todayEntry?todayEntry.fat:0;
  const now2=new Date(),heuresPassed=now2.getHours()+now2.getMinutes()/60;
  const brulees=tdee>0?Math.round((tdee/24)*heuresPassed):0;
  const restantes=Math.max(0,(adjustedCible||cible)-kcalMange);
  const RING_CIRCUM=440,pctMange=cible>0?Math.min(1,kcalMange/cible):0,dashOffset=Math.round(RING_CIRCUM*(1-pctMange));
  const ring=document.getElementById('nutriRingFill');
  if (ring){ring.style.strokeDashoffset=dashOffset;ring.className='nutri-ring-fill'+(pctMange>1?' over':pctMange>0.9?' warn':'');}
  const setEl=(id,val)=>{const el=document.getElementById(id);if(el)el.textContent=val;};
  setEl('nutriKcalRestantes',restantes);setEl('nutriKcalSub',kcalMange>0?`sur ${cible} kcal`:`Objectif: ${cible} kcal`);
  setEl('nutriMangees',kcalMange);setEl('nutriCible',cible);setEl('nutriBrulees',brulees);
  const barW=(done,target)=>Math.min(100,target>0?Math.round(done/target*100):0)+'%';
  const applyBar=(id,done,target)=>{const el=document.getElementById(id);if(!el)return;el.style.width=barW(done,target);el.classList.toggle('over',done>target*1.05);};
  applyBar('nutriProtBar',protMange,macros.prot);applyBar('nutriCarbBar',carbMange,macros.carb);applyBar('nutriFatBar',fatMange,macros.fat);
  setEl('nutriProtLabel',`${protMange} / ${macros.prot} g`);setEl('nutriCarbLabel',`${carbMange} / ${macros.carb} g`);setEl('nutriFatLabel',`${fatMange} / ${macros.fat} g`);
  setEl('nutriTDEELabel',tdee>0?`${tdee} kcal`:'тАФ');setEl('nutriProtCible',`${macros.prot}g`);
  const tdeeDayEl = document.getElementById('nutriDayTypeLabel');
  if (tdeeDayEl) tdeeDayEl.textContent = tdeeLabel;
  // IPF GL card: only show if mode supports it
  const ipfCard = document.getElementById('metricIPFCard');
  if (ipfCard) ipfCard.style.display = modeFeature('showIPF') ? '' : 'none';
  if (modeFeature('showIPF')) {
    setEl('metricIPF',ipf>0?ipf:'тАФ');setEl('metricIPFsub',ipf>0?(ipf<300?'D├йbutant':ipf<400?'Interm├йdiaire':ipf<500?'Avanc├й':'ЁЯПЖ ├Йlite'):'Importe des s├йances');
  }
  // Ratio card: only show if mode supports it
  const ratioCard = document.getElementById('metricRatioCard');
  if (ratioCard) ratioCard.style.display = modeFeature('showBWRatio') ? '' : 'none';
  if (modeFeature('showBWRatio')) {
    setEl('metricRatio',ratio>0?ratio:'тАФ');setEl('metricRatioSub',ratio>0?(ratio>4?'ЁЯФе Recompo active':ratio>3?'En progression':'Continue'):'IPF GL / kg corps');
  }
  // Poids : historique 15 derni├иres entr├йes
  const bwHistory=(db.body||[]).filter(e=>e.bw>0).sort((a,b)=>b.ts-a.ts).slice(0,15);
  const wEl=document.getElementById('weightHistory');
  if (wEl){if(!bwHistory.length){wEl.innerHTML='<p style="color:var(--sub);font-size:12px;text-align:center;">Aucune entr├йe</p>';}
  else{wEl.innerHTML=bwHistory.map((e,i)=>{const prev=bwHistory[i+1];const delta=prev?Math.round((e.bw-prev.bw)*10)/10:null;const cls=delta===null?'':delta>0?'trend-up':delta<0?'trend-down':'trend-flat';const str=delta===null?'':(delta>0?'тЖС':delta<0?'тЖУ':'тЖТ')+Math.abs(delta)+'kg';return`<div class="weight-history-item"><span>${new Date(e.ts).toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit'})}</span><span style="font-weight:700;">${e.bw} kg</span><span class="${cls}" style="font-size:12px;min-width:50px;text-align:right;">${str}</span></div>`;}).join('');}}
  const pEl=document.getElementById('plateauAlerts');
  if (pEl){
    if (modeFeature('showPlateauDetection')) {
      const plateaux=['bench','squat','deadlift'].map(t=>detectPlateau(t)).filter(Boolean);pEl.innerHTML=plateaux.map(p=>`<div class="plateau-alert">ЁЯУЙ ${p.type.toUpperCase()} plateau тАФ adapte la variation</div>`).join('');
    } else { pEl.innerHTML = ''; }
  }
  try { const cEl=document.getElementById('coachAlgoContent');if(cEl)cEl.innerHTML=generateCoachAlgoMessage(); } catch(e) { console.warn('Coach algo render failed:', e); }
  // Nouvelles sections тАФ each wrapped in try/catch so one failure doesn't block others
  try { renderFormeScore(); } catch(e) { const _e=document.getElementById('formeScoreContent'); if(_e) _e.innerHTML='<div style="color:var(--sub);font-size:12px;text-align:center;padding:10px;">Donn├йes insuffisantes</div>'; }
  try { renderTrainingLoad(); } catch(e) { const _e=document.getElementById('trainingLoadContent'); if(_e) _e.innerHTML='<div style="color:var(--sub);font-size:12px;text-align:center;padding:10px;">Donn├йes insuffisantes</div>'; }
  try { renderWeightTrend(); } catch(e) {}
  try { renderMacroHistory(); } catch(e) {}
  try { renderBodyWeightChart(bwHistory); } catch(e) {}
  try { renderMuscleHeatmap(); } catch(e) { const _e=document.getElementById('muscleHeatmapContent'); if(_e) _e.innerHTML='<div style="color:var(--sub);font-size:12px;text-align:center;padding:10px;">Donn├йes insuffisantes</div>'; }
  try { if (typeof renderJointHealthSection === 'function') renderJointHealthSection(); } catch(e) {}
}
function renderBodyWeightChart(entries) {
  const el = document.getElementById('chartBodyWeight');
  if (!el) return;
  if (entries.length < 2) { el.innerHTML = ''; return; }
  const sorted = [...entries].reverse();
  const w = 280, h = 60, pad = 4;
  const bws = sorted.map(e => e.bw);
  const minB = Math.min(...bws), maxB = Math.max(...bws);
  const range = maxB - minB || 1;
  const points = sorted.map((e, i) => ({
    x: pad + (i / (sorted.length - 1)) * (w - pad * 2),
    y: pad + (1 - (e.bw - minB) / range) * (h - pad * 2)
  }));
  const line = points.map((p, i) => (i === 0 ? 'M' : 'L') + p.x.toFixed(1) + ',' + p.y.toFixed(1)).join(' ');
  const area = line + ' L' + points[points.length - 1].x.toFixed(1) + ',' + h + ' L' + points[0].x.toFixed(1) + ',' + h + ' Z';
  const last = points[points.length - 1];
  const gradId = 'bwg' + Math.random().toString(36).substr(2, 5);
  el.innerHTML = '<svg viewBox="0 0 ' + w + ' ' + h + '" preserveAspectRatio="none" style="width:100%;height:60px;">' +
    '<defs><linearGradient id="' + gradId + '" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="var(--green)" stop-opacity="0.15"/><stop offset="100%" stop-color="var(--green)" stop-opacity="0"/></linearGradient></defs>' +
    '<path d="' + area + '" fill="url(#' + gradId + ')"/>' +
    '<path d="' + line + '" fill="none" stroke="var(--green)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>' +
    '<circle cx="' + last.x.toFixed(1) + '" cy="' + last.y.toFixed(1) + '" r="3" fill="var(--green)"/>' +
    '</svg>' +
    '<div style="display:flex;justify-content:space-between;font-size:9px;color:var(--sub);margin-top:2px;">' +
    '<span>' + new Date(sorted[0].ts).toLocaleDateString('fr-FR', {day:'2-digit',month:'2-digit'}) + '</span>' +
    '<span>' + minB.toFixed(1) + 'тАУ' + maxB.toFixed(1) + ' kg</span>' +
    '<span>' + new Date(sorted[sorted.length-1].ts).toLocaleDateString('fr-FR', {day:'2-digit',month:'2-digit'}) + '</span></div>';
}
// ============================================================
// ONGLET S├ЙANCES тАФ vue semaine тЖРтЖТ
// ============================================================
function getWeekStart(ts) {
  const d = new Date(ts); d.setHours(0,0,0,0);
  const day = d.getDay(); const diff = day===0 ? -6 : 1-day;
  d.setDate(d.getDate()+diff); return d.getTime();
}
function getWeekEnd(ws) { return ws + 6*86400000 + 86399999; }

function navigateWeek(dir) {
  currentWeekOffset += dir;
  renderSeancesTab();
}

function renderSeancesTab() {
  const now = Date.now();
  const thisWeekStart = getWeekStart(now);
  const targetWeekStart = thisWeekStart + (currentWeekOffset * 7 * 86400000);
  const targetWeekEnd = getWeekEnd(targetWeekStart);

  const startD = new Date(targetWeekStart), endD = new Date(targetWeekEnd);
  const fmt = d => d.toLocaleDateString('fr-FR', {day:'2-digit', month:'2-digit'});
  document.getElementById('weekRangeLabel').textContent = fmt(startD) + ' тАУ ' + fmt(endD);
  document.getElementById('weekIndexLabel').textContent =
    currentWeekOffset === 0 ? 'Cette semaine' :
    currentWeekOffset === -1 ? 'Semaine pass├йe' :
    'Il y a ' + Math.abs(currentWeekOffset) + ' semaines';

  var _prevWk = document.getElementById('prevWeekBtn');
  var _nextWk = document.getElementById('nextWeekBtn');
  if (_prevWk) _prevWk.style.opacity = '1';
  if (_nextWk) {
    _nextWk.style.opacity = currentWeekOffset >= 0 ? '0.3' : '1';
    _nextWk.disabled = currentWeekOffset >= 0;
  }

  var allWeekSessions = db.logs.filter(l => l.timestamp >= targetWeekStart && l.timestamp <= targetWeekEnd)
    .sort((a,b) => a.timestamp - b.timestamp);

  // Filter chips
  var _logFilters = ['Tout','Squat','Bench','Deadlift','├Йpaules','Dos'];
  var filterHtml = '<div style="display:flex;gap:6px;margin-bottom:10px;overflow-x:auto;'
    + 'scrollbar-width:none;padding-bottom:2px;">';
  _logFilters.forEach(function(f) {
    var isActive = (_logFilter === f) || (f === 'Tout' && !_logFilter);
    filterHtml += '<button onclick="setLogFilter(\'' + f + '\')" '
      + 'style="flex-shrink:0;padding:5px 12px;border-radius:20px;font-size:11px;'
      + 'border:0.5px solid ' + (isActive ? 'var(--accent)' : 'var(--border-card)') + ';'
      + 'background:' + (isActive ? 'rgba(10,132,255,0.15)' : 'none') + ';'
      + 'color:' + (isActive ? 'var(--accent)' : 'var(--sub)') + ';cursor:pointer;">'
      + f + '</button>';
  });
  filterHtml += '</div>';

  // Apply lift filter
  var sessions = _logFilter
    ? allWeekSessions.filter(function(s) {
        return (s.exercises || []).some(function(e) {
          return ((e.name || '').toLowerCase()).includes(_logFilter.toLowerCase());
        });
      })
    : allWeekSessions;

  const container = document.getElementById('weekSessionsContainer');

  // Stats semaine
  var totalDur = sessions.reduce(function(s,l){ return s+(l.duration||0); }, 0);
  var totalVol = sessions.reduce(function(s,l){ return s+(l.volume||0); }, 0);
  var durMin = Math.round(totalDur/60);
  var durStr = durMin>=60 ? Math.floor(durMin/60)+'h'+(durMin%60>0?(durMin%60<10?'0':'')+(durMin%60):'') : durMin+'min';
  var volStr2 = totalVol>=1000 ? (totalVol/1000).toFixed(1)+'t' : totalVol+'kg';

  var statsHtml = '<div class="wk-stats-bar">'+
    '<div class="wk-stats-item"><div class="wk-stats-val" style="color:var(--accent);">'+sessions.length+'</div><div class="wk-stats-lbl">S├йances</div></div>'+
    '<div class="wk-stats-item"><div class="wk-stats-val" style="color:var(--purple);">'+volStr2+'</div><div class="wk-stats-lbl">Volume</div></div>'+
    '<div class="wk-stats-item"><div class="wk-stats-val" style="color:var(--orange);">'+durStr+'</div><div class="wk-stats-lbl">Dur├йe</div></div>'+
  '</div>';

  // Precompute best e1RM before each session (chronological pass over all logs)
  var _allSorted = db.logs.slice().sort(function(a,b){ return a.timestamp-b.timestamp; });
  var _runBest = {};
  var _prevBestByTs = {};
  _allSorted.forEach(function(log) {
    if (log.timestamp >= targetWeekStart && log.timestamp <= targetWeekEnd) {
      _prevBestByTs[log.timestamp] = Object.assign({}, _runBest);
    }
    (log.exercises||[]).forEach(function(e) {
      if ((e.maxRM||0) > (_runBest[e.name]||0)) _runBest[e.name] = e.maxRM;
    });
  });

  // G├йn├йrer les cards (sans jours de repos)
  var cardsHtml = sessions.length === 0
    ? '<div style="text-align:center;padding:32px 20px;color:var(--sub);font-size:13px;">Aucune s├йance cette semaine<br><button onclick="showSeancesSub(\'s-go\')" style="margin-top:14px;background:var(--accent);color:white;border:none;border-radius:10px;padding:10px 20px;font-size:14px;font-weight:700;cursor:pointer;">D├йmarrer une s├йance GO ЁЯТк</button></div>'
    : sessions.map(function(session, si) {
      return renderSessionCard2(session, si, _prevBestByTs[session.timestamp]||{});
    }).join('');

  container.innerHTML = filterHtml + statsHtml + '<div id="sc-cards-wrap">' + cardsHtml + '</div>';
}

function setLogFilter(f) {
  _logFilter = (f === 'Tout') ? null : f;
  renderSeancesTab();
}

function renderSessionCard2(session, si, prevBestRM) {
  var ts = session.timestamp || 0;
  var d = new Date(ts);
  var dayShort = ['Dim','Lun','Mar','Mer','Jeu','Ven','Sam'][d.getDay()];
  var dayNum = d.getDate();
  var monthShort = ['Jan','F├йv','Mar','Avr','Mai','Jun','Jul','Ao├╗','Sep','Oct','Nov','D├йc'][d.getMonth()];
  var dayLabel = dayShort+' '+dayNum+' '+monthShort;

  // Couleur selon type de s├йance (SBD ou autre)
  var title = session.title || 'S├йance';
  var titleLow = title.toLowerCase();
  var accentColor = 'var(--purple)';
  var borderColor = 'rgba(191,90,242,.2)';
  var bgColor = 'rgba(191,90,242,.04)';
  var topbarBg = 'linear-gradient(90deg,var(--purple),var(--teal))';
  if (/squat|jambe|quad|leg/i.test(titleLow)) {
    accentColor='var(--squat)'; borderColor='rgba(255,69,58,.2)'; bgColor='rgba(255,69,58,.04)';
    topbarBg='linear-gradient(90deg,var(--squat),var(--orange))';
  } else if (/bench|pecto|push|poitrine|d├йvelopp├й/i.test(titleLow)) {
    accentColor='var(--bench)'; borderColor='rgba(10,132,255,.2)'; bgColor='rgba(10,132,255,.04)';
    topbarBg='linear-gradient(90deg,var(--bench),var(--teal))';
  } else if (/dead|soulev├й|deadlift|pull|dos/i.test(titleLow)) {
    accentColor='var(--deadlift)'; borderColor='rgba(255,159,10,.2)'; bgColor='rgba(255,159,10,.04)';
    topbarBg='linear-gradient(90deg,var(--deadlift),var(--orange))';
  }

  var vol = session.volume || 0;
  var volDisplay = vol >= 1000 ? (vol/1000).toFixed(1)+'t' : vol+'kg';
  var dur = session.duration ? Math.round(session.duration/60)+'min' : '';
  var exoCount = (session.exercises||[]).length;
  var metaStr = [dur, exoCount+' exercice'+(exoCount>1?'s':'')].filter(Boolean).join(' ┬╖ ');

  // Badge PR тАФ only show if at least one exercise beat its previous all-time e1RM
  var _pb = prevBestRM || {};
  var hasPR = (session.exercises||[]).some(function(e){ return (e.maxRM||0) > 0 && (e.maxRM||0) > (_pb[e.name]||0); });
  var prBadge = hasPR ? '<span class="sc-pr-badge" style="background:rgba(50,215,75,.1);color:var(--green);border:1px solid rgba(50,215,75,.18);">ЁЯПЖ PR</span>' : '';

  // Tags muscles
  var muscles = {};
  (session.exercises||[]).forEach(function(e){
    var mg = typeof getMuscleGroup==='function' ? getMuscleGroup(e.name) : '';
    if (mg && mg!=='Autre' && mg!=='Cardio') muscles[mg]=true;
  });
  var tagsHtml = Object.keys(muscles).slice(0,3).map(function(mg){
    return '<span class="sc-tag" style="color:var(--sub);border-color:var(--border);">'+mg+'</span>';
  }).join('');

  // Sparkline тАФ exercice principal
  var mainExo = (session.exercises||[]).find(function(e){return e.isPrimary;}) || (session.exercises||[])[0];
  var sparkHtml = (mainExo && mainExo.name && typeof _buildSparkSVG === 'function')
    ? _buildSparkSVG(mainExo.name, accentColor)
    : '';

  // D├йtail complet (sets par exercice)
  var detailHtml = renderSessionDetail2(session);

  var uid = 'sc2-'+si+'-'+ts;

  return '<div class="sc" style="background:'+bgColor+';border-color:'+borderColor+';" id="wrap-'+uid+'">'+
    '<div class="sc-topbar" style="background:'+topbarBg+';"></div>'+
    '<div class="sc-body-wrap" onclick="togSc2(\''+uid+'\')">'+
      '<div class="sc-row1">'+
        '<div class="sc-day-label" style="color:'+accentColor+';">'+dayLabel+prBadge+'</div>'+
        '<div class="sc-vol-block"><div class="sc-vol-num" style="color:var(--purple);">'+volDisplay+'</div><div class="sc-vol-unit">volume</div></div>'+
      '</div>'+
      '<div class="sc-title">'+title+'</div>'+
      '<div class="sc-meta-line">'+metaStr+'</div>'+
      (tagsHtml ? '<div class="sc-tags">'+tagsHtml+'</div>' : '')+
      (sparkHtml ? '<div style="margin:6px 0 2px;">'+sparkHtml+'</div>' : '')+
      '<div class="sc-footer">'+
        '<div style="flex:1;font-size:10px;color:var(--sub);">Appuie pour voir le d├йtail</div>'+
        '<button class="sc-menu-btn" onclick="event.stopPropagation();togScMenu(\'menu-'+uid+'\')">┬╖┬╖┬╖</button>'+
      '</div>'+
    '</div>'+
    '<div class="sc-dropdown" id="menu-'+uid+'">'+
      '<div class="sc-dd-item" onclick="copySessionToGo(\''+session.id+'\');closeAllScMenus()"><span class="sc-dd-ico">тЖй</span>Copier dans GO</div>'+
      '<div class="sc-dd-item" onclick="shareSessionToFeed(\''+session.id+'\');closeAllScMenus()"><span class="sc-dd-ico">ЁЯУд</span>Partager ├а un gym bro</div>'+
      '<div class="sc-dd-sep"></div>'+
      '<div class="sc-dd-item" onclick="openSessionEditor(\''+session.id+'\');closeAllScMenus()"><span class="sc-dd-ico">тЬПя╕П</span>Renommer</div>'+
      '<div class="sc-dd-item sc-dd-danger" onclick="deleteSessionFromList(\''+session.id+'\');closeAllScMenus()"><span class="sc-dd-ico">ЁЯЧСя╕П</span>Supprimer</div>'+
    '</div>'+
    '<div class="sc-detail" id="det-'+uid+'">'+detailHtml+'</div>'+
  '</div>';
}

function renderSessionDetail2(session) {
  var exos = session.exercises || [];
  if (!exos.length) return '<div class="sc-detail-inner"><div style="padding:12px 14px;font-size:12px;color:var(--sub);">Aucun exercice</div></div>';

  var exoBlocks = exos.map(function(exo) {
    var ms = typeof getMuscleStyle==='function' ? getMuscleStyle(exo.name)
      : (typeof _ecMuscleStyle==='function' ? _ecMuscleStyle(exo.name) : {bg:'rgba(120,120,168,.1)',icon:'ЁЯТк'});
    var best = exo.maxRM > 0 ? exo.maxRM+'kg ├Ч '+(((exo.allSets||[]).filter(function(s){return s.weight===exo.maxRM;})[0]||{}).reps||'?')+' reps' : '';
    var bestColor = exo.isPR ? 'color:var(--green)' : 'color:var(--sub)';

    var sets = exo.allSets || exo.series || [];
    var setsHtml = '';
    if (sets.length > 0) {
      var fmtDur2 = function(sec) {
        if (!sec || sec <= 0) return 'тАФ';
        var h = Math.floor(sec/3600), m = Math.floor((sec%3600)/60), s = Math.floor(sec%60);
        if (h > 0) return h+'h'+String(m).padStart(2,'0');
        if (m > 0 && s > 0) return m+'min '+s+'s';
        if (m > 0) return m+'min';
        return s+'s';
      };
      var rows = sets.map(function(s, i) {
        var rest = s.restSeconds ? Math.round(s.restSeconds/60)+'min' : (s.rest || 'тАФ');
        var isWarmup = s.setType==='warmup' || s.isWarmup;
        var isPR = s.setType==='pr' || s.isPR;
        var rowCls = isWarmup ? 'sc-wu' : isPR ? 'sc-pr' : 'sc-wk';
        var typeLabel = isWarmup ? '├Йchauff.' : isPR ? 'ЁЯПЖ PR' : 'Travail';
        var loadCell, repsCell;
        if (s.isPaliers) {
          typeLabel = 'Cardio';
          loadCell = fmtDur2(s.durSec);
          repsCell = s.reps ? s.reps+' pal.' : 'тАФ';
        } else if (s.distKm) {
          typeLabel = 'Cardio';
          loadCell = s.distKm+'km';
          repsCell = fmtDur2(s.durSec);
        } else if (s.durSec) {
          loadCell = fmtDur2(s.durSec);
          repsCell = 'тАФ';
        } else {
          var w = s.weight || 0;
          var r = s.reps || 0;
          loadCell = w > 0 ? w+'kg' : 'тАФ';
          repsCell = r > 0 ? '├Ч'+r : 'тАФ';
        }
        return '<tr class="'+rowCls+'">'+
          '<td class="sc-set-n">'+(i+1)+'</td>'+
          '<td class="sc-set-type"><span>'+typeLabel+'</span></td>'+
          '<td class="sc-set-load">'+loadCell+'</td>'+
          '<td class="sc-set-reps">'+repsCell+'</td>'+
          '<td class="sc-set-rest">'+rest+'</td>'+
        '</tr>';
      }).join('');
      setsHtml = '<table class="sc-sets-table">'+
        '<tr><th>S</th><th>Type</th><th>Charge</th><th>Reps</th><th>Repos</th></tr>'+
        rows+'</table>';
    }

    return '<div class="sc-exo-block">'+
      '<div class="sc-exo-head2">'+
        '<div class="sc-exo-ico2" style="background:'+ms.bg+'">'+ms.icon+'</div>'+
        '<span class="sc-exo-name2">'+exo.name+'</span>'+
        '<span class="sc-exo-best2" style="'+bestColor+'">'+best+'</span>'+
      '</div>'+
      setsHtml+
    '</div>';
  }).join('');

  return '<div class="sc-detail-inner">'+
    '<div class="sc-detail-lbl">D├йtail ┬╖ '+exos.length+' exercice'+(exos.length>1?'s':'')+'</div>'+
    exoBlocks+
    '<div class="sc-actions">'+
      '<button class="sc-action-btn" style="color:var(--accent);border-color:rgba(10,132,255,.2);background:rgba(10,132,255,.08);" onclick="copySessionToGo(\''+session.id+'\')">тЖй Copier dans GO</button>'+
      '<button class="sc-action-btn" style="color:var(--sub);border-color:var(--border);background:var(--surface);" onclick="openSessionEditor(\''+session.id+'\')">тЬПя╕П Modifier</button>'+
    '</div>'+
  '</div>';
}

function togSc2(uid) {
  var det = document.getElementById('det-'+uid);
  if (!det) return;
  var was = det.classList.contains('open');
  document.querySelectorAll('.sc-detail.open').forEach(function(d){ d.classList.remove('open'); });
  if (!was) det.classList.add('open');
  closeAllScMenus();
}

function togScMenu(id) {
  var m = document.getElementById(id);
  if (!m) return;
  var was = m.classList.contains('open');
  closeAllScMenus();
  if (!was) m.classList.add('open');
}

function closeAllScMenus() {
  document.querySelectorAll('.sc-dropdown.open').forEach(function(d){ d.classList.remove('open'); });
}

function copySessionToGo(sessionId) {
  var session = db.logs.find(function(l){ return l.id===sessionId; });
  if (!session) { showToast('S├йance introuvable'); return; }
  db._copiedSession = session;
  showToast('тЬЕ S├йance copi├йe тАФ ouvre GO pour la lancer');
  showSeancesSub('s-go', document.querySelector('[onclick*="s-go"]'));
}

function shareSessionToFeed(sessionId) {
  var session = db.logs.find(function(l){ return l.id===sessionId; });
  if (!session) return;
  if (typeof publishSessionActivity==='function') {
    publishSessionActivity(session);
    showToast('ЁЯУд Partag├й dans le feed !');
  } else {
    showToast('Social non disponible');
  }
}

function toggleSession(id) {
  const el = document.getElementById(id);
  if (el) el.classList.toggle('open');
}
function toggleScExo(id) {
  const el = document.getElementById(id);
  if (!el) return;
  el.classList.toggle('open');
  const chev = document.getElementById('chev-' + id);
  if (chev) chev.classList.toggle('open', el.classList.contains('open'));
}
function deleteSessionFromList(logId) {
  showModal('Supprimer cette s├йance ?', 'Supprimer', 'var(--red)', () => {
    db.logs = db.logs.filter(l => l.id !== logId);
    db.reports = db.reports.filter(r => !(r.type==='debrief' && r.sessionId===logId));
    saveDBNow(); renderSeancesTab(); showToast('тЬУ S├йance supprim├йe');
  });
}

// ============================================================
// STATS тАФ RADAR AM├ЙLIOR├Й
// ============================================================
function getMuscleGroupRadar(subGroup) {
  const map = {
    'Quadriceps':'Quads','Ischio-jambiers':'Ischio','Fessiers':'Fessiers','Mollets':'Ischio',
    'Pecs':'Pecs','Pecs (haut)':'Pecs','Pecs (bas)':'Pecs',
    'Grand dorsal':'Dos','Haut du dos':'Dos','Lombaires':'Dos','Trap├иzes':'Dos','Dorsaux':'Dos',
    '├Йpaules':'├Йpaules','├Йpaules (lat├йral)':'├Йpaules','├Йpaules (ant├йrieur)':'├Йpaules','├Йpaules (post├йrieur)':'├Йpaules',
    'Biceps':'Bras','Triceps':'Bras','Avant-bras':'Bras',
    'Abdos (frontal)':'Abdos','Obliques':'Abdos','Abdos':'Abdos',
    'Cardio':'Cardio'
  };
  return map[subGroup] || 'Autres';
}
const MUSCLE_COLORS_RADAR = {
  'Dos':'#FF9F0A','Pecs':'#0A84FF','Abdos':'#FF453A',
  'Quads':'#32D74B','Fessiers':'#34C759','Ischio':'#30D158','├Йpaules':'#BF5AF2','Bras':'#64D2FF','Cardio':'#FF6B00','Autres':'#8E8E93'
};
const RADAR_AXES = ['Dos','Pecs','Abdos','Quads','Fessiers','Ischio','├Йpaules','Bras','Cardio','Autres'];

function renderRadarImproved(period) {
  period = period || 'week';
  document.getElementById('radarBtn7').classList.toggle('active', period==='week');
  document.getElementById('radarBtn30').classList.toggle('active', period==='month');

  const rl = getLogsInRange(period==='week' ? 7 : 30);

  // Compter s├йries ET nombre d'exercices distincts par groupe
  const msSets = {}; const msExos = {};
  RADAR_AXES.forEach(k => { msSets[k] = 0; msExos[k] = new Set(); });

  rl.forEach(l => l.exercises.forEach(e => {
    const mg = getMuscleGroupRadar(getMuscleGroup(e.name));
    if (mg && msSets.hasOwnProperty(mg)) {
      msSets[mg] += e.sets;
      msExos[mg].add(e.name);
    }
  }));

  // S├йries brutes par groupe тАФ pas de normalisation artificielle
  const values = RADAR_AXES.map(k => msSets[k] || 0);
  const rawMax = Math.max(...values, 1);

  // Pas propre pour les anneaux (ex: max=28 тЖТ step=5, ringMax=30)
  function niceStep(v) {
    if (v <= 5) return 1;
    if (v <= 15) return 2;
    if (v <= 40) return 5;
    if (v <= 100) return 10;
    return 20;
  }
  const step = niceStep(rawMax / 4);
  const ringMax = Math.ceil(rawMax / step) * step || 4;
  const numRings = 4;
  const numAxes = RADAR_AXES.length;
  const R = 95, cx = 150, cy = 135;
  const angleStep = (2 * Math.PI) / numAxes;

  let svg = '<svg viewBox="0 0 300 270" style="width:100%;height:100%;max-width:100%;">';

  // Grid rings avec labels propres (multiples du step)
  for (let lv = 1; lv <= numRings; lv++) {
    const r = (lv / numRings) * R;
    const pts = [];
    for (let i = 0; i < numAxes; i++) {
      const a = i * angleStep - Math.PI/2;
      pts.push((cx + r*Math.cos(a)).toFixed(1) + ',' + (cy + r*Math.sin(a)).toFixed(1));
    }
    svg += '<polygon points="' + pts.join(' ') + '" fill="none" stroke="rgba(255,255,255,' + (lv===numRings?'0.14':'0.06') + ')" stroke-width="' + (lv===numRings?'1.5':'0.8') + '"/>';
    const labelVal = Math.round((lv / numRings) * ringMax);
    svg += '<text x="' + (cx + r + 4) + '" y="' + (cy - 4) + '" fill="rgba(134,134,139,0.65)" font-size="8" dominant-baseline="middle">' + labelVal + '</text>';
  }

  // Axis lines
  for (let i = 0; i < numAxes; i++) {
    const a = i * angleStep - Math.PI/2;
    svg += '<line x1="' + cx + '" y1="' + cy + '" x2="' + (cx + R*Math.cos(a)).toFixed(1) + '" y2="' + (cy + R*Math.sin(a)).toFixed(1) + '" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>';
  }

  // Data polygon тАФ bas├й sur s├йries brutes / ringMax
  const dp = [];
  for (let i = 0; i < numAxes; i++) {
    const a = i * angleStep - Math.PI/2;
    const r = (values[i] / ringMax) * R;
    dp.push({ x: cx + r*Math.cos(a), y: cy + r*Math.sin(a), color: MUSCLE_COLORS_RADAR[RADAR_AXES[i]] });
  }
  svg += '<polygon points="' + dp.map(p => p.x.toFixed(1)+','+p.y.toFixed(1)).join(' ') + '" fill="rgba(10,132,255,0.1)" stroke="#0A84FF" stroke-width="2" stroke-linejoin="round"/>';

  // Points + labels
  RADAR_AXES.forEach((muscle, i) => {
    const a = i * angleStep - Math.PI/2;
    const color = MUSCLE_COLORS_RADAR[muscle];
    const lDist = R + 30;
    const lx = cx + lDist * Math.cos(a);
    const ly = cy + lDist * Math.sin(a);
    const val = values[i];

    svg += '<circle cx="' + dp[i].x.toFixed(1) + '" cy="' + dp[i].y.toFixed(1) + '" r="' + (val > 0 ? 5 : 3) + '" fill="' + (val > 0 ? color : '#3A3A3C') + '" stroke="var(--card)" stroke-width="2"/>';
    svg += '<text x="' + lx.toFixed(1) + '" y="' + (ly - 6).toFixed(1) + '" text-anchor="middle" dominant-baseline="middle" fill="' + (val > 0 ? color : '#5A5A5E') + '" font-size="11" font-weight="600">' + muscle + '</text>';
    if (val > 0) svg += '<text x="' + lx.toFixed(1) + '" y="' + (ly + 7).toFixed(1) + '" text-anchor="middle" dominant-baseline="middle" fill="' + color + '" font-size="9" opacity="0.9">' + val + 's</text>';
  });

  svg += '</svg>';
  const ct = document.getElementById('radarContainer'); if (ct) ct.innerHTML = svg;

  // L├йgende тАФ s├йries brutes
  const legend = document.getElementById('radarLegend');
  if (legend) legend.innerHTML = RADAR_AXES.map((muscle, i) => {
    const val = values[i] || 0;
    const color = MUSCLE_COLORS_RADAR[muscle];
    return '<div style="display:flex;align-items:center;gap:5px;font-size:11px;">' +
      '<div style="width:10px;height:10px;border-radius:50%;background:' + (val>0?color:'#3A3A3C') + '"></div>' +
      '<span style="color:' + (val>0?'var(--text)':'var(--sub)') + '">' + muscle + ': <strong>' + val + '</strong></span></div>';
  }).join('');
}

// ============================================================
// STATS тАФ VOLUME MUSCULAIRE avec ├йvolution 4 semaines
// ============================================================
function setMuscleView(v) {
  currentMuscleView = v;
  var _bb = document.getElementById('muscleViewBarsBtn');
  var _be = document.getElementById('muscleViewEvolBtn');
  var _bs = document.getElementById('muscleViewBarsSection');
  var _es = document.getElementById('muscleViewEvolSection');
  if (_bb) _bb.classList.toggle('active', v==='bars');
  if (_be) _be.classList.toggle('active', v==='evol');
  if (_bs) _bs.style.display = v==='bars' ? 'block' : 'none';
  if (_es) _es.style.display = v==='evol' ? 'block' : 'none';
  if (v === 'evol') renderMuscleEvolChart();
  else renderMuscleVolumeContent(window._musclePeriod || 'week');
}

function renderMuscleEvolChart() {
  const ctx = document.getElementById('chartMuscleEvol'); if (!ctx) return;
  if (typeof Chart === 'undefined') { if (ctx.parentElement) ctx.parentElement.innerHTML = '<div style="text-align:center;padding:20px;color:var(--sub);font-size:12px;">Graphique indisponible (hors-ligne)</div>'; return; }
  if (chartMuscleEvol) { try { chartMuscleEvol.destroy(); } catch(e) {} chartMuscleEvol = null; }
  // D├йtruire toute instance Chart.js d├йj├а attach├йe au canvas
  try {
    const _existingM = Chart.getChart ? Chart.getChart(ctx) : null;
    if (_existingM) _existingM.destroy();
  } catch(e) {}

  const now = Date.now(); const week = 7*86400000;
  const weeks = [
    { label:'S-3', start:now-4*week, end:now-3*week },
    { label:'S-2', start:now-3*week, end:now-2*week },
    { label:'S-1', start:now-2*week, end:now-week },
    { label:'Cette sem.', start:now-week, end:now }
  ];
  const muscles = RADAR_AXES;
  // Single pass: accumulate sets per muscle per week bucket
  const weekBuckets = weeks.map(() => ({})); // array of { muscle: sets }
  muscles.forEach(m => weekBuckets.forEach(b => b[m] = 0));
  db.logs.forEach(l => {
    for (let wi = 0; wi < weeks.length; wi++) {
      if (l.timestamp >= weeks[wi].start && l.timestamp <= weeks[wi].end) {
        l.exercises.forEach(e => {
          const mg = getMuscleGroupRadar(getMuscleGroup(e.name));
          if (mg && weekBuckets[wi].hasOwnProperty(mg)) weekBuckets[wi][mg] += e.sets;
        });
        break; // a log can only be in one week
      }
    }
  });
  const datasets = muscles.map(mg => {
    const color = MUSCLE_COLORS_RADAR[mg] || '#86868B';
    return {
      label: mg,
      data: weekBuckets.map(b => b[mg] || 0),
      borderColor: color, backgroundColor: color + '22',
      borderWidth: 2.5, pointRadius: 4, pointBackgroundColor: color, tension: 0.3, fill: false
    };
  }).filter(d => d.data.some(v => v > 0));

  // Filters
  const fEl = document.getElementById('muscleEvolFilters');
  if (fEl) fEl.innerHTML = datasets.map(d =>
    '<button class="lifts-filter-chip active" onclick="toggleEvolFilter(this,\'' + d.label + '\')" style="border-color:' + MUSCLE_COLORS_RADAR[d.label] + ';color:' + MUSCLE_COLORS_RADAR[d.label] + '">' + d.label + '</button>'
  ).join('');

  chartMuscleEvol = new Chart(ctx, {
    type: 'line',
    data: { labels: weeks.map(w => w.label), datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: { legend: { display: false }, tooltip: { callbacks: { label: c => ' ' + c.dataset.label + ': ' + c.parsed.y + 's' } } },
      scales: {
        y: { grid: { color: '#2C2C2E' }, ticks: { color: '#86868B', callback: v => v + 's' }, beginAtZero: true },
        x: { grid: { display: false }, ticks: { color: '#86868B' } }
      }
    }
  });
}
function toggleEvolFilter(btn, muscle) {
  if (!chartMuscleEvol) return;
  btn.classList.toggle('active');
  const ds = chartMuscleEvol.data.datasets.find(d => d.label === muscle);
  if (ds) ds.hidden = !btn.classList.contains('active');
  chartMuscleEvol.update();
}

// ============================================================
// STATS тАФ MEILLEURS LIFTS refaits
// ============================================================
var LIFT_IMPORTANCE = {
  'squat': 100, 'bench': 100, 'deadlift': 100,
  'souleve': 100, 'developpe couche': 100,
  'developpe': 80, 'presse': 80, 'hack squat': 80, 'rowing': 75,
  'tirage': 75, 'militaire': 75, 'hip thrust': 75, 'tractions': 75,
  'dips': 70, 'curl barre': 65, 'extension jambes': 65,
  'curl': 50, 'extension': 50, 'elevation': 45, 'ecartes': 45,
  'oiseau': 40, 'shrug': 40, 'planche': 35, 'pompes': 50,
  'gainage': 30
};
function getLiftImportance(name) {
  var n = (name || '').toLowerCase()
    .normalize('NFD').replace(/[╠А-═п]/g, '')
    .replace(/[()]/g, ' ');
  var best = 35;
  Object.keys(LIFT_IMPORTANCE).forEach(function(kw) {
    if (n.includes(kw) && LIFT_IMPORTANCE[kw] > best) best = LIFT_IMPORTANCE[kw];
  });
  return best;
}
function getLiftType(lift) {
  if (lift.maxRM > 0) return 'weight';
  if (lift.maxReps > 0) return 'reps';
  if (lift.maxDuration > 0) return 'time';
  return 'reps';
}
function getLiftPRDisplay(lift) {
  var type = getLiftType(lift);
  if (type === 'weight') return { label: lift.maxRM + ' kg', icon: 'ЁЯПЛя╕П' };
  if (type === 'reps') return { label: lift.maxReps + ' reps', icon: 'ЁЯФв' };
  var sec = lift.maxDuration || 0;
  var label = sec >= 60
    ? Math.floor(sec / 60) + 'min' + (sec % 60 > 0 ? String(sec % 60).padStart(2, '0') : '')
    : sec + 's';
  return { label: label, icon: 'тП▒' };
}

function renderLifts() {
  var limit365 = Date.now() - 365 * 86400000;

  // 1. Count sessions per exercise over 365d
  var sessionCount = {};
  var lastSeen = {};
  var logs365 = (db.logs || []).filter(function(l) { return (l.timestamp || 0) >= limit365; });
  logs365.forEach(function(log) {
    var seen = new Set();
    (log.exercises || []).forEach(function(e) {
      if (!seen.has(e.name)) {
        sessionCount[e.name] = (sessionCount[e.name] || 0) + 1;
        lastSeen[e.name] = Math.max(lastSeen[e.name] || 0, log.timestamp || 0);
        seen.add(e.name);
      }
    });
  });

  // 2. Build liftMap from all-time logs, only for exercises seen тЙе 2 times on 365d
  var liftMap = {};
  (db.logs || []).forEach(function(log) {
    (log.exercises || []).forEach(function(exo) {
      if ((sessionCount[exo.name] || 0) < 2) return;
      var canonKey = Object.keys(liftMap).find(function(k) { return matchExoName(exo.name, k); }) || exo.name;
      if (/adduction/i.test(exo.name) && /abduction/i.test(canonKey)) canonKey = exo.name;
      if (/abduction/i.test(exo.name) && /adduction/i.test(canonKey)) canonKey = exo.name;
      if (!liftMap[canonKey]) {
        liftMap[canonKey] = {
          name: canonKey,
          muscle: getMuscleGroupRadar(getMuscleGroup(canonKey)),
          maxRM: 0, maxReps: 0, maxDuration: 0, maxRMDate: null
        };
      }
      var l = liftMap[canonKey];
      if ((exo.maxRM || 0) > l.maxRM) { l.maxRM = exo.maxRM; l.maxRMDate = exo.maxRMDate || null; }
      if ((exo.maxReps || 0) > l.maxReps) l.maxReps = exo.maxReps;
      (exo.series || exo.allSets || []).forEach(function(s) {
        if (s.duration && s.duration > (l.maxDuration || 0)) l.maxDuration = s.duration;
      });
    });
  });

  // 3. Score each lift
  var maxSessions = Math.max.apply(null, Object.keys(sessionCount).map(function(k) { return sessionCount[k] || 0; }).concat([1]));
  var lifts = Object.values(liftMap).map(function(l) {
    var sessions = sessionCount[l.name] || 1;
    var daysSince = lastSeen[l.name] ? Math.round((Date.now() - lastSeen[l.name]) / 86400000) : 365;
    l.score = (getLiftImportance(l.name) / 100) * 0.40 + (sessions / maxSessions) * 0.35 + Math.max(0, 1 - daysSince / 365) * 0.25;
    l.sessions = sessions;
    return l;
  });

  // 4. Keep only lifts with a PR value
  lifts = lifts.filter(function(l) { return l.maxRM > 0 || l.maxReps > 0 || l.maxDuration > 0; });
  lifts.sort(function(a, b) { return b.score - a.score; });

  // 5. Chips тАФ 9 fixed groups (RADAR_AXES without Cardio)
  var availableGroups = new Set(lifts.map(function(l) { return l.muscle; }));
  var RECORDS_AXES = RADAR_AXES.filter(function(m) { return m !== 'Cardio'; });
  document.getElementById('liftsFilterRow').innerHTML = ['Tout'].concat(RECORDS_AXES).map(function(m) {
    var hasData = m === 'Tout' || availableGroups.has(m);
    var isActive = m === liftsMuscleFilter;
    var color = MUSCLE_COLORS_RADAR[m];
    var style = '';
    if (isActive) {
      style = 'background:' + (color || 'var(--blue)') + ';color:white;border-color:' + (color || 'var(--blue)') + ';';
    } else if (!hasData) {
      style = 'opacity:0.35;cursor:default;' + (color ? 'border-color:' + color + '40;color:' + color + ';' : '');
    } else if (color) {
      style = 'border-color:' + color + '40;';
    }
    return '<button class="lifts-filter-chip' + (isActive ? ' active' : '') + '" style="' + style + '" ' +
      (hasData ? 'onclick="setLiftsFilter(\'' + m + '\')"' : 'disabled') + '>' + m + '</button>';
  }).join('');

  // 6. Filter by selected group
  var filtered = liftsMuscleFilter === 'Tout' ? lifts : lifts.filter(function(l) { return l.muscle === liftsMuscleFilter; });
  var el = document.getElementById('liftsList');
  if (!el) return;

  // 7. Encart Autres
  var autresHtml = '';
  if (liftsMuscleFilter === 'Autres') {
    autresHtml = '<div style="background:rgba(142,142,147,0.08);border:0.5px solid rgba(142,142,147,0.2);border-radius:10px;padding:12px;margin-bottom:14px;">' +
      '<div style="font-size:11px;font-weight:700;color:#8E8E93;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;">тЪая╕П Exercices non classifi├йs</div>' +
      '<div style="font-size:12px;color:var(--sub);margin-bottom:8px;">Ces exercices n\'ont pas de groupe musculaire reconnu.</div>' +
      '<div style="display:flex;flex-direction:column;gap:4px;">' +
      filtered.map(function(l) {
        return '<div style="display:flex;align-items:center;justify-content:space-between;font-size:12px;">' +
          '<span style="color:var(--text);">' + l.name + '</span>' +
          '<span style="color:#8E8E93;font-size:10px;background:rgba(142,142,147,0.1);padding:2px 6px;border-radius:4px;">' + getMuscleGroup(l.name) + '</span>' +
          '</div>';
      }).join('') +
      '</div></div>';
  }

  if (!filtered.length) {
    el.innerHTML = autresHtml + '<div style="text-align:center;padding:24px 0;color:var(--sub);font-size:13px;">' +
      (db.logs && db.logs.length ? 'Aucun lift pour ce groupe' : 'Importe des s├йances depuis R├йglages тЖТ ЁЯУе Import') + '</div>';
    return;
  }

  // 8. Render cards
  var RANK_STYLES = [
    'background:rgba(255,215,0,0.15);color:#FFD700;',
    'background:rgba(192,192,192,0.12);color:#C0C0C0;',
    'background:rgba(205,127,50,0.12);color:#CD7F32;'
  ];
  el.innerHTML = autresHtml + filtered.map(function(lift, idx) {
    var pr = getLiftPRDisplay(lift);
    var color = MUSCLE_COLORS_RADAR[lift.muscle] || '#8E8E93';
    var rankStyle = idx < 3 ? RANK_STYLES[idx] : 'background:var(--surface);color:var(--sub);';
    var isSBD = !!getSBDType(lift.name);
    var prDate = lift.maxRMDate ? formatDate(lift.maxRMDate) : '';
    var badgesHtml = '';
    if (isSBD) badgesHtml += '<span class="lc-badge purple">SBD</span>';
    if (lift.maxRM > 0 && db.user && db.user.bw > 0) {
      badgesHtml += '<span class="lc-badge blue">├Ч' + (lift.maxRM / db.user.bw).toFixed(2) + ' bw</span>';
    }
    badgesHtml += '<span class="lc-badge" style="background:rgba(142,142,147,0.1);color:var(--sub);">' + lift.sessions + ' s├йances</span>';
    return '<div class="lc">' +
      '<div class="lc-head">' +
        '<div class="lc-rank" style="' + rankStyle + '">' + (idx + 1) + '</div>' +
        '<div class="lc-info"><div class="lc-name">' + lift.name + '</div>' +
        '<div class="lc-badges">' + badgesHtml + '</div></div>' +
        '<div class="lc-right"><div class="lc-e1rm" style="color:' + color + ';">' + pr.icon + ' ' + pr.label + '</div>' +
        (prDate ? '<div class="lc-date">' + prDate + '</div>' : '') + '</div>' +
      '</div>' +
    '</div>';
  }).join('');
}

function setLiftsFilter(muscle) {
  if (muscle === 'Cardio') return;
  liftsMuscleFilter = muscle;
  renderLifts();
}

function updateNutriTargets() {
  const kcal = parseFloat(document.getElementById('inputKcalBase').value);
  const bw   = parseFloat(document.getElementById('inputBWBase').value);
  if (kcal > 0) db.user.kcalBase = kcal;
  if (bw   > 0) db.user.bwBase   = bw;
  saveDB();
  showToast('тЬУ Cibles nutritionnelles sauvegard├йes');
}

