// ACCORD├ЙON R├ЙGLAGES
// ============================================================
// Lazy-render flags for heavy accordion content
var _accDirty = { records: true, keylifts: true, prog: true };

function toggleAcc(id) {
  const body = document.getElementById(id);
  const chev = document.getElementById('chev-' + id);
  if (!body) return;
  const isOpen = body.classList.contains('open');
  const opening = !isOpen;
  body.classList.toggle('open', opening);
  if (chev) chev.classList.toggle('open', opening);
  // Lazy render heavy content only when accordion opens
  if (opening) {
    if (id === 'acc-records' && _accDirty.records) { _accDirty.records = false; renderRecordsCorrectionList(); }
    if (id === 'acc-keylifts' && _accDirty.keylifts) { _accDirty.keylifts = false; renderKeyLiftsEditor(); }
    if (id === 'acc-prog' && _accDirty.prog) { _accDirty.prog = false; renderSettingsRoutineEditor(); }
    if (id === 'acc-glossary') { renderGlossaryPage(); }
  }
}

function fillSettingsFields() {
  const ni = document.getElementById('inputName'); if (ni && db.user.name) ni.value = db.user.name;
  const bi = document.getElementById('inputBW'); if (bi) bi.value = db.user.bw || '';
  const kEl = document.getElementById('inputKcalBase'); if (kEl) kEl.value = db.user.kcalBase || 2300;
  const bwEl = document.getElementById('inputBWBase'); if (bwEl) bwEl.value = db.user.bwBase || 80;
  const hEl = document.getElementById('settingsHeight'); if (hEl) hEl.value = db.user.height || '';
  const aEl = document.getElementById('settingsAge'); if (aEl) aEl.value = db.user.age || '';
  const tBwEl = document.getElementById('settingsTargetBW'); if (tBwEl) tBwEl.value = db.user.targetBW || '';

  // Cycle menstruel
  var ct = db.user.cycleTracking || { enabled: false, lastPeriodDate: null, cycleLength: 28 };
  var cBlock = document.getElementById('settingsCycleBlock');
  if (cBlock) cBlock.style.display = (db.user.gender === 'female') ? 'block' : 'none';
  var cEnabled = document.getElementById('settingsCycleEnabled');
  if (cEnabled) cEnabled.checked = !!ct.enabled;
  var cDetails = document.getElementById('settingsCycleDetails');
  if (cDetails) cDetails.style.display = ct.enabled ? 'block' : 'none';
  var cLast = document.getElementById('settingsCycleLastDate');
  if (cLast) cLast.value = ct.lastPeriodDate || '';
  var cLen = document.getElementById('settingsCycleLength');
  if (cLen) cLen.value = ct.cycleLength || 28;

  // Blessures
  if (typeof renderInjuriesEditor === 'function') renderInjuriesEditor();

  // Activit├йs compl├йmentaires
  renderSettingsActivities();

  const tB = document.getElementById('tgtBench'), tS = document.getElementById('tgtSquat'), tD = document.getElementById('tgtDead');
  if (tB) tB.value = db.user.targets.bench; if (tS) tS.value = db.user.targets.squat; if (tD) tD.value = db.user.targets.deadlift;
  renderSettingsProfile();
  if (typeof renderStorageGauge === 'function') renderStorageGauge();
  if (typeof renderTierSection === 'function') renderTierSection();
  // Mark lazy accordions as dirty so they render on open
  _accDirty.records = true;
  _accDirty.keylifts = true;
  _accDirty.prog = true;
}

// тФАтФА Activit├йs compl├йmentaires тАФ r├йglages тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
var ACTIVITY_TYPES = [
  { id: 'natation',          label: 'ЁЯПК Natation' },
  { id: 'course',            label: 'ЁЯПГ Course / Running' },
  { id: 'trail',             label: 'ЁЯе╛ Trail' },
  { id: 'randonnee',         label: 'ЁЯПФя╕П Randonn├йe' },
  { id: 'velo',              label: 'ЁЯЪ┤ V├йlo' },
  { id: 'yoga',              label: 'ЁЯзШ Yoga' },
  { id: 'pilates',           label: 'ЁЯй║ Pilates' },
  { id: 'ski',               label: 'тЫ╖я╕П Ski' },
  { id: 'arts_martiaux',     label: 'ЁЯеК Arts Martiaux' },
  { id: 'sports_collectifs', label: 'тЪ╜ Sport Collectif' },
  { id: 'autre',             label: 'ЁЯПЕ Autre' }
];

var DAYS_FULL_LIST = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

var ACTIVITY_SESSION_LABELS = {
  natation:          { emoji: 'ЁЯПК', label: 'Natation',        exoName: 'Natation' },
  course:            { emoji: 'ЁЯПГ', label: 'Course',          exoName: 'Course ├а pied' },
  trail:             { emoji: 'ЁЯе╛', label: 'Trail',           exoName: 'Trail' },
  randonnee:         { emoji: 'ЁЯПФя╕П', label: 'Randonn├йe',      exoName: 'Randonn├йe' },
  velo:              { emoji: 'ЁЯЪ┤', label: 'V├йlo',            exoName: 'V├йlo' },
  yoga:              { emoji: 'ЁЯзШ', label: 'Yoga',            exoName: 'Yoga' },
  pilates:           { emoji: 'ЁЯй║', label: 'Pilates',         exoName: 'Pilates' },
  ski:               { emoji: 'тЫ╖я╕П', label: 'Ski',             exoName: 'Ski' },
  arts_martiaux:     { emoji: 'ЁЯеК', label: 'Arts Martiaux',   exoName: 'Arts Martiaux' },
  sports_collectifs: { emoji: 'тЪ╜', label: 'Sport Collectif', exoName: 'Sport Collectif' },
  autre:             { emoji: 'ЁЯПЕ', label: 'Activit├й',        exoName: 'Activit├й physique' }
};

var ACTIVITY_INTENSITY_LABELS = { 1: 'L├йger', 2: 'Mod├йr├й', 3: 'Soutenu', 4: 'Intense', 5: 'Maximum' };

function _injectSecondaryActivities(days) {
  var fixedActivities = (db.user && db.user.activities) || [];
  fixedActivities.forEach(function(act) {
    if (!act.fixed || !act.days || !act.days.length) return;
    var actInfo = ACTIVITY_SESSION_LABELS[act.type] || ACTIVITY_SESSION_LABELS.autre;
    var intensityLabel = ACTIVITY_INTENSITY_LABELS[act.intensity || 2] || 'Mod├йr├й';
    act.days.forEach(function(dayName) {
      var existing = days.find(function(d) { return d.day === dayName; });
      if (!existing || !existing.rest) return; // only fill rest days
      existing.rest = false;
      existing.title = actInfo.emoji + ' ' + actInfo.label;
      existing.isSecondaryActivity = true;
      existing.coachNote = intensityLabel
        + ' ┬╖ ' + (act.duration || 45) + 'min'
        + (act.elevGain ? ' ┬╖ D+' + act.elevGain + 'm' : '');
      existing.exercises = [{
        name: actInfo.exoName,
        type: 'cardio',
        isSecondaryActivity: true,
        sets: [{ durationMin: act.duration || 45, rpe: act.intensity || 2, isWarmup: false }]
      }];
    });
  });
  return days;
}

function renderSettingsActivities() {
  var el = document.getElementById('settingsActivities');
  if (!el) return;
  var acts = (db.user && db.user.activities) || [];
  if (!acts.length) { el.innerHTML = ''; return; }
  var intensityLabels = ['', 'L├йger', 'Mod├йr├й', 'Soutenu', 'Intense', 'Max'];
  el.innerHTML = acts.map(function(act, idx) {
    var typeOpts = ACTIVITY_TYPES.map(function(t) {
      return '<option value="' + t.id + '"' + (act.type === t.id ? ' selected' : '') + '>' + t.label + '</option>';
    }).join('');
    var intOpts = [1,2,3,4,5].map(function(i) {
      return '<option value="' + i + '"' + (act.intensity === i ? ' selected' : '') + '>' + intensityLabels[i] + '</option>';
    }).join('');
    var dayOpts = '<option value="">Jour?</option>' + DAYS_FULL_LIST.map(function(d, i) {
      var sel = act.days && act.days.indexOf(d) >= 0 ? ' selected' : '';
      return '<option value="' + d + '"' + sel + '>' + (DAYS_SHORT[i + 1] || d.slice(0,3)) + '</option>';
    }).join('');
    return '<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;">' +
      '<select onchange="updateActivity(' + idx + ',\'type\',this.value)" style="flex:2;padding:7px;background:var(--surface);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;">' + typeOpts + '</select>' +
      '<select onchange="updateActivity(' + idx + ',\'intensity\',parseInt(this.value))" style="flex:1;padding:7px;background:var(--surface);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;">' + intOpts + '</select>' +
      '<input type="number" value="' + (act.duration || 60) + '" min="10" max="480" onchange="updateActivity(' + idx + ',\'duration\',parseInt(this.value))" style="width:55px;padding:7px;background:var(--surface);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;" placeholder="min">' +
      '<select onchange="updateActivity(' + idx + ',\'day\',this.value)" style="flex:1;padding:7px;background:var(--surface);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;">' + dayOpts + '</select>' +
      '<button onclick="removeActivity(' + idx + ')" style="background:none;border:none;color:var(--red);cursor:pointer;font-size:18px;padding:0;">├Ч</button>' +
    '</div>';
  }).join('');
}

function addSettingsActivity() {
  if (!db.user.activities) db.user.activities = [];
  db.user.activities.push({ type: 'natation', intensity: 2, duration: 60, days: [], fixed: false });
  renderSettingsActivities();
  saveDB();
}

function updateActivity(idx, field, value) {
  if (!db.user.activities || !db.user.activities[idx]) return;
  if (field === 'day') {
    db.user.activities[idx].days = value ? [value] : [];
    db.user.activities[idx].fixed = !!value;
  } else {
    db.user.activities[idx][field] = value;
  }
  saveDB();
}

function removeActivity(idx) {
  if (!db.user.activities) return;
  db.user.activities.splice(idx, 1);
  renderSettingsActivities();
  saveDB();
}

// тФАтФА Tier & Th├иmes тАФ rendu de la section statut тФАтФА
function renderTierBadge(tier) {
  if (tier === 'founder') return '<span class="badge-founder" style="background:var(--founder-gradient);color:var(--founder-text);padding:1px 6px;border-radius:4px;font-size:9px;font-weight:800;">FOUNDER</span>';
  if (tier === 'early_adopter') return '<span style="background:rgba(199,199,204,0.2);color:#C7C7CC;padding:1px 6px;border-radius:4px;font-size:9px;font-weight:800;">EARLY ADOPTER</span>';
  return '';
}

function isCreator() {
  return db.user.isCreator === true;
}

function renderTierSection() {
  // D├йterminer le tier actuel
  var tier = 'member';
  if (db.isFounder || db.godMode) tier = 'founder';
  else if (db.isEarlyAdopter) tier = 'early_adopter';
  else if (db.user && db.user.tier) tier = db.user.tier;

  var isFounder = tier === 'founder' || isCreator();
  var isEA = tier === 'early_adopter' || isFounder;

  // Section bienvenue
  var welcomeEl = document.getElementById('tierWelcomeSection');
  if (welcomeEl) {
    var wh = '';
    if (isFounder) {
      wh = '<div style="text-align:center;padding:12px;background:linear-gradient(135deg,rgba(200,133,10,0.1),rgba(232,184,48,0.05));border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:28px;margin-bottom:4px;">ЁЯСС</div>';
      wh += '<div style="font-size:14px;font-weight:700;color:#E8B830;">Founder</div>';
      wh += '<div style="font-size:11px;color:var(--sub);margin-top:4px;">Acc├иs complet ├а tous les th├иmes et fonctionnalit├йs exclusives.</div>';
      wh += '</div>';
    } else if (isEA) {
      wh = '<div style="text-align:center;padding:12px;background:rgba(199,199,204,0.05);border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:28px;margin-bottom:4px;">тнР</div>';
      wh += '<div style="font-size:14px;font-weight:700;color:#C7C7CC;">Early Adopter</div>';
      wh += '<div style="font-size:11px;color:var(--sub);margin-top:4px;">Merci de faire partie des premiers !</div>';
      wh += '</div>';
    } else {
      wh = '<div style="text-align:center;padding:12px;background:rgba(255,255,255,0.03);border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:14px;color:var(--sub);">Membre</div>';
      wh += '</div>';
    }
    welcomeEl.innerHTML = wh;
  }

  // Section badges tier
  var badgesEl = document.getElementById('tierBadgesSection');
  if (badgesEl) {
    var bh = '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
    bh += '<div style="padding:6px 12px;border-radius:8px;font-size:11px;font-weight:700;' + (isFounder ? 'background:var(--founder-gradient);color:var(--founder-text);' : 'background:rgba(255,255,255,0.05);color:var(--sub);opacity:0.4;') + '">Founder</div>';
    bh += '<div style="padding:6px 12px;border-radius:8px;font-size:11px;font-weight:700;' + (isEA ? 'background:rgba(199,199,204,0.15);color:#C7C7CC;' : 'background:rgba(255,255,255,0.05);color:var(--sub);opacity:0.4;') + '">Early Adopter</div>';
    bh += '</div>';
    badgesEl.innerHTML = bh;
  }

  // Section th├иmes
  var themeEl = document.getElementById('themeSelector');
  if (themeEl) {
    var saved = localStorage.getItem('selectedTheme') || 'default';
    var themes = [
      { id: 'default', name: 'Bleu iOS', color: '#0A84FF', locked: false },
      { id: 'silver', name: 'Silver', color: '#C7C7CC', locked: !isEA },
      { id: 'gold', name: 'Gold', color: '#E8B830', locked: !isFounder }
    ];
    var th = '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
    themes.forEach(function(t) {
      var isActive = saved === t.id;
      var clickable = !t.locked;
      var style = 'display:flex;align-items:center;gap:8px;padding:10px 14px;border-radius:10px;cursor:' + (clickable ? 'pointer' : 'default') + ';';
      style += 'background:' + (isActive ? 'rgba(255,255,255,0.08)' : 'rgba(255,255,255,0.03)') + ';';
      style += 'border:1px solid ' + (isActive ? t.color : 'rgba(255,255,255,0.06)') + ';';
      style += t.locked ? 'opacity:0.35;' : '';
      var onclick = clickable ? 'applyThemeWithCheck(\'' + t.id + '\');setTimeout(renderTierSection,200);' : '';
      th += '<div style="' + style + '" onclick="' + onclick + '">';
      th += '<div style="width:20px;height:20px;border-radius:50%;background:' + t.color + ';flex-shrink:0;"></div>';
      th += '<div><div style="font-size:12px;font-weight:600;color:var(--text);">' + t.name + '</div>';
      if (t.locked) th += '<div style="font-size:10px;color:var(--sub);">ЁЯФТ ' + (t.id === 'gold' ? 'Founder' : 'Early Adopter') + '</div>';
      th += '</div></div>';
    });
    th += '</div>';
    themeEl.innerHTML = th;
  }
}

// тФАтФА Settings Profile Editor тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
// Debounced save for rapid toggle interactions (avoids clearCaches + JSON.stringify on each click)
let _saveSettingsTimer = null;
function _debouncedSaveSettings() {
  if (_saveSettingsTimer) clearTimeout(_saveSettingsTimer);
  _saveSettingsTimer = setTimeout(() => { saveDB(); _saveSettingsTimer = null; }, 300);
}

function updateProfileField(field, value) {
  if (!db.user.programParams) db.user.programParams = {};
  if (field === 'level') {
    db.user.level = value;
    db.user.programParams.level = value;
  } else if (field === 'trainingMode') {
    db.user.trainingMode = value;
  } else if (field === 'height' || field === 'age' || field === 'targetBW') {
    db.user[field] = value;
  } else {
    db.user.programParams[field] = value;
  }
  _debouncedSaveSettings();
  showToast('тЬУ Profil mis ├а jour');
  if (field === 'level' || field === 'trainingMode') _notifyProgramOutdated();
}

// тФАтФА Cycle menstruel handlers тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function toggleCycleTracking(enabled) {
  if (!db.user.cycleTracking) db.user.cycleTracking = { enabled: false, lastPeriodDate: null, cycleLength: 28 };
  db.user.cycleTracking.enabled = !!enabled;
  var details = document.getElementById('settingsCycleDetails');
  if (details) details.style.display = enabled ? 'block' : 'none';
  _debouncedSaveSettings();
  showToast(enabled ? 'ЁЯМЩ Cycle activ├й' : 'тЬУ Cycle d├йsactiv├й');
}

function updateCycleField(field, value) {
  if (!db.user.cycleTracking) db.user.cycleTracking = { enabled: false, lastPeriodDate: null, cycleLength: 28 };
  db.user.cycleTracking[field] = value;
  _debouncedSaveSettings();
}

// тФАтФА Injuries: zone-by-zone editor тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
var INJURY_ZONES = [
  { key: 'genou',    label: 'ЁЯж╡ Genoux' },
  { key: 'epaule',   label: 'ЁЯдЪ ├Йpaules' },
  { key: 'dos',      label: 'ЁЯж┤ Dos' },
  { key: 'hanche',   label: 'ЁЯж┤ Hanches' },
  { key: 'poignet',  label: 'тЬЛ Poignets' },
  { key: 'coude',    label: 'ЁЯТк Coudes' },
  { key: 'nuque',    label: 'ЁЯСд Nuque' },
];

function renderInjuriesEditor() {
  var container = document.getElementById('settingsInjuriesList');
  if (!container) return;
  var injuries = db.user.injuries || [];
  var byZone = {};
  injuries.forEach(function(inj) { if (inj && inj.zone) byZone[inj.zone] = inj; });

  container.innerHTML = INJURY_ZONES.map(function(z) {
    var inj = byZone[z.key];
    var level = inj && inj.active ? inj.level : 0; // 0 = aucune
    return '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;background:var(--surface);border:1px solid var(--border);border-radius:10px;">'+
      '<div style="font-size:13px;font-weight:600;flex-shrink:0;">' + z.label + '</div>'+
      '<select onchange="setInjuryLevel(\''+z.key+'\', parseInt(this.value))" style="padding:6px 8px;background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;">'+
        '<option value="0"' + (level===0?' selected':'') + '>Aucune</option>'+
        '<option value="1"' + (level===1?' selected':'') + '>Niveau 1 тАФ G├кne l├йg├иre</option>'+
        '<option value="2"' + (level===2?' selected':'') + '>Niveau 2 тАФ Blessure active</option>'+
        '<option value="3"' + (level===3?' selected':'') + '>Niveau 3 тАФ Post-chirurgie</option>'+
      '</select>'+
    '</div>';
  }).join('');
}

function setInjuryLevel(zone, level) {
  if (!Array.isArray(db.user.injuries)) db.user.injuries = [];
  var idx = db.user.injuries.findIndex(function(i) { return i && i.zone === zone; });
  if (level === 0) {
    if (idx >= 0) db.user.injuries.splice(idx, 1);
  } else {
    var entry = { zone: zone, level: level, active: true, since: new Date().toISOString().slice(0,10) };
    if (idx >= 0) db.user.injuries[idx] = Object.assign({}, db.user.injuries[idx], entry);
    else db.user.injuries.push(entry);
  }
  _debouncedSaveSettings();
  showToast(level === 0 ? 'тЬУ Zone retir├йe' : 'тЪХя╕П Niveau ' + level + ' enregistr├й');
}

function renderSettingsProfile() {
  const params = db.user.programParams || {};

  // Niveau
  const lvl = document.getElementById('settingsLevel');
  if (lvl) lvl.value = db.user.level || 'intermediaire';

  // Genre
  const genderEl = document.getElementById('settingsGender');
  if (genderEl) genderEl.value = db.user.gender || 'unspecified';

  // Mode d'entra├оnement
  const modeEl = document.getElementById('settingsTrainingMode');
  if (modeEl) modeEl.value = db.user.trainingMode || 'powerbuilding';

  // Niveau de d├йtail UI
  const uiDetailEl = document.getElementById('settingsUIDetail');
  if (uiDetailEl) uiDetailEl.value = db.user.uiDetail || 'auto';

  // Niveau de vocabulaire (1 = d├йbutant, 2 = interm├йdiaire, 3 = expert)
  const vocabEl = document.getElementById('settingsVocabLevel');
  if (vocabEl) vocabEl.value = String(db.user.vocabLevel || 2);

  // Objectifs (toggle buttons)
  const goalsEl = document.getElementById('settingsGoals');
  if (goalsEl) {
    const allGoals = [
      { id:'force', icon:'ЁЯПЛя╕П', label:'Force' },
      { id:'masse', icon:'ЁЯТк', label:'Masse' },
      { id:'seche', icon:'ЁЯФе', label:'S├иche' },
      { id:'recompo', icon:'тЪЦя╕П', label:'Recompo' },
      { id:'maintien', icon:'ЁЯОп', label:'Maintien' },
      { id:'reprise', icon:'ЁЯМ▒', label:'Reprise' },
    ];
    const selected = params.goals || ['force'];
    goalsEl.innerHTML = allGoals.map(g => {
      const active = selected.includes(g.id);
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="toggleSettingsGoal('${g.id}', this)" style="padding:6px 12px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${g.icon} ${g.label}</button>`;
    }).join('');
  }

  // Fr├йquence
  const freqEl = document.getElementById('settingsFreq');
  if (freqEl) {
    const currentFreq = params.freq || 3;
    freqEl.innerHTML = [1,2,3,4,5,6].map(f => {
      const active = f === currentFreq;
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="setSettingsFreq(${f}, this)" style="padding:6px 14px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:13px;font-weight:700;cursor:pointer;">${f}j/sem</button>`;
    }).join('');
  }

  // Jours d'entra├оnement
  const daysEl = document.getElementById('settingsDays');
  if (daysEl) {
    const currentDays = params.selectedDays || [];
    const dayLabels = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
    daysEl.innerHTML = dayLabels.map(d => {
      const active = currentDays.includes(d);
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="toggleSettingsDay('${d}', this)" style="padding:6px 12px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${d.substring(0,3)}</button>`;
    }).join('');
  }

  // Mat├йriel
  const matEl = document.getElementById('settingsMat');
  if (matEl) {
    const currentMat = params.mat || 'salle';
    const mats = [{id:'salle',label:'ЁЯПв Salle'},{id:'halteres',label:'ЁЯПа Halt├иres'},{id:'maison',label:'ЁЯПб Maison'}];
    matEl.innerHTML = mats.map(m => {
      const active = m.id === currentMat;
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="setSettingsMat('${m.id}', this)" style="padding:6px 14px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${m.label}</button>`;
    }).join('');
  }

  // Dur├йe
  const durEl = document.getElementById('settingsDuration');
  if (durEl) {
    const currentDur = params.duration || 60;
    const durs = [{v:30,l:'30min'},{v:45,l:'45min'},{v:60,l:'1h'},{v:75,l:'1h15'},{v:90,l:'1h30'},{v:120,l:'2h'}];
    durEl.innerHTML = durs.map(d => {
      const active = d.v === currentDur;
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="setSettingsDuration(${d.v}, this)" style="padding:6px 12px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${d.l}</button>`;
    }).join('');
  }

  // Blessures
  const injEl = document.getElementById('settingsInjuries');
  if (injEl) {
    const currentInj = params.injuries || [];
    const zones = ['├Йpaules','Genoux','Dos','Poignets','Nuque','Hanches'];
    injEl.innerHTML = zones.map(z => {
      // Compare against the normalized form persisted in programParams
      const norm = (typeof _normalizeInjuryZone === 'function') ? _normalizeInjuryZone(z) : z.toLowerCase();
      const active = currentInj.includes(norm) || currentInj.includes(z);
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="toggleSettingsInjury('${z}', this)" style="padding:6px 12px;border-radius:8px;border:1px solid ${active?'var(--orange)':'var(--border)'};background:${active?'rgba(255,159,10,0.15)':'var(--surface)'};color:${active?'var(--orange)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${z}</button>`;
    }).join('');
  }

  // Cardio
  const cardioEl = document.getElementById('settingsCardio');
  if (cardioEl) {
    const currentCardio = params.cardio || 'integre';
    const opts = [{id:'integre',l:'ЁЯПГ Int├йgr├й'},{id:'dedie',l:'ЁЯУЕ Jours d├йdi├йs'},{id:'aucun',l:'тЭМ Aucun'}];
    cardioEl.innerHTML = opts.map(o => {
      const active = o.id === currentCardio;
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="setSettingsCardio('${o.id}', this)" style="padding:6px 12px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${o.l}</button>`;
    }).join('');
  }

  // Supersets
  const ssEl = document.getElementById('settingsSupersets');
  if (ssEl) {
    const currentSS = (db.user && db.user.supersetPreference) || 'auto';
    const ssOpts = [
      {id:'standard', l:'Standard', icon:'ЁЯУЛ'},
      {id:'auto',     l:'Auto',     icon:'тЪб'},
      {id:'optimised',l:'Optimis├йe',icon:'ЁЯФА'}
    ];
    ssEl.innerHTML = ssOpts.map(o => {
      const active = o.id === currentSS;
      return `<button class="settings-toggle-btn ${active?'active':''}" onclick="setSupersetPref('${o.id}', this)" style="padding:6px 14px;border-radius:8px;border:1px solid ${active?'var(--blue)':'var(--border)'};background:${active?'rgba(10,132,255,0.15)':'var(--surface)'};color:${active?'var(--blue)':'var(--sub)'};font-size:12px;font-weight:600;cursor:pointer;">${o.icon} ${o.l}</button>`;
    }).join('');
  }

  // Prehab toggle
  var prehabCb = document.getElementById('settingsPrehabToggle');
  var prehabSlider = document.getElementById('settingsPrehabSlider');
  var prehabKnob = document.getElementById('settingsPrehabKnob');
  var prehabOn = db.user.prehabEnabled !== false;
  if (prehabCb) prehabCb.checked = prehabOn;
  if (prehabSlider) prehabSlider.style.background = prehabOn ? 'var(--blue)' : 'var(--border)';
  if (prehabKnob) prehabKnob.style.left = prehabOn ? '23px' : '3px';

  // Mode programme + Coach Profile
  var programModeEl = document.getElementById('settingsProgramMode');
  if (programModeEl) {
    var currentMode = db.user.programMode || 'auto';
    var currentCoachProfile = db.user.coachProfile || 'full';
    // v224 тАФ Labels Guid├й/Avanc├й (au lieu de Auto/Custom)
    programModeEl.innerHTML = '<div style="display:flex;gap:6px;margin-bottom:10px;">'
      + ['auto','custom'].map(function(m) {
        var active = m === currentMode;
        var labels = { auto: 'ЁЯзн Guid├й', custom: 'тЪЩя╕П Avanc├й' };
        return '<button onclick="setProgramMode(\'' + m + '\')" '
          + 'style="flex:1;padding:7px;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;'
          + 'border:1px solid ' + (active ? 'var(--accent)' : 'var(--border)') + ';'
          + 'background:' + (active ? 'rgba(10,132,255,0.15)' : 'var(--surface)') + ';'
          + 'color:' + (active ? 'var(--accent)' : 'var(--sub)') + ';">' + labels[m] + '</button>';
      }).join('')
      + '</div>'
      + '<div style="font-size:11px;color:var(--sub);margin-bottom:6px;">Niveau de coaching</div>'
      + '<div style="display:flex;gap:6px;">'
      + ['full','guardrail','silent'].map(function(p) {
        var active = p === currentCoachProfile;
        var labels = { full: 'ЁЯФФ Complet', guardrail: 'ЁЯЫб S├йcurit├й', silent: 'ЁЯФЗ Silencieux' };
        return '<button onclick="setCoachProfile(\'' + p + '\')" '
          + 'style="flex:1;padding:6px 4px;border-radius:8px;font-size:11px;font-weight:600;cursor:pointer;'
          + 'border:1px solid ' + (active ? 'var(--accent)' : 'var(--border)') + ';'
          + 'background:' + (active ? 'rgba(10,132,255,0.15)' : 'var(--surface)') + ';'
          + 'color:' + (active ? 'var(--accent)' : 'var(--sub)') + ';">' + labels[p] + '</button>';
      }).join('')
      + '</div>';
    // v224 тАФ En mode Avanc├й, afficher les dur├йes de phases personnalisables
    if (currentMode === 'custom' && typeof renderPhaseDurationSettings === 'function') {
      programModeEl.innerHTML += renderPhaseDurationSettings();
    }
  }

  // PhysioManager тАФ section cycle menstruel (uniquement si genre F/female/femme)
  var _gender = db.user && db.user.gender;
  var _isFemale = _gender === 'F' || _gender === 'female' || _gender === 'femme';
  var _cycleSection = document.getElementById('settingsMenstrualSection');
  if (_isFemale) {
    if (!_cycleSection) {
      var _section = document.createElement('div');
      _section.id = 'settingsMenstrualSection';
      _section.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
      var _parentEl = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
      if (_parentEl && _parentEl.parentNode) _parentEl.parentNode.appendChild(_section);
      _cycleSection = _section;
    }
    var _menEnabled = db.user.menstrualEnabled === true;
    var _menData = db.user.menstrualData || {};
    _cycleSection.innerHTML = '<div style="font-size:13px;font-weight:700;margin-bottom:10px;">ЁЯМ╕ Suivi cycle menstruel</div>'
      + '<div style="font-size:11px;color:var(--sub);margin-bottom:12px;line-height:1.5;">'
      + 'Ajuste les charges et le repos selon ta phase. Donn├йes 100% priv├йes, jamais partag├йes.</div>'
      + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;">'
      + '<span style="font-size:13px;">Activer le suivi</span>'
      + '<button onclick="toggleMenstrualTracking()" style="padding:7px 16px;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer;'
      + 'border:1px solid ' + (_menEnabled ? 'var(--green)' : 'var(--border)') + ';'
      + 'background:' + (_menEnabled ? 'rgba(52,199,89,0.15)' : 'var(--surface)') + ';'
      + 'color:' + (_menEnabled ? 'var(--green)' : 'var(--sub)') + ';">'
      + (_menEnabled ? 'тЬЕ Activ├й' : 'D├йsactiv├й') + '</button>'
      + '</div>'
      + (_menEnabled ? '<div style="margin-bottom:10px;">'
        + '<div style="font-size:11px;color:var(--sub);margin-bottom:6px;">D├йbut des derni├иres r├иgles</div>'
        + '<input type="date" id="menstrualStartDate" value="' + (_menData.lastPeriodStart || '') + '"'
        + ' onchange="saveMenstrualData()" style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:13px;">'
        + '</div>'
        + '<div style="margin-bottom:10px;">'
        + '<div style="font-size:11px;color:var(--sub);margin-bottom:6px;">Dur├йe du cycle (jours)</div>'
        + '<input type="number" id="menstrualCycleLength" value="' + (_menData.cycleLength || 28) + '" min="21" max="40"'
        + ' onchange="saveMenstrualData()" style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:13px;">'
        + '</div>'
        + '<button onclick="menstrualResetToday()" style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--sub);font-size:12px;cursor:pointer;">'
        + 'ЁЯФД R├йinitialiser (r├иgles aujourd\'hui)</button>'
        : '');
  } else if (_cycleSection) {
    _cycleSection.innerHTML = '';
    _cycleSection.style.display = 'none';
  }

  // тФАтФА Health Connect / Garmin section (T├ВCHE 17 ├ЙTAPE A) тФАтФА
  var _hcSection = document.getElementById('settingsHealthConnect');
  if (!_hcSection) {
    _hcSection = document.createElement('div');
    _hcSection.id = 'settingsHealthConnect';
    _hcSection.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
    var _hcParent = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
    if (_hcParent && _hcParent.parentNode) _hcParent.parentNode.appendChild(_hcSection);
  }
  var _garminConnected = db.garminConnected || false;
  var _lastSync = db.garminLastSync
    ? (typeof formatRelativeDate === 'function' ? formatRelativeDate(db.garminLastSync) : 'Synchronis├й')
    : 'Jamais synchronis├й';
  var _lastRHR = (db.rhrHistory && db.rhrHistory.length > 0) ? db.rhrHistory[0] : null;
  _hcSection.innerHTML = '<div style="font-size:13px;font-weight:700;margin-bottom:10px;">тМЪ Donn├йes de sant├й</div>'
    + '<div style="background:var(--bg);border-radius:10px;padding:12px;">'
    + '<div style="display:flex;justify-content:space-between;align-items:center;">'
    + '<div><div style="font-size:13px;font-weight:600;">Health Connect</div>'
    + '<div style="font-size:11px;color:var(--sub);">' + _lastSync + '</div></div>'
    + '<button onclick="connectHealthConnect()" style="padding:7px 14px;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;'
    + 'background:' + (_garminConnected ? 'rgba(50,215,75,0.15)' : 'rgba(10,132,255,0.1)') + ';'
    + 'border:1px solid ' + (_garminConnected ? 'var(--green)' : 'var(--accent)') + ';'
    + 'color:' + (_garminConnected ? 'var(--green)' : 'var(--accent)') + ';">'
    + (_garminConnected ? 'тЬУ Connect├й' : 'Connecter') + '</button>'
    + '</div>'
    + (_lastRHR ? '<div style="margin-top:10px;font-size:12px;color:var(--sub);">тЭдя╕П FC repos : <strong style="color:var(--text);">' + _lastRHR.value + ' bpm</strong></div>' : '')
    + '</div>';

  // тФАтФА Weight Cut section (T├ВCHE 19 ├ЙTAPE D) тФАтФА
  var _showWC = (db.user.programParams && (db.user.programParams.goals || []).includes('competition'))
    || (db.user.weightCut && db.user.weightCut.active);
  var _wcSection = document.getElementById('settingsWeightCut');
  if (_showWC) {
    if (!_wcSection) {
      _wcSection = document.createElement('div');
      _wcSection.id = 'settingsWeightCut';
      _wcSection.style.cssText = 'margin-top:14px;';
      var _wcParent = document.getElementById('settingsHealthConnect');
      if (_wcParent && _wcParent.parentNode) _wcParent.parentNode.insertBefore(_wcSection, _wcParent.nextSibling);
    }
    var wc = db.user.weightCut || {};
    var isActive = wc.active || false;
    var wcHtml = '<div style="font-size:11px;color:var(--sub);text-transform:uppercase;letter-spacing:0.8px;font-weight:600;margin-bottom:8px;">тЪЦя╕П Weight Cut</div>';
    wcHtml += '<div style="background:var(--surface);border-radius:12px;padding:12px;">';
    wcHtml += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">';
    wcHtml += '<div style="font-size:13px;font-weight:600;">Mode Weight Cut</div>';
    wcHtml += '<button onclick="toggleWeightCut()" style="padding:6px 12px;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;'
      + 'background:' + (isActive ? 'rgba(255,159,10,0.2)' : 'var(--surface)') + ';'
      + 'border:1px solid ' + (isActive ? 'var(--orange)' : 'var(--border)') + ';'
      + 'color:' + (isActive ? 'var(--orange)' : 'var(--sub)') + ';">'
      + (isActive ? 'тЪб Actif' : 'Inactif') + '</button>';
    wcHtml += '</div>';
    if (isActive) {
      wcHtml += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px;">';
      wcHtml += '<div><div style="font-size:11px;color:var(--sub);margin-bottom:4px;">Poids de d├йpart</div>'
        + '<input type="number" id="wc-start-weight" step="0.1" value="' + (wc.startWeight || db.user.bw || '') + '" '
        + 'style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:13px;box-sizing:border-box;"></div>';
      wcHtml += '<div><div style="font-size:11px;color:var(--sub);margin-bottom:4px;">Objectif (kg)</div>'
        + '<input type="number" id="wc-target-weight" step="0.1" value="' + (wc.targetWeight || '') + '" '
        + 'style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:13px;box-sizing:border-box;"></div>';
      wcHtml += '</div>';
      wcHtml += '<div style="margin-bottom:10px;"><div style="font-size:11px;color:var(--sub);margin-bottom:4px;">Poids actuel (kg)</div>'
        + '<input type="number" id="wc-current-weight" step="0.1" value="' + (wc.currentWeight || db.user.bw || '') + '" '
        + 'style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:13px;box-sizing:border-box;">'
        + '</div>';
      wcHtml += '<div style="margin-bottom:12px;"><div style="font-size:11px;color:var(--sub);margin-bottom:4px;">Date de comp├йtition</div>'
        + '<input type="date" id="wc-competition-date" value="' + (wc.competitionDate || '') + '" '
        + 'style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:13px;box-sizing:border-box;">'
        + '</div>';
      if (wc.startWeight && wc.targetWeight && wc.currentWeight) {
        var _totalToLose = wc.startWeight - wc.targetWeight;
        var _lost = wc.startWeight - wc.currentWeight;
        var _pct = _totalToLose > 0 ? Math.min(100, Math.round(_lost / _totalToLose * 100)) : 0;
        wcHtml += '<div style="margin-bottom:12px;">';
        wcHtml += '<div style="display:flex;justify-content:space-between;font-size:11px;color:var(--sub);margin-bottom:4px;">'
          + '<span>-' + Math.round(_lost * 10) / 10 + 'kg</span>'
          + '<span>Objectif: -' + Math.round(_totalToLose * 10) / 10 + 'kg</span></div>';
        wcHtml += '<div style="height:6px;background:var(--border);border-radius:3px;">'
          + '<div style="height:100%;width:' + _pct + '%;background:var(--orange);border-radius:3px;transition:width 0.3s;"></div>'
          + '</div></div>';
      }
      wcHtml += '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-top:1px solid var(--border);margin-bottom:10px;">'
        + '<div><div style="font-size:13px;">Suppl├йmentation en cr├йatine</div>'
        + '<div style="font-size:11px;color:var(--sub);">+1kg poids de corps (eau intracellulaire)</div></div>'
        + '<label style="position:relative;display:inline-block;width:44px;height:24px;">'
        + '<input type="checkbox" id="toggle-creatine" ' + (db.user.takesCreatine ? 'checked' : '')
        + ' onchange="db.user.takesCreatine=this.checked;saveDB();showToast(\'Cr├йatine mise ├а jour\')" '
        + 'style="opacity:0;width:0;height:0;">'
        + '<span style="position:absolute;cursor:pointer;inset:0;background:' + (db.user.takesCreatine ? 'var(--orange)' : 'var(--border)') + ';border-radius:24px;transition:.3s;">'
        + '<span style="position:absolute;width:18px;height:18px;background:#fff;border-radius:50%;bottom:3px;left:' + (db.user.takesCreatine ? '23px' : '3px') + ';transition:.3s;"></span></span>'
        + '</label></div>';
      wcHtml += '<button onclick="saveWeightCutData()" style="width:100%;padding:10px;background:var(--orange);border:none;border-radius:10px;color:#fff;font-weight:700;font-size:13px;cursor:pointer;">Enregistrer</button>';
    }
    wcHtml += '</div>';
    _wcSection.innerHTML = wcHtml;
  } else if (_wcSection) {
    _wcSection.innerHTML = '';
  }

  // тФАтФА Poids de la barre тФАтФА
  var _barSection = document.getElementById('settingsBarWeightSection');
  if (!_barSection) {
    _barSection = document.createElement('div');
    _barSection.id = 'settingsBarWeightSection';
    _barSection.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
    var _barParent = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
    if (_barParent && _barParent.parentNode) _barParent.parentNode.appendChild(_barSection);
  }
  var _bw = db.user.barWeight || 20;
  var _curUnit = db.user.units || 'kg';
  var _barHtml = '<div style="font-size:13px;font-weight:700;margin-bottom:12px;">ЁЯПЛя╕П ├Йquipement & Unit├йs</div>';
  _barHtml += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">';
  _barHtml += '<div style="font-size:12px;color:var(--sub);">Unit├йs de poids</div>';
  _barHtml += '<div style="display:flex;gap:4px;">';
  ['kg', 'lbs'].forEach(function(u) {
    var active = _curUnit === u;
    _barHtml += '<button onclick="setWeightUnit(\'' + u + '\')" style="padding:6px 14px;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer;'
      + 'background:' + (active ? 'var(--accent)' : 'var(--surface)') + ';'
      + 'border:1px solid ' + (active ? 'var(--accent)' : 'var(--border)') + ';'
      + 'color:' + (active ? '#fff' : 'var(--sub)') + ';">' + u + '</button>';
  });
  _barHtml += '</div></div>';
  _barHtml += '<div style="font-size:11px;color:var(--sub);margin-bottom:8px;">Poids de la barre (pour le calculateur de galettes)</div>';
  _barHtml += '<select id="settings-bar-weight" onchange="saveBarWeight(this.value)" '
    + 'style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--border);'
    + 'background:var(--bg);color:var(--text);font-size:13px;">';
  [['20', 'Olympique standard (20kg)'], ['15', 'Femmes / Comp├йtition (15kg)'],
   ['10', 'EZ Curl (10kg)'], ['5', 'Barre technique (5kg)']].forEach(function(opt) {
    _barHtml += '<option value="' + opt[0] + '"' + (_bw == opt[0] ? ' selected' : '') + '>' + opt[1] + '</option>';
  });
  _barHtml += '</select>';
  _barSection.innerHTML = _barHtml;

  // тФАтФА Mode Hybrid Athlete тФАтФА
  var _hybridSection = document.getElementById('settingsHybridSection');
  if (!_hybridSection) {
    _hybridSection = document.createElement('div');
    _hybridSection.id = 'settingsHybridSection';
    _hybridSection.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
    var _hybridParent = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
    if (_hybridParent && _hybridParent.parentNode) _hybridParent.parentNode.appendChild(_hybridSection);
  }
  var _isHybrid = !!(db.user && db.user.hybridAthlete);
  _hybridSection.innerHTML = '<div style="font-size:13px;font-weight:700;margin-bottom:12px;">ЁЯПК Endurance & Force</div>'
    + '<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;">'
    + '<div>'
    + '<div style="font-size:13px;">Mode Hybrid Athlete</div>'
    + '<div style="font-size:11px;color:var(--sub);">Endurance + Force тАФ plafond ACWR adapt├й (1.0тАУ1.5)</div>'
    + '</div>'
    + '<label style="position:relative;display:inline-block;width:44px;height:24px;">'
    + '<input type="checkbox" id="toggle-hybrid" ' + (_isHybrid ? 'checked' : '')
    + ' onchange="db.user.hybridAthlete=this.checked;saveDB();showToast(this.checked ? \'Mode Hybrid activ├й\' : \'Mode Hybrid d├йsactiv├й\')" '
    + 'style="opacity:0;width:0;height:0;">'
    + '<span style="position:absolute;cursor:pointer;inset:0;background:' + (_isHybrid ? 'var(--accent)' : 'var(--border)') + ';border-radius:24px;transition:.3s;">'
    + '<span style="position:absolute;width:18px;height:18px;background:#fff;border-radius:50%;bottom:3px;left:' + (_isHybrid ? '23px' : '3px') + ';transition:.3s;"></span></span>'
    + '</label></div>';

  // тФАтФА RGPD section тФАтФА
  var _rgpdSection = document.getElementById('settingsRGPDSection');
  if (!_rgpdSection) {
    _rgpdSection = document.createElement('div');
    _rgpdSection.id = 'settingsRGPDSection';
    _rgpdSection.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
    var _rgpdParent = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
    if (_rgpdParent && _rgpdParent.parentNode) _rgpdParent.parentNode.appendChild(_rgpdSection);
  }
  renderRGPDSection(_rgpdSection);

  // тФАтФА Analyse morphologique (Prompt B) тФАтФА
  var _morphoSettingsSection = document.getElementById('settingsMorphoSection');
  var _levelForMorpho = db.user && db.user.level;
  if (_levelForMorpho !== 'debutant') {
    if (!_morphoSettingsSection) {
      _morphoSettingsSection = document.createElement('div');
      _morphoSettingsSection.id = 'settingsMorphoSection';
      _morphoSettingsSection.style.cssText = 'background:var(--surface);border-radius:14px;padding:16px;margin-top:16px;';
      var _morphoParent = document.querySelector('.settings-profile-container') || document.getElementById('settingsProgramMode');
      if (_morphoParent && _morphoParent.parentNode) _morphoParent.parentNode.appendChild(_morphoSettingsSection);
    }
    var _morpho = db.user.morpho;
    var _morphoAnswered = _morpho !== null && _morpho !== undefined;
    var _morphoHtml = '<div style="font-size:13px;font-weight:700;margin-bottom:8px;">ЁЯУР Analyse morphologique</div>';
    _morphoHtml += '<div style="font-size:11px;color:var(--sub);line-height:1.5;margin-bottom:12px;">Adapte les exercices ├а ta morphologie (longueur des leviers, proportions tronc/membres).</div>';
    if (_morphoAnswered) {
      var _morphoLines = [];
      if (_morpho.long_femurs) _morphoLines.push('F├йmurs longs');
      if (_morpho.short_arms_long_torso) _morphoLines.push('Bras courts / tronc long');
      if (_morpho.long_arms) _morphoLines.push('Bras longs');
      if (_morpho.short_torso) _morphoLines.push('Tronc court');
      _morphoHtml += '<div style="font-size:12px;color:var(--sub);margin-bottom:10px;">'
        + (_morphoLines.length > 0 ? 'тЬУ ' + _morphoLines.join(' ┬╖ ') : 'Aucun morphotype s├йlectionn├й') + '</div>';
    }
    _morphoHtml += '<button onclick="openMorphoSettings()" style="width:100%;padding:9px;border-radius:10px;'
      + 'border:1px solid var(--border);background:var(--bg);color:var(--text);'
      + 'font-size:12px;font-weight:600;cursor:pointer;">'
      + (_morphoAnswered ? 'тЬПя╕П Modifier mon analyse morphologique' : 'тЮХ Configurer mon analyse morphologique')
      + '</button>';
    _morphoSettingsSection.innerHTML = _morphoHtml;
    _morphoSettingsSection.style.display = '';
  } else if (_morphoSettingsSection) {
    _morphoSettingsSection.style.display = 'none';
  }
}

