// тФАтФА FONCTIONS UTILITAIRES тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА

function wpRound25(v) { return Math.round(v / 2.5) * 2.5; }
function wpRound125(v) { return Math.round(v / 1.25) * 1.25; }
// тФАтФА NORMALISATION NOM EXERCICE тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
function wpNormalizeName(name) {
  if (!name) return '';
  return name
    .toLowerCase()
    .replace(/[├а├б├в├г├д├е]/g, 'a').replace(/[├и├й├к├л]/g, 'e')
    .replace(/[├м├н├о├п]/g, 'i').replace(/[├▓├│├┤├╡├╢]/g, 'o')
    .replace(/[├╣├║├╗├╝]/g, 'u').replace(/[├з]/g, 'c').replace(/[├▒]/g, 'n')
    .replace(/[()[\]]/g, ' ')
    .replace(/[-тАУтАФ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

