// тФАтФА Programme comp├йtition 12 semaines (v206) тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
// P├йriodisation Gemini : Accumulation 4 тЖТ Intensification 4 тЖТ Peak 2 тЖТ Taper 1 тЖТ Comp Week 1.
// Adaptation blessure ├йpaule par phase. Barre de Sauvetage = 60% PR Bench.
function generateCompPeakingPlan(compDate) {
  if (!compDate) return null;
  var _weeksOut = Math.round((new Date(compDate) - Date.now()) / (7 * 86400000));
  if (_weeksOut <= 0) return null;

  var _phases = [
    { label: 'R├йcup├йration (Comp Week)', phase: 'deload',          weeks: 1 },
    { label: 'Taper',                    phase: 'peak',            weeks: 1 },
    { label: 'Peak',                     phase: 'peak',            weeks: 2 },
    { label: 'Intensification',          phase: 'intensification', weeks: 4 },
    { label: 'Accumulation',             phase: 'hypertrophie',    weeks: 4 }
  ];

  var _schedule = [];
  var _cursor = new Date(compDate);
  _phases.forEach(function(p) {
    var _end = new Date(_cursor);
    _cursor = new Date(_cursor);
    _cursor.setDate(_cursor.getDate() - p.weeks * 7);
    _schedule.unshift({
      phase: p.phase, label: p.label, weeks: p.weeks,
      startDate: _cursor.toISOString().split('T')[0],
      endDate: _end.toISOString().split('T')[0]
    });
  });

  var _today = new Date().toISOString().split('T')[0];
  var _current = _schedule.find(function(s) {
    return _today >= s.startDate && _today <= s.endDate;
  });

  // Adaptation blessure ├йpaule par phase
  var _shoulderBlessure = typeof hasShoulderInjury === 'function' && hasShoulderInjury();
  var _benchAdaptation = null;
  if (_shoulderBlessure && _current) {
    if (_current.phase === 'hypertrophie') {
      _benchAdaptation = { replace: true, with: 'Floor Press', maxRPE: 6,
        note: '├Йpaule : Bench supprim├й en Accumulation. Floor Press l├йger uniquement.' };
    } else if (_current.phase === 'intensification') {
      var _painLevel = _getCurrentShoulderPain();
      _benchAdaptation = _painLevel < 2
        ? { replace: false, note: '├Йpaule : Bench autoris├й (douleur < 2/5). Prise serr├йe.' }
        : { replace: true, with: 'Floor Press', maxRPE: 7,
            note: '├Йpaule : douleur ' + _painLevel + '/5. Bench maintenu en Floor Press.' };
    } else if (_current.phase === 'peak') {
      _benchAdaptation = { replace: false, minSets: 1, maxSets: 2,
        note: '├Йpaule : volume Bench minimal. 1-2 singles pour valider le total.' };
    }
  }

  var _benchPR = (db.bestPR && db.bestPR.bench) || 0;
  var _safetyBar = _benchPR > 0 ? Math.round(_benchPR * 0.60 / 2.5) * 2.5 : null;

  var _daysToComp = Math.round((new Date(compDate) - Date.now()) / 86400000);
  var _readinessAlert = null;
  if (_daysToComp <= 14 && _daysToComp > 0) {
    var _openingSquat = (db.bestPR && db.bestPR.squat)
      ? Math.round(db.bestPR.squat * 0.88 / 2.5) * 2.5 : null;
    if (_daysToComp <= 3) {
      _readinessAlert = 'тЪб J-' + _daysToComp + ' : Activation 50-60% uniquement. Squat + Dead. Z├ЙRO Bench.';
    } else if (_safetyBar) {
      _readinessAlert = 'ЁЯОп J-' + _daysToComp + ' : Valide tes ' + _safetyBar + ' kg au Bench pour rester dans la course au total.';
    } else if (_openingSquat) {
      _readinessAlert = 'ЁЯОп J-' + _daysToComp + ' : V├йrifie que ton ouverture Squat (' + _openingSquat + ' kg) passe ├а RPE 6.';
    }
  }

  return {
    compDate: compDate, weeksOut: _weeksOut, schedule: _schedule,
    currentPhase: _current ? _current.phase : null,
    currentLabel: _current ? _current.label : null,
    benchAdaptation: _benchAdaptation,
    safetyBar: _safetyBar,
    readinessAlert: _readinessAlert
  };
}

function _getCurrentShoulderPain() {
  var _inj = ((db.user && db.user.injuries) || []).find(function(i) {
    return typeof i === 'object' && /epaule|shoulder/i.test(i.zone || '');
  });
  return _inj ? (_inj.level || 0) : 0;
}

// v225 тАФ Semaines depuis le dernier deload (pour banni├иre proactive)
function getWeeksSinceDeload() {
  var _ldd = db.weeklyPlan && db.weeklyPlan.lastDeloadDate;
  if (!_ldd) return null;
  return Math.round((Date.now() - new Date(_ldd).getTime()) / (7 * 86400000));
}

// v225 тАФ D├йtection automatique du deload depuis les logs (seuils valid├йs Gemini)
function detectLastDeload() {
  var logs = db.logs || [];
  if (logs.length < 6) return null;
  var level = (db.user && db.user.level) || 'intermediaire';

  // Cl├й semaine : lundi de la semaine (ISO-like)
  function _weekKey(ts) {
    var d = new Date(ts);
    var day = d.getDay() || 7;
    var monday = new Date(d.getTime() - (day - 1) * 86400000);
    return monday.toISOString().split('T')[0];
  }

  var weekMap = {};
  logs.forEach(function(log) {
    var ts = log.timestamp || 0;
    if (!ts) return;
    var wk = _weekKey(ts);
    if (!weekMap[wk]) weekMap[wk] = { ts: ts, volume: 0 };
    (log.exercises || []).forEach(function(e) {
      var sets = Array.isArray(e.sets) ? e.sets : [];
      sets.forEach(function(s) {
        if (!s.isWarmup && s.weight > 0 && s.reps > 0) {
          weekMap[wk].volume += s.weight * s.reps;
        }
      });
    });
  });

  var weeks = Object.keys(weekMap).sort();
  if (weeks.length < 5) return null;

  // Guard d├йbutant : variance trop haute тЖТ signal non fiable
  if (level === 'debutant') {
    var vols = weeks.map(function(wk) { return weekMap[wk].volume; });
    var mean = vols.reduce(function(a, b) { return a + b; }, 0) / vols.length;
    var variance = vols.reduce(function(a, v) { return a + Math.pow(v - mean, 2); }, 0) / vols.length;
    var cv = mean > 0 ? Math.sqrt(variance) / mean : 0;
    if (cv > 0.20) return null;
  }

  var threshold = level === 'debutant' ? 0.50 : 0.60;

  // v226 тАФ Chercher le deload CONFIRM├Й le plus r├йcent ; sauter PENDING/INJURY (semaine en cours sans rebond)
  var _fallback = null;
  for (var i = weeks.length - 1; i >= 4; i--) {
    var prevFour = [weeks[i - 4], weeks[i - 3], weeks[i - 2], weeks[i - 1]];
    var avgVol = prevFour.reduce(function(sum, wk) { return sum + weekMap[wk].volume; }, 0) / 4;
    if (avgVol === 0) continue;
    var curVol = weekMap[weeks[i]].volume;
    var ratio = curVol / avgVol;
    if (ratio >= threshold) continue;

    var reboundRatio = null;
    var status = 'PENDING';
    if (i + 1 < weeks.length) {
      var nextVol = weekMap[weeks[i + 1]].volume;
      reboundRatio = avgVol > 0 ? nextVol / avgVol : null;
      if (reboundRatio !== null) {
        status = reboundRatio >= 0.95 ? 'CONFIRMED_DELOAD' : 'INJURY_OR_PAUSE';
      }
    }
    var _candidate = {
      date: new Date(weekMap[weeks[i]].ts).toISOString(),
      status: status,
      volumeRatio: ratio,
      reboundRatio: reboundRatio
    };
    if (status === 'CONFIRMED_DELOAD') return _candidate;
    if (!_fallback) _fallback = _candidate;
  }
  return _fallback;
}

function wpDetectPhase() {
  // v206 тАФ Programme comp├йtition : prioritaire sur toutes les autres d├йtections
  var _compDate = db.user && db.user.programParams && db.user.programParams.compDate;
  if (_compDate) {
    var _cp = generateCompPeakingPlan(_compDate);
    if (_cp && _cp.currentPhase) {
      if (db.weeklyPlan && db.weeklyPlan.currentBlock) {
        db.weeklyPlan.currentBlock.phase = _cp.currentPhase;
        db.weeklyPlan.currentBlock._compLabel = _cp.currentLabel;
      }
      return _cp.currentPhase;
    }
  }
  // v193 тАФ Bien-├кtre : phase neutre, jamais de peak/force/deload
  if (db.user && db.user.trainingMode === 'bien_etre') return 'accumulation';
  // Priorit├й 1 : for├зage manuel r├йcent (< 7 jours)
  var cb = db.weeklyPlan && db.weeklyPlan.currentBlock;
  if (cb && cb.forcedAt && (Date.now() - cb.forcedAt) < 7 * 86400000 && cb.phase) {
    return cb.phase;
  }

  // Priorit├й 2 : deload automatique si r├йcup├йration critique
  // Lecture directe todayWellbeing (NE PAS appeler shouldDeload тЖТ cycle avec computeSRS)
  var _wbPh = db.todayWellbeing;
  if (_wbPh && _wbPh.sleep && _wbPh.motivation) {
    var _normPh = (_wbPh.sleep + _wbPh.motivation) / 2 / 5 * 100;
    if (_normPh < 45) return 'deload';
  }

  // Dur├йes adaptatives par mode ├Ч niveau
  var mode = (db.user && db.user.trainingMode) || 'powerbuilding';
  var level = (db.user && db.user.level) || 'intermediaire';
  var hasTable = typeof BLOCK_DURATION !== 'undefined' && BLOCK_DURATION;
  var durations = hasTable && BLOCK_DURATION[mode] && BLOCK_DURATION[mode][level]
    ? BLOCK_DURATION[mode][level]
    : (hasTable ? BLOCK_DURATION.powerbuilding.intermediaire : null);

  // Fallback minimal si table indisponible
  if (!durations) {
    return 'accumulation';
  }

  // v224 тАФ Mode Avanc├й : overrider les dur├йes avec customBlockDuration
  if (db.user && db.user.programMode === 'custom' && db.user.customBlockDuration) {
    durations = Object.assign({}, durations);
    var _customDur = db.user.customBlockDuration;
    Object.keys(_customDur).forEach(function(phase) {
      if (_customDur[phase] > 0) durations[phase] = _customDur[phase];
    });
  }

  // v225 тАФ SOURCE 0 : detectLastDeload() тАФ auto-d├йtection depuis les logs
  if (!db.weeklyPlan || !db.weeklyPlan.lastDeloadDate) {
    var _detected = typeof detectLastDeload === 'function' ? detectLastDeload() : null;
    if (_detected && _detected.status === 'CONFIRMED_DELOAD') {
      if (!db.weeklyPlan) db.weeklyPlan = {};
      db.weeklyPlan.lastDeloadDate = _detected.date;
      db.weeklyPlan._deloadDetectedAuto = true;
      if (typeof saveDB === 'function') saveDB();
    }
  }

  // Guard : blockStartDate d├йsynchronis├йe (snapshot cloud depuis appareil mal dat├й)
  // Ne peut pas arriver en code normal тАФ 4 ├йcritures utilisent toutes Date.now()
  if (cb && cb.blockStartDate && cb.blockStartDate > Date.now()) {
    console.warn('[wpDetectPhase] blockStartDate dans le futur тАФ reset ├а Date.now()');
    cb.blockStartDate = Date.now();
    if (typeof saveDB === 'function') saveDB();
  }

  // v230 тАФ weeksSince : lastDeloadDate (prioritaire) sinon blockStartDate, plancher ├а 1
  // Fix B тАФ exception : blockStartDate r├йcente (< 14j) + lastDeloadDate auto-d├йtect├йe
  // = nouveau m├йsocycle d├йmarr├й manuellement тЖТ blockStartDate prime sur historique
  var _cbBSD = cb && cb.blockStartDate;
  var _lastDL = db.weeklyPlan && db.weeklyPlan.lastDeloadDate;
  var _autoDetected = !!(db.weeklyPlan && db.weeklyPlan._deloadDetectedAuto);
  var _blockIsRecent = !!(_cbBSD && (Date.now() - _cbBSD) < 14 * 86400000);
  var _ref = (_lastDL && !(_autoDetected && _blockIsRecent))
    ? new Date(_lastDL).getTime()
    : _cbBSD || Date.now();
  var weeksSince = Math.max(1, Math.round((Date.now() - _ref) / (7 * 86400000)));

  // Navigation dans le cycle
  // v229 тАФ Tableaux align├йs avec les cl├йs r├йelles de BLOCK_DURATION.
  // ('intro', 'fondation', 'progression', 'maintien' n'existaient pas тЖТ durations=0 тЖТ skip тЖТ bug)
  var w = weeksSince;
  var phases = mode === 'powerlifting'
    ? ['hypertrophie', 'force', 'intensification', 'peak', 'deload']
    : mode === 'musculation'
    ? ['accumulation', 'volume', 'recuperation', 'deload']
    : mode === 'calisthenics'
    ? ['accumulation', 'volume', 'deload']
    : mode === 'bien_etre'
    ? ['accumulation']
    : ['hypertrophie', 'force', 'intensification', 'peak', 'deload']; // powerbuilding (default)

  // Fix A тАФ Guard cycle d├йpass├й : si weeksSince > dur├йe totale du cycle,
  // lastDeloadDate appartient au cycle pr├йc├йdent тЖТ recaler sur blockStartDate
  var _totalCycleWeeks = phases.reduce(function(s, ph) { return s + (durations[ph] || 0); }, 0) || 14;
  if (weeksSince > _totalCycleWeeks && _lastDL && _cbBSD) {
    weeksSince = Math.max(1, Math.round((Date.now() - _cbBSD) / (7 * 86400000)));
    w = weeksSince; // w est captur├й avant Fix A тЖТ doit ├кtre synchronis├й
  }

  var _detectedPhase = null;
  var _weeksBeforePhase = 0;
  for (var i = 0; i < phases.length; i++) {
    var dur = durations[phases[i]] || 0;
    if (dur > 0 && w <= dur) { _detectedPhase = phases[i]; break; }
    w -= dur;
    _weeksBeforePhase += dur;
  }
  if (!_detectedPhase) _detectedPhase = 'deload';

  // v202 тАФ Plateau indicator : 3+ plateaux accessoires ou SRS < 50 ├Ч2 en hypertrophie тЖТ force
  if (_detectedPhase === 'hypertrophie') {
    var _pLogs = (db.logs || []).filter(function(l) {
      return Date.now() - (l.timestamp||0) < 3 * 7 * 86400000;
    });
    var _pCount = 0;
    _pLogs.forEach(function(l) {
      (l.exercises||[]).forEach(function(e) {
        if (!/squat|bench|deadlift|soulev├й|d├йvelopp├й couch├й/i.test(e.name||'') && e.plateauDetected) _pCount++;
      });
    });
    var _pLowSRS = db.readiness
      ? db.readiness.filter(function(r) { return r.score < 50; }).slice(-7).length : 0;
    if (_pCount >= 3 || _pLowSRS >= 2) _detectedPhase = 'force';
  }

  // v224 тАФ Sync currentBlock.phase + week pour coh├йrence avec generateWeeklyPlan
  if (db.weeklyPlan && db.weeklyPlan.currentBlock) {
    db.weeklyPlan.currentBlock.phase = _detectedPhase;
    var _weekInPhase = weeksSince - _weeksBeforePhase;
    if (_detectedPhase === 'force') {
      // Recalculer _weeksBeforePhase pour 'force' au cas o├╣ plateau-indicator
      // l'a forc├й depuis hypertrophie (sinon _weeksBeforePhase refl├иte d├йj├а force)
      var _wbpForce = 0;
      for (var _pi2 = 0; _pi2 < phases.indexOf('force'); _pi2++) {
        _wbpForce += (durations[phases[_pi2]] || 0);
      }
      _weekInPhase = weeksSince - _wbpForce;
    }
    db.weeklyPlan.currentBlock.week = Math.max(1,
      Math.min(_weekInPhase, durations[_detectedPhase] || 4));
  }

  return _detectedPhase;
}

