// тФАтФА INSTINCT MODE тАФ universel (Gemini v208) тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
// "S├йance Plaisir" pour bien_etre/calisthenics, "Mode Instinct" sinon.
// Aucune cible impos├йe, l'algo observe sans intervenir.
function startInstinctSession(mode) {
  var _mode = mode || (db.user && db.user.trainingMode) || 'powerbuilding';
  var _isWellbeing = _mode === 'bien_etre' || _mode === 'calisthenics';
  var _label = _isWellbeing ? 'S├йance Plaisir ЁЯМЯ' : 'Mode Instinct ЁЯО▓';
  var _desc = _isWellbeing
    ? 'Aucun log obligatoire. Aucune cible. Juste bouger pour se sentir bien.'
    : 'Entra├оne-toi au feeling. Aucun RPE impos├й. L\'algo observe sans intervenir.';
  db._lastInstinctSession = Date.now();
  db._instinctMode = true;
  if (typeof saveDB === 'function') saveDB();
  if (typeof goStartWorkout === 'function') goStartWorkout(false);
  if (typeof showToast === 'function') showToast('ЁЯОп ' + _label + ' тАФ ' + _desc, 5000);
}

function _goDoStartWorkout(withProgram) {
  var todayDay = DAYS_FULL[new Date().getDay()];
  var routine = getRoutine();
  activeWorkout = {
    id: generateId(),
    title: withProgram ? (routine && routine[todayDay] ? routine[todayDay] : 'S├йance') : 'S├йance vide',
    startTime: Date.now(),
    exercises: [],
    restTimer: { running: false, remaining: 0, total: 0, exoIndex: -1 }
  };
  if (withProgram) {
    var dayExos = getProgExosForDay(todayDay);
    // Check if weeklyPlan has data for today
    var planDay = null;
    if (db.weeklyPlan && db.weeklyPlan.days) {
      planDay = db.weeklyPlan.days.find(function(d) { return d.day === todayDay && !d.rest; });
    }
    // Express mode: filter to main lift + 1 accessory
    if (planDay && planDay.exercises && db._expressMode) {
      planDay = Object.assign({}, planDay, {
        exercises: filterExpressSession(planDay.exercises)
      });
    }

    // removeAccessories flag: heavy secondary activity yesterday тЖТ drop non-primary exercises
    if (planDay && planDay.exercises && !db._expressMode) {
      var _apf = typeof getActivityPenaltyFlags === 'function' ? getActivityPenaltyFlags() : { flags: [] };
      var _removeAcc = _apf.flags.some(function(f) { return f.removeAccessories === true; });
      if (_removeAcc) {
        planDay = Object.assign({}, planDay, {
          exercises: planDay.exercises.filter(function(e) { return e.isPrimary; })
        });
      }
    }

    dayExos.forEach(function(exoRef) {
      var found = null;
      // Try to find in EXO_DATABASE by id or name match
      var keys = Object.keys(EXO_DATABASE);
      for (var i = 0; i < keys.length; i++) {
        var e = EXO_DATABASE[keys[i]];
        if (keys[i] === exoRef || matchExoName(e.name, exoRef)) { found = e; break; }
      }
      // Also check db.customExercises
      if (!found && db.customExercises) {
        for (var j = 0; j < db.customExercises.length; j++) {
          if (matchExoName(db.customExercises[j].name, exoRef)) { found = db.customExercises[j]; break; }
        }
      }
      var name = found ? found.name : exoRef;
      var exoId = found ? found.id : null;
      var initSets = [];
      var restSec = goGetDefaultRest(name, exoId);

      // Try to get sets from weeklyPlan first
      var planExo = null;
      if (planDay && planDay.exercises) {
        planExo = planDay.exercises.find(function(pe) { return matchExoName(pe.name, name); });
      }

      if (planExo && planExo.sets && planExo.sets.length) {
        // Pre-fill ALL sets from weeklyPlan
        planExo.sets.forEach(function(ps) {
          var setType = 'normal';
          if (ps.isWarmup) setType = 'warmup';
          else if (ps.isBackoff || ps.isBackOff) setType = 'backoff';
          else if (ps.isDropSet) setType = 'dropset';
          initSets.push({
            weight: ps.weight || 0,
            reps: ps.reps || 0,
            type: setType,
            completed: false,
            rpe: ps.rpe || null,
            duration: 0,
            distance: 0,
            plannedWeight: ps.weight || 0  // v203 тАФ r├йf├йrence pour warning > 15%
          });
        });
        if (planExo.restSeconds) restSec = planExo.restSeconds;
      } else {
        // Fallback: pre-fill from history (all previous sets, not just one)
        var prevData = goGetPreviousSets(name);
        if (prevData && prevData.series && prevData.series.length > 0) {
          prevData.series.forEach(function(s) {
            var setType = (s.isWarmup || s.type === 'warmup') ? 'warmup' : ((s.isBackoff || s.type === 'backoff') ? 'backoff' : 'normal');
            initSets.push({
              weight: s.weight || 0,
              reps: s.reps || 0,
              type: setType,
              completed: false,
              rpe: s.rpe || null,
              duration: s.duration || 0,
              distance: s.distance || 0
            });
          });
        } else {
          // No history тАФ single empty set
          initSets.push({ weight: 0, reps: 0, type: 'normal', completed: false, rpe: null, duration: 0, distance: 0 });
        }
      }

      activeWorkout.exercises.push({
        exoId: exoId,
        name: name,
        sets: initSets,
        restSeconds: restSec,
        notes: ''
      });
    });
  }
  _goSessionPaused = false;
  goStartAutoSave();
  goRequestWakeLock();
  goStartSessionTimer();
  goAutoSave();
  renderGoTab();

  // PiP: auto-trigger when tab goes to background
  if (_goPipVisibilityHandler) document.removeEventListener('visibilitychange', _goPipVisibilityHandler);
  _goPipVisibilityHandler = function() {
    if (document.hidden && activeWorkout && !document.pictureInPictureElement) goStartPiP();
  };
  document.addEventListener('visibilitychange', _goPipVisibilityHandler);

  // Social: set training status
  try { setTrainingStatus(true, activeWorkout.title); } catch(e) {}
}

// тФАтФА Restore Draft тФАтФА
function goRestoreDraft() {
  try {
    var data = JSON.parse(localStorage.getItem('SBD_ACTIVE_WORKOUT'));
    if (data) {
      activeWorkout = data;
      _goSessionPaused = false;
      goStartAutoSave();
      goRequestWakeLock();
      goStartSessionTimer();
      renderGoTab();
      showToast('Brouillon restaur├й');
    }
  } catch(e) { showToast('Erreur de restauration'); }
}

// тФАтФА Session Timer тФАтФА
function goStartSessionTimer() {
  goStopSessionTimer();
  _goSessionTimerId = setInterval(function() {
    if (!activeWorkout || _goSessionPaused) return;
    var el = document.getElementById('goTimerDisplay');
    if (el) {
      var elapsed = Math.floor((Date.now() - activeWorkout.startTime) / 1000);
      el.textContent = goFormatTime(elapsed);
    }
  }, 1000);
}
function goStopSessionTimer() { if (_goSessionTimerId) { clearInterval(_goSessionTimerId); _goSessionTimerId = null; } }
function goTogglePause() {
  if (_goSessionPaused) {
    // Resume: adjust startTime to account for pause duration
    activeWorkout.startTime += (Date.now() - _goSessionPausedAt);
    _goSessionPaused = false;
    showToast('S├йance reprise');
  } else {
    _goSessionPausedAt = Date.now();
    _goSessionPaused = true;
    showToast('S├йance en pause');
  }
  goRequestRender();
}

